function validarTipoEspacoReservaRh(tipo) {
  const t = String(tipo || '').trim().toLowerCase();
  if (t === 'auditório' || t === 'auditorio') return 'Auditório';
  if (t === 'sala de reunião' || t === 'sala de reuniao') return 'Sala de reunião';
  if (t === 'reunião online' || t === 'reuniao online') return 'Reunião online';
  if (t === 'visita') return 'Visita';
  if (t === 'evento') return 'Evento';
  return null;
}

function normalizarDiasSemanaRh(dias) {
  if (!Array.isArray(dias)) return [];
  const permitidos = new Set(['seg', 'ter', 'qua', 'qui', 'sex', 'sab', 'dom']);
  return Array.from(new Set(dias.map((d) => String(d || '').trim().toLowerCase()).filter((d) => permitidos.has(d))));
}

function formatarDataIsoLocalRh(dateObj) {
  if (!(dateObj instanceof Date) || Number.isNaN(dateObj.getTime())) return null;
  const ano = dateObj.getFullYear();
  const mes = String(dateObj.getMonth() + 1).padStart(2, '0');
  const dia = String(dateObj.getDate()).padStart(2, '0');
  return `${ano}-${mes}-${dia}`;
}

function normalizarDataIsoRh(valor) {
  if (!valor) return null;
  if (valor instanceof Date) return formatarDataIsoLocalRh(valor);

  const bruto = String(valor).trim();
  const direto = /^\d{4}-\d{2}-\d{2}$/.test(bruto)
    ? bruto
    : (/^\d{4}-\d{2}-\d{2}/.test(bruto) ? bruto.slice(0, 10) : null);
  if (direto) return direto;

  const dt = new Date(bruto);
  if (Number.isNaN(dt.getTime())) return null;
  return formatarDataIsoLocalRh(dt);
}

function obterSiglaDiaSemanaRh(dataIso) {
  const data = new Date(`${String(dataIso || '').slice(0, 10)}T00:00:00`);
  if (Number.isNaN(data.getTime())) return null;
  const mapa = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
  return mapa[data.getDay()] || null;
}

function gerarDatasRecorrenciaRh({ dataBaseIso, repetir, repetirTodosMeses, diasSemana }) {
  if (!repetir) return [dataBaseIso];

  const baseIso = normalizarDataIsoRh(dataBaseIso) || String(dataBaseIso || '').slice(0, 10);
  const base = new Date(`${baseIso}T00:00:00`);
  if (Number.isNaN(base.getTime())) return [dataBaseIso];

  const diasPermitidos = new Set(normalizarDiasSemanaRh(diasSemana));
  if (!diasPermitidos.size) return [dataBaseIso];

  const ano = base.getFullYear();
  const mesesAlvo = repetirTodosMeses
    ? Array.from({ length: 12 }, (_v, idx) => idx)
    : [base.getMonth()];

  const mapaSemana = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
  const datas = [];
  mesesAlvo.forEach((mes) => {
    const ultimoDia = new Date(ano, mes + 1, 0).getDate();
    for (let dia = 1; dia <= ultimoDia; dia++) {
      const atual = new Date(ano, mes, dia);
      const sigla = mapaSemana[atual.getDay()];
      if (diasPermitidos.has(sigla)) {
        const dataIso = formatarDataIsoLocalRh(atual);
        if (dataIso) datas.push(dataIso);
      }
    }
  });

  return Array.from(new Set(datas));
}

function normalizarDatasExcecaoRh(datas) {
  if (!Array.isArray(datas)) return [];
  return Array.from(new Set(
    datas
      .map((d) => normalizarDataIsoRh(d))
      .filter((d) => /^\d{4}-\d{2}-\d{2}$/.test(d))
  ));
}

function unirDatasExcecaoRh(datasAtuais, novasDatas) {
  return normalizarDatasExcecaoRh([
    ...normalizarDatasExcecaoRh(datasAtuais),
    ...normalizarDatasExcecaoRh(novasDatas)
  ]);
}

function gerarOcorrenciasReservaRecorrenteNoAnoRh({ ano, dataBaseIso, repetirTodosMeses, diasSemana, datasExcecao = [] }) {
  const dataBase = normalizarDataIsoRh(dataBaseIso) || String(dataBaseIso || '').slice(0, 10);
  const base = new Date(`${dataBase}T00:00:00`);
  if (Number.isNaN(base.getTime())) return [];
  if (!Number.isInteger(ano) || ano <= 0) return [];

  const diasPermitidos = new Set(normalizarDiasSemanaRh(diasSemana));
  if (!diasPermitidos.size) return [];

  const mesesAlvo = repetirTodosMeses
    ? Array.from({ length: 12 }, (_v, idx) => idx)
    : [base.getMonth()];

  const datasExcecaoSet = new Set(normalizarDatasExcecaoRh(datasExcecao));
  const mapaSemana = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
  const ocorrencias = [];

  mesesAlvo.forEach((mes) => {
    const ultimoDia = new Date(ano, mes + 1, 0).getDate();
    for (let dia = 1; dia <= ultimoDia; dia++) {
      const atual = new Date(ano, mes, dia);
      const sigla = mapaSemana[atual.getDay()];
      if (!diasPermitidos.has(sigla)) continue;
      const dataIso = formatarDataIsoLocalRh(atual);
      if (!dataIso) continue;
      if (datasExcecaoSet.has(dataIso)) continue;
      ocorrencias.push(dataIso);
    }
  });

  return Array.from(new Set(ocorrencias)).sort();
}

async function existeConflitoReservaRh(client, { dataReserva, tipoEspaco, horaInicio, horaFim, ignorarId = null }) {
  const diaSemana = obterSiglaDiaSemanaRh(dataReserva);
  if (!diaSemana) return false;

  const { rows } = await client.query(
    `SELECT id
       FROM rh.reservas_ambientes
      WHERE tipo_espaco = $2
        AND ($3::bigint IS NULL OR id <> $3::bigint)
        AND hora_inicio < $5::time
        AND hora_fim > $4::time
        AND (
          (
            repetir = false
            AND data_reserva = $1::date
          )
          OR (
            repetir = true
            AND EXTRACT(YEAR FROM data_reserva) = EXTRACT(YEAR FROM $1::date)
            AND (
              repetir_todos_meses = true
              OR EXTRACT(MONTH FROM data_reserva) = EXTRACT(MONTH FROM $1::date)
            )
            AND $6 = ANY(dias_semana)
            AND NOT ($1::date = ANY(COALESCE(datas_excecao, ARRAY[]::date[])))
          )
        )
      LIMIT 1`,
    [dataReserva, tipoEspaco, ignorarId, horaInicio, horaFim, diaSemana]
  );
  return rows.length > 0;
}

app.get('/api/google-calendar/status', async (req, res) => {
  const userLogado = resolverUsuarioAuditoria(req);
  if (!userLogado) {
    // Sem sessão: retorna estado padrão sem erro (evita 401 desnecessário no console)
    return res.json({ ok: true, connected: false, configured: false, authenticated: false });
  }

  try {
    const contaGoogle = await obterContaGoogleAuthUser(userLogado);

    if (!googleCalendarConfigOk()) {
      return res.json({ ok: true, connected: false, configured: false, email: contaGoogle, contaGoogle });
    }

    const row = await obterGoogleTokenUsuario(userLogado);
    const contaGoogleNorm = normalizarEmailGoogle(contaGoogle);
    const tokenEmailNorm = normalizarEmailGoogle(row?.email || null);
    const vinculoValido = !!row && !!contaGoogleNorm && (!tokenEmailNorm || tokenEmailNorm === contaGoogleNorm);

    return res.json({
      ok: true,
      connected: vinculoValido,
      configured: true,
      email: vinculoValido ? contaGoogleNorm : null,
      contaGoogle,
      tokenEmail: row?.email || null
    });
  } catch (err) {
    return res.status(500).json({ ok: false, error: err?.message || 'Falha ao verificar status Google Calendar' });
  }
});

app.get('/api/google-calendar/connect', async (req, res) => {
  const userLogado = resolverUsuarioAuditoria(req);
  if (!userLogado) {
    return res.status(401).send('Usuário não autenticado');
  }

  if (!googleCalendarConfigOk()) {
    return res.status(400).send('Google Calendar não configurado no servidor');
  }

  const returnTo = normalizarGoogleReturnTo(req, req.query?.returnTo);
  const nonce = crypto.randomBytes(16).toString('hex');
  req.session.googleCalendarOauthNonce = nonce;

  const state = Buffer.from(JSON.stringify({ nonce, returnTo }), 'utf8').toString('base64url');
  const redirectUri = montarGoogleRedirectUri(req);

  const params = new URLSearchParams({
    client_id: process.env.GOOGLE_OAUTH_CLIENT_ID,
    redirect_uri: redirectUri,
    response_type: 'code',
    access_type: 'offline',
    prompt: 'consent select_account',
    include_granted_scopes: 'false',
    scope: GOOGLE_CALENDAR_SCOPES.join(' '),
    state
  });

  return res.redirect(`https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`);
});

app.get('/api/google-calendar/callback', async (req, res) => {
  const userLogado = resolverUsuarioAuditoria(req);
  if (!userLogado) {
    return res.status(401).send('Usuário não autenticado');
  }

  const fallback = '/#';
  const rawState = String(req.query?.state || '');
  let returnTo = fallback;
  try {
    const parsed = JSON.parse(Buffer.from(rawState, 'base64url').toString('utf8'));
    if (!parsed?.nonce || parsed.nonce !== req.session.googleCalendarOauthNonce) {
      return res.status(400).send('State OAuth inválido. Tente conectar novamente.');
    }
    returnTo = normalizarGoogleReturnTo(req, parsed.returnTo || fallback);
  } catch (_err) {
    return res.status(400).send('State OAuth inválido. Tente conectar novamente.');
  } finally {
    req.session.googleCalendarOauthNonce = null;
  }

  if (req.query?.error) {
    const sep = returnTo.includes('?') ? '&' : '?';
    return res.redirect(`${returnTo}${sep}google_calendar_connected=0`);
  }

  const code = String(req.query?.code || '').trim();
  if (!code) {
    return res.status(400).send('Código OAuth ausente.');
  }

  try {
    const redirectUri = montarGoogleRedirectUri(req);
    const tokenResp = await safeFetch('https://oauth2.googleapis.com/token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: new URLSearchParams({
        code,
        client_id: process.env.GOOGLE_OAUTH_CLIENT_ID,
        client_secret: process.env.GOOGLE_OAUTH_CLIENT_SECRET,
        redirect_uri: redirectUri,
        grant_type: 'authorization_code'
      }).toString()
    });

    const tokenData = await tokenResp.json().catch(() => ({}));
    if (!tokenResp.ok || !tokenData.access_token) {
      throw new Error(tokenData.error_description || tokenData.error || `Falha OAuth Google (${tokenResp.status})`);
    }

    let email = null;
    try {
      const meResp = await safeFetch('https://openidconnect.googleapis.com/v1/userinfo', {
        headers: { Authorization: `Bearer ${tokenData.access_token}` }
      });
      const meData = await meResp.json().catch(() => ({}));
      if (meResp.ok) {
        email = String(meData?.email || '').trim() || null;
      }
    } catch (_err) {
      email = null;
    }

    const expiresSec = Number(tokenData.expires_in || 3600);
    const expiresAt = new Date(Date.now() + (expiresSec * 1000));

    await salvarGoogleTokenUsuario({
      username: userLogado,
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token || null,
      tokenType: tokenData.token_type || 'Bearer',
      scope: tokenData.scope || null,
      expiresAt,
      email
    });

    await atualizarContaGoogleAuthUser(req, email);

    const sep = returnTo.includes('?') ? '&' : '?';
    return res.redirect(`${returnTo}${sep}google_calendar_connected=1`);
  } catch (err) {
    console.error('[GoogleCalendar] Callback OAuth erro:', err);
    const sep = returnTo.includes('?') ? '&' : '?';
    return res.redirect(`${returnTo}${sep}google_calendar_connected=0`);
  }
});

app.post('/api/google-calendar/disconnect', async (req, res) => {
  const userLogado = resolverUsuarioAuditoria(req);
  if (!userLogado) {
    return res.status(401).json({ ok: false, error: 'Usuário não autenticado' });
  }

  try {
    await pool.query(`DELETE FROM rh.google_calendar_tokens WHERE username = $1`, [userLogado]);
    await atualizarContaGoogleAuthUser(req, null);
    return res.json({ ok: true });
  } catch (err) {
    return res.status(500).json({ ok: false, error: err?.message || 'Falha ao desconectar Google Calendar' });
  }
});

app.get('/api/rh/reservas', async (req, res) => {
  try {
    const userLogado = (resolverUsuarioAuditoria(req) || '').trim().toLowerCase();
    const userEhRh = await usuarioEhSetorRhCalendario(req);
    const ano = Number(req.query?.ano);
    const mes = Number(req.query?.mes);
    if (!Number.isInteger(ano) || !Number.isInteger(mes) || mes < 1 || mes > 12) {
      return res.status(400).json({ error: 'Parâmetros inválidos. Use ano e mes (1-12).' });
    }

    const { rows } = await pool.query(
      `SELECT r.id,
              r.tipo_espaco,
              r.tema_reuniao,
              r.data_reserva,
              to_char(r.hora_inicio, 'HH24:MI') AS hora_inicio,
              to_char(r.hora_fim, 'HH24:MI') AS hora_fim,
              r.repetir,
              r.repetir_todos_meses,
              r.dias_semana,
              r.datas_excecao,
              r.cafe,
              r.descricao,
              r.visitantes,
              r.link_reuniao,
              r.anexo_url,
              r.anexo_nome,
              r.google_event_id,
              r.google_calendar_id,
              r.google_event_link,
              r.criado_por,
              r.realizada,
              COALESCE(array_agg(p.username ORDER BY p.username)
                FILTER (WHERE p.username IS NOT NULL), ARRAY[]::TEXT[]) AS participantes
         FROM rh.reservas_ambientes r
         LEFT JOIN rh.reservas_participantes p ON p.reserva_id = r.id
        WHERE EXTRACT(YEAR FROM r.data_reserva) = $1
          AND (
            (
              r.repetir = false
              AND EXTRACT(MONTH FROM r.data_reserva) = $2
            )
            OR (
              r.repetir = true
              AND (
                r.repetir_todos_meses = true
                OR EXTRACT(MONTH FROM r.data_reserva) = $2
              )
            )
          )
        GROUP BY r.id
        ORDER BY r.hora_inicio ASC, r.id ASC`,
      [ano, mes]
    );

    const ultimoDiaMes = new Date(ano, mes, 0);
    const mapaSemana = ['dom', 'seg', 'ter', 'qua', 'qui', 'sex', 'sab'];
    const reservas = [];

    rows.forEach((r) => {
      const baseReserva = {
        id: r.id,
        tipo: r.tipo_espaco,
        tema: r.tema_reuniao,
        inicio: r.hora_inicio,
        fim: r.hora_fim,
        repetir: !!r.repetir,
        repetirTodosMeses: !!r.repetir_todos_meses,
        diasSemana: Array.isArray(r.dias_semana) ? r.dias_semana : [],
        datasExcecao: Array.isArray(r.datas_excecao)
          ? r.datas_excecao.map((d) => normalizarDataIsoRh(d)).filter(Boolean)
          : [],
        cafe: !!r.cafe,
        descricao: r.descricao || null,
        visitantes: r.visitantes || null,
        linkReuniao: r.link_reuniao || null,
        anexoUrl: r.anexo_url || null,
        anexoNome: r.anexo_nome || null,
        googleEventId: r.google_event_id || null,
        googleCalendarId: r.google_calendar_id || null,
        googleEventLink: r.google_event_link || null,
        googleAgendado: !!r.google_event_id,
        criadoPor: r.criado_por,
        realizada: !!r.realizada,
        podeEditar: userEhRh || (!!userLogado && String(r.criado_por || '').trim().toLowerCase() === userLogado),
        participantes: Array.isArray(r.participantes) ? r.participantes : []
      };

      if (!baseReserva.repetir) {
        reservas.push({ ...baseReserva, data: normalizarDataIsoRh(r.data_reserva) || r.data_reserva });
        return;
      }

      const diasSemanaSet = new Set(baseReserva.diasSemana);
      const datasExcecaoSet = new Set(normalizarDatasExcecaoRh(baseReserva.datasExcecao));
      if (!diasSemanaSet.size) {
        reservas.push({ ...baseReserva, data: normalizarDataIsoRh(r.data_reserva) || r.data_reserva });
        return;
      }

      for (let dia = 1; dia <= ultimoDiaMes.getDate(); dia++) {
        const dataAtual = new Date(ano, mes - 1, dia);
        const sigla = mapaSemana[dataAtual.getDay()];
        if (!diasSemanaSet.has(sigla)) continue;
        const dataIso = formatarDataIsoLocalRh(dataAtual);
        if (!dataIso) continue;
        if (datasExcecaoSet.has(dataIso)) continue;
        reservas.push({ ...baseReserva, data: dataIso });
      }
    });

    reservas.sort((a, b) => {
      if (a.data !== b.data) return String(a.data).localeCompare(String(b.data));
      if (a.inicio !== b.inicio) return String(a.inicio).localeCompare(String(b.inicio));
      return Number(a.id) - Number(b.id);
    });

    return res.json({ ok: true, reservas });
  } catch (err) {
    console.error('[API] /api/rh/reservas GET erro:', err);
    return res.status(500).json({ error: 'Falha ao listar reservas RH' });
  }
});

app.post('/api/rh/reservas', async (req, res) => {
  const userLogado = resolverUsuarioAuditoria(req);
  if (!userLogado) {
    return res.status(401).json({ error: 'Usuário não autenticado para registrar reserva' });
  }
  const body = req.body || {};

  const tipoEspaco = validarTipoEspacoReservaRh(body.tipo);
  const tema = String(body.tema || '').trim();
  const dataReserva = String(body.data || '').trim();
  const horaInicio = String(body.inicio || '').trim();
  const horaFim = String(body.fim || '').trim();
  const repetir = !!body.repetir;
  const repetirTodosMeses = !!body.repetirTodosMeses;
  const diasSemana = normalizarDiasSemanaRh(body.diasSemana);
  const cafe = !!body.cafe;
  const descricao = String(body.descricao || '').trim() || null;
  const visitantes = String(body.visitantes || '').trim() || null;
  const linkReuniao = String(body.linkReuniao || '').trim() || null;
  const anexoUrl = String(body.anexoUrl || '').trim() || null;
  const anexoNome = String(body.anexoNome || '').trim() || null;
  const agendarGoogle = !!body.agendarGoogle;
  const participantes = Array.isArray(body.participantes)
    ? Array.from(new Set(body.participantes.map((u) => String(u || '').trim()).filter(Boolean)))
    : [];

  if (!tipoEspaco || !tema || !dataReserva || !horaInicio || !horaFim) {
    return res.status(400).json({ error: 'Campos obrigatórios: tipo, tema, data, inicio, fim' });
  }
  if (horaFim <= horaInicio) {
    return res.status(400).json({ error: 'Horário fim deve ser maior que horário início' });
  }

  const datasReserva = gerarDatasRecorrenciaRh({
    dataBaseIso: dataReserva,
    repetir,
    repetirTodosMeses,
    diasSemana
  });

  const tiposComConflito = new Set(['Auditório', 'Sala de reunião']);
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    if (tiposComConflito.has(tipoEspaco)) {
      for (const dataItem of datasReserva) {
        const conflito = await existeConflitoReservaRh(client, {
          dataReserva: dataItem,
          tipoEspaco,
          horaInicio,
          horaFim,
          ignorarId: null
        });
        if (conflito) {
          await client.query('ROLLBACK');
          return res.status(409).json({ error: `Conflito de horário para o mesmo espaço na data ${dataItem}` });
        }
      }
    }

    const insertReserva = await client.query(
      `INSERT INTO rh.reservas_ambientes
        (tipo_espaco, tema_reuniao, data_reserva, hora_inicio, hora_fim, repetir, repetir_todos_meses, dias_semana, cafe, descricao, visitantes, criado_por, link_reuniao, anexo_url, anexo_nome)
       VALUES ($1, $2, $3::date, $4::time, $5::time, $6, $7, $8::text[], $9, $10, $11, $12, $13, $14, $15)
       RETURNING id`,
      [tipoEspaco, tema, dataReserva, horaInicio, horaFim, repetir, repetirTodosMeses, diasSemana, cafe, descricao, visitantes, userLogado, linkReuniao, anexoUrl, anexoNome]
    );

    const reservaId = insertReserva.rows[0].id;
    for (const username of participantes) {
      await client.query(
        `INSERT INTO rh.reservas_participantes (reserva_id, username)
         VALUES ($1, $2)
         ON CONFLICT DO NOTHING`,
        [reservaId, username]
      );
    }

    await client.query('COMMIT');

    let googleAgenda = { requested: agendarGoogle, ok: null, eventId: null, eventLink: null, message: null };
    if (agendarGoogle) {
      try {
        const resultadoGoogle = await sincronizarReservaGoogleCalendar({
          username: userLogado,
          reserva: {
            id: reservaId,
            tipo: tipoEspaco,
            tema,
            data: dataReserva,
            inicio: horaInicio,
            fim: horaFim,
            cafe,
            descricao,
            visitantes,
            linkReuniao,
            participantes
          },
          googleEventId: null,
          googleCalendarId: 'primary'
        });

        await pool.query(
          `UPDATE rh.reservas_ambientes
              SET google_event_id = $1,
                  google_calendar_id = $2,
                  google_event_link = $3,
                  atualizado_em = NOW()
            WHERE id = $4`,
          [resultadoGoogle.eventId, resultadoGoogle.calendarId, resultadoGoogle.htmlLink, reservaId]
        );

        googleAgenda = {
          requested: true,
          ok: true,
          eventId: resultadoGoogle.eventId,
          eventLink: resultadoGoogle.htmlLink,
          message: 'Evento criado no Google Agenda.'
        };
      } catch (errGoogle) {
        logFalhaGoogleCalendar({
          operacao: 'create_event_after_reserva_post',
          username: userLogado,
          reservaId,
          err: errGoogle,
          reservaLocalSalva: true
        });
        googleAgenda = {
          requested: true,
          ok: false,
          eventId: null,
          eventLink: null,
          code: classificarFalhaGoogleCalendar(errGoogle),
          message: String(errGoogle?.message || 'Falha ao criar evento no Google Agenda')
        };
      }
    }

    return res.json({ ok: true, ids: [reservaId], googleAgenda });
  } catch (err) {
    try { await client.query('ROLLBACK'); } catch {}
    console.error('[API] /api/rh/reservas POST erro:', err);
    return res.status(500).json({ error: 'Falha ao criar reserva RH' });
  } finally {
    client.release();
  }
});

app.put('/api/rh/reservas/:id', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) {
    return res.status(401).json({ error: 'Usuário não autenticado para alterar reserva' });
  }
  const reservaId = Number(req.params?.id);
  if (!Number.isInteger(reservaId) || reservaId <= 0) {
    return res.status(400).json({ error: 'ID inválido' });
  }

  const body = req.body || {};
  const tipoEspaco = validarTipoEspacoReservaRh(body.tipo);
  const tema = String(body.tema || '').trim();
  const dataReserva = String(body.data || '').trim();
  const horaInicio = String(body.inicio || '').trim();
  const horaFim = String(body.fim || '').trim();
  const repetir = !!body.repetir;
  const repetirTodosMeses = !!body.repetirTodosMeses;
  const diasSemana = normalizarDiasSemanaRh(body.diasSemana);
  const cafe = !!body.cafe;
  const descricao = String(body.descricao || '').trim() || null;
  const visitantes = String(body.visitantes || '').trim() || null;
  const linkReuniaoPut = String(body.linkReuniao || '').trim() || null;
  const anexoUrlPut = String(body.anexoUrl || '').trim() || null;
  const anexoNomePut = String(body.anexoNome || '').trim() || null;
  const agendarGoogle = !!body.agendarGoogle;
  const escopoSolicitado = String(body.aplicarEm || '').trim().toLowerCase();
  const aplicarEm = escopoSolicitado === 'este_dia'
    ? 'este_dia'
    : (escopoSolicitado === 'todos_futuros' ? 'todos_futuros' : 'registro');
  const manterAta = body.manterAta === undefined ? true : !!body.manterAta;
  const participantes = Array.isArray(body.participantes)
    ? Array.from(new Set(body.participantes.map((u) => String(u || '').trim()).filter(Boolean)))
    : [];

  if (!tipoEspaco || !tema || !dataReserva || !horaInicio || !horaFim) {
    return res.status(400).json({ error: 'Campos obrigatórios: tipo, tema, data, inicio, fim' });
  }
  if (horaFim <= horaInicio) {
    return res.status(400).json({ error: 'Horário fim deve ser maior que horário início' });
  }

  const tiposComConflitoPut = new Set(['Auditório', 'Sala de reunião']);
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { rows: atualRows } = await client.query(
      `SELECT id, criado_por, data_reserva, repetir, repetir_todos_meses, dias_semana, datas_excecao,
              ata_referencia_reserva_id,
              google_event_id, google_calendar_id, google_event_link
         FROM rh.reservas_ambientes
        WHERE id = $1
        LIMIT 1`,
      [reservaId]
    );
    if (!atualRows.length) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Reserva não encontrada' });
    }

    const criador = String(atualRows[0].criado_por || '').trim().toLowerCase();
    const userNorm = String(userLogado || '').trim().toLowerCase();
    const userEhRh = await usuarioEhSetorRhCalendario(req);
    if (!userNorm || (criador !== userNorm && !userEhRh)) {
      await client.query('ROLLBACK');
      return res.status(403).json({ error: 'Somente o criador ou o setor RH pode alterar esta reserva' });
    }

    const reservaAtual = atualRows[0];
    const reservaAtualRecorrente = !!reservaAtual.repetir;
    const dataBaseAtualIso = normalizarDataIsoRh(reservaAtual.data_reserva) || String(reservaAtual.data_reserva || '').slice(0, 10);
    const diasSemanaAtuais = normalizarDiasSemanaRh(reservaAtual.dias_semana);
    const datasExcecaoAtuais = normalizarDatasExcecaoRh(reservaAtual.datas_excecao);
    const reservaAtaOrigemId = Number(reservaAtual.ata_referencia_reserva_id) || reservaId;
    const googleEventIdAtual = String(reservaAtual?.google_event_id || '').trim() || null;
    const googleCalendarIdAtual = String(reservaAtual?.google_calendar_id || '').trim() || 'primary';

    if (tiposComConflitoPut.has(tipoEspaco)) {
      const conflito = await existeConflitoReservaRh(client, {
        dataReserva,
        tipoEspaco,
        horaInicio,
        horaFim,
        ignorarId: reservaId
      });
      if (conflito) {
        await client.query('ROLLBACK');
        return res.status(409).json({ error: 'Conflito de horário para o mesmo espaço na data informada' });
      }
    }

    let reservaIdFinal = reservaId;
    let escopoAplicado = 'registro';
    let googleEventIdBaseSync = googleEventIdAtual;
    let googleCalendarIdBaseSync = googleCalendarIdAtual;

    const inserirParticipantesReservaRh = async (idReserva, listaUsuarios) => {
      await client.query(`DELETE FROM rh.reservas_participantes WHERE reserva_id = $1`, [idReserva]);
      for (const username of listaUsuarios) {
        await client.query(
          `INSERT INTO rh.reservas_participantes (reserva_id, username)
           VALUES ($1, $2)
           ON CONFLICT DO NOTHING`,
          [idReserva, username]
        );
      }
    };

    if (reservaAtualRecorrente && aplicarEm === 'este_dia') {
      const ocorrenciasAtuais = gerarOcorrenciasReservaRecorrenteNoAnoRh({
        ano: new Date(`${dataReserva}T00:00:00`).getFullYear(),
        dataBaseIso: dataBaseAtualIso,
        repetirTodosMeses: !!reservaAtual.repetir_todos_meses,
        diasSemana: diasSemanaAtuais,
        datasExcecao: datasExcecaoAtuais
      });
      const dataCorte = ocorrenciasAtuais.includes(dataReserva) ? dataReserva : dataBaseAtualIso;
      if (dataCorte !== dataReserva) {
        console.warn('[API] PUT /api/rh/reservas fallback este_dia: data fora da ocorrencia, usando data base da serie', {
          reservaId,
          dataSolicitada: dataReserva,
          dataBaseAtualIso
        });
      }

      const insertNovo = await client.query(
        `INSERT INTO rh.reservas_ambientes
          (tipo_espaco, tema_reuniao, data_reserva, hora_inicio, hora_fim, repetir, repetir_todos_meses, dias_semana,
           cafe, descricao, visitantes, criado_por, link_reuniao, anexo_url, anexo_nome, ata_referencia_reserva_id, datas_excecao)
         VALUES ($1, $2, $3::date, $4::time, $5::time, false, false, ARRAY[]::text[],
                 $6, $7, $8, $9, $10, $11, $12, $13, ARRAY[]::date[])
         RETURNING id`,
        [
          tipoEspaco,
          tema,
          dataCorte,
          horaInicio,
          horaFim,
          cafe,
          descricao,
          visitantes,
          userLogado,
          linkReuniaoPut,
          anexoUrlPut,
          anexoNomePut,
          manterAta ? reservaAtaOrigemId : null
        ]
      );
      reservaIdFinal = insertNovo.rows[0].id;
      await inserirParticipantesReservaRh(reservaIdFinal, participantes);

      const novasExcecoes = unirDatasExcecaoRh(datasExcecaoAtuais, [dataCorte]);
      await client.query(
        `UPDATE rh.reservas_ambientes
            SET datas_excecao = $1::date[],
                atualizado_em = NOW()
          WHERE id = $2`,
        [novasExcecoes, reservaId]
      );

      escopoAplicado = 'este_dia';
      googleEventIdBaseSync = null;
      googleCalendarIdBaseSync = 'primary';
    } else if (reservaAtualRecorrente && aplicarEm === 'todos_futuros') {
      const anoSerie = new Date(`${dataReserva}T00:00:00`).getFullYear();
      const ocorrenciasAtuais = gerarOcorrenciasReservaRecorrenteNoAnoRh({
        ano: anoSerie,
        dataBaseIso: dataBaseAtualIso,
        repetirTodosMeses: !!reservaAtual.repetir_todos_meses,
        diasSemana: diasSemanaAtuais,
        datasExcecao: datasExcecaoAtuais
      });
      const dataCorte = ocorrenciasAtuais.includes(dataReserva) ? dataReserva : dataBaseAtualIso;
      if (dataCorte !== dataReserva) {
        console.warn('[API] PUT /api/rh/reservas fallback todos_futuros: data fora da ocorrencia, usando data base da serie', {
          reservaId,
          dataSolicitada: dataReserva,
          dataBaseAtualIso
        });
      }

      const datasFuturas = ocorrenciasAtuais.filter((d) => d >= dataCorte);
      const excecoesSerieAntiga = unirDatasExcecaoRh(datasExcecaoAtuais, datasFuturas);
      await client.query(
        `UPDATE rh.reservas_ambientes
            SET datas_excecao = $1::date[],
                google_event_id = NULL,
                google_calendar_id = NULL,
                google_event_link = NULL,
                atualizado_em = NOW()
          WHERE id = $2`,
        [excecoesSerieAntiga, reservaId]
      );

      const ocorrenciasNovaSerie = gerarOcorrenciasReservaRecorrenteNoAnoRh({
        ano: anoSerie,
        dataBaseIso: dataCorte,
        repetirTodosMeses,
        diasSemana,
        datasExcecao: []
      });
      const excecoesNovaSerie = ocorrenciasNovaSerie.filter((d) => d < dataCorte);

      const insertSerieNova = await client.query(
        `INSERT INTO rh.reservas_ambientes
          (tipo_espaco, tema_reuniao, data_reserva, hora_inicio, hora_fim, repetir, repetir_todos_meses, dias_semana,
           cafe, descricao, visitantes, criado_por, link_reuniao, anexo_url, anexo_nome, ata_referencia_reserva_id, datas_excecao)
         VALUES ($1, $2, $3::date, $4::time, $5::time, $6, $7, $8::text[],
                 $9, $10, $11, $12, $13, $14, $15, $16, $17::date[])
         RETURNING id`,
        [
          tipoEspaco,
          tema,
          dataCorte,
          horaInicio,
          horaFim,
          repetir,
          repetirTodosMeses,
          diasSemana,
          cafe,
          descricao,
          visitantes,
          userLogado,
          linkReuniaoPut,
          anexoUrlPut,
          anexoNomePut,
          manterAta ? reservaAtaOrigemId : null,
          excecoesNovaSerie
        ]
      );
      reservaIdFinal = insertSerieNova.rows[0].id;
      await inserirParticipantesReservaRh(reservaIdFinal, participantes);

      escopoAplicado = 'todos_futuros';
    } else {
      await client.query(
        `UPDATE rh.reservas_ambientes
            SET tipo_espaco = $1,
                tema_reuniao = $2,
                data_reserva = $3::date,
                hora_inicio = $4::time,
                hora_fim = $5::time,
                repetir = $6,
                repetir_todos_meses = $7,
                dias_semana = $8::text[],
                cafe = $9,
                descricao = $10,
                visitantes = $11,
                link_reuniao = $12,
                anexo_url = $13,
                anexo_nome = $14,
                atualizado_em = NOW()
          WHERE id = $15`,
        [tipoEspaco, tema, dataReserva, horaInicio, horaFim, repetir, repetirTodosMeses, diasSemana, cafe, descricao, visitantes, linkReuniaoPut, anexoUrlPut, anexoNomePut, reservaId]
      );
      await inserirParticipantesReservaRh(reservaId, participantes);
      escopoAplicado = 'registro';
    }

    await client.query('COMMIT');

    const deveSincronizarGoogle = agendarGoogle || !!googleEventIdBaseSync;
    let googleAgenda = { requested: deveSincronizarGoogle, ok: null, eventId: googleEventIdBaseSync, eventLink: null, message: null };

    if (deveSincronizarGoogle) {
      try {
        const resultadoGoogle = await sincronizarReservaGoogleCalendar({
          username: userLogado,
          reserva: {
            id: reservaIdFinal,
            tipo: tipoEspaco,
            tema,
            data: dataReserva,
            inicio: horaInicio,
            fim: horaFim,
            cafe,
            descricao,
            visitantes,
            linkReuniao: linkReuniaoPut,
            participantes
          },
          googleEventId: googleEventIdBaseSync,
          googleCalendarId: googleCalendarIdBaseSync
        });

        await pool.query(
          `UPDATE rh.reservas_ambientes
              SET google_event_id = $1,
                  google_calendar_id = $2,
                  google_event_link = $3,
                  atualizado_em = NOW()
            WHERE id = $4`,
          [resultadoGoogle.eventId, resultadoGoogle.calendarId, resultadoGoogle.htmlLink, reservaIdFinal]
        );

        googleAgenda = {
          requested: true,
          ok: true,
          eventId: resultadoGoogle.eventId,
          eventLink: resultadoGoogle.htmlLink,
          message: googleEventIdBaseSync ? 'Evento atualizado no Google Agenda.' : 'Evento criado no Google Agenda.'
        };
      } catch (errGoogle) {
        logFalhaGoogleCalendar({
          operacao: 'upsert_event_after_reserva_put',
          username: userLogado,
          reservaId: reservaIdFinal,
          err: errGoogle,
          reservaLocalSalva: true
        });
        googleAgenda = {
          requested: true,
          ok: false,
          eventId: googleEventIdBaseSync,
          eventLink: null,
          code: classificarFalhaGoogleCalendar(errGoogle),
          message: String(errGoogle?.message || 'Falha ao sincronizar evento no Google Agenda')
        };
      }
    }

    return res.json({ ok: true, id: reservaIdFinal, escopoAplicado, googleAgenda });
  } catch (err) {
    try { await client.query('ROLLBACK'); } catch {}
    console.error('[API] /api/rh/reservas PUT erro:', err);
    return res.status(500).json({ error: 'Falha ao atualizar reserva RH' });
  } finally {
    client.release();
  }
});

// DELETE /api/rh/reservas/:id
// Exclui uma reserva (ou toda a série se for recorrente, pois é um único registro no BD).
// O criador e o setor RH podem excluir.
app.delete('/api/rh/reservas/:id', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) {
    return res.status(401).json({ error: 'Usuário não autenticado' });
  }
  const reservaId = Number(req.params?.id);
  if (!Number.isInteger(reservaId) || reservaId <= 0) {
    return res.status(400).json({ error: 'ID inválido' });
  }

  const body = req.body || {};
  const escopoSolicitado = String(body.aplicarEm || '').trim().toLowerCase();
  const aplicarEm = escopoSolicitado === 'este_dia'
    ? 'este_dia'
    : (escopoSolicitado === 'todos_futuros' ? 'todos_futuros' : 'registro');
  const dataOcorrenciaReq = normalizarDataIsoRh(body.data || null);

  const client = await pool.connect();
  try {
    const { rows } = await client.query(
      `SELECT criado_por, data_reserva, repetir, repetir_todos_meses, dias_semana, datas_excecao,
              google_event_id, google_calendar_id
         FROM rh.reservas_ambientes
        WHERE id = $1
        LIMIT 1`,
      [reservaId]
    );
    if (!rows.length) {
      return res.status(404).json({ error: 'Reserva não encontrada' });
    }
    const criador = String(rows[0].criado_por || '').trim().toLowerCase();
    const userNorm = String(userLogado).trim().toLowerCase();
    const userEhRh = await usuarioEhSetorRhCalendario(req);
    if (!userNorm || (criador !== userNorm && !userEhRh)) {
      return res.status(403).json({ error: 'Somente o criador ou o setor RH pode excluir esta reserva' });
    }

    const reservaAtual = rows[0];
    const reservaRecorrente = !!reservaAtual.repetir;

    if (reservaRecorrente && aplicarEm !== 'registro') {
      const dataBaseIso = normalizarDataIsoRh(reservaAtual.data_reserva) || String(reservaAtual.data_reserva || '').slice(0, 10);
      const datasExcecaoAtuais = normalizarDatasExcecaoRh(reservaAtual.datas_excecao);
      const dataAlvo = dataOcorrenciaReq || dataBaseIso;
      const anoSerie = new Date(`${dataAlvo}T00:00:00`).getFullYear();
      const ocorrenciasAtuais = gerarOcorrenciasReservaRecorrenteNoAnoRh({
        ano: anoSerie,
        dataBaseIso,
        repetirTodosMeses: !!reservaAtual.repetir_todos_meses,
        diasSemana: normalizarDiasSemanaRh(reservaAtual.dias_semana),
        datasExcecao: datasExcecaoAtuais
      });

      const dataCorte = ocorrenciasAtuais.includes(dataAlvo) ? dataAlvo : dataBaseIso;

      if (aplicarEm === 'este_dia') {
        const novasExcecoes = unirDatasExcecaoRh(datasExcecaoAtuais, [dataCorte]);
        await client.query(
          `UPDATE rh.reservas_ambientes
              SET datas_excecao = $1::date[],
                  atualizado_em = NOW()
            WHERE id = $2`,
          [novasExcecoes, reservaId]
        );
        return res.json({ ok: true, escopoAplicado: 'este_dia' });
      }

      const datasFuturas = ocorrenciasAtuais.filter((d) => d >= dataCorte);
      if (datasFuturas.length) {
        const novasExcecoes = unirDatasExcecaoRh(datasExcecaoAtuais, datasFuturas);
        await client.query(
          `UPDATE rh.reservas_ambientes
              SET datas_excecao = $1::date[],
                  atualizado_em = NOW()
            WHERE id = $2`,
          [novasExcecoes, reservaId]
        );
        return res.json({ ok: true, escopoAplicado: 'todos_futuros' });
      }
    }

    const googleEventId = String(reservaAtual.google_event_id || '').trim() || null;
    const googleCalendarId = String(reservaAtual.google_calendar_id || '').trim() || 'primary';
    if (googleEventId) {
      try {
        await excluirReservaGoogleCalendar({
          username: userLogado,
          googleEventId,
          googleCalendarId
        });
      } catch (errGoogleDelete) {
        logFalhaGoogleCalendar({
          operacao: 'delete_event_before_reserva_delete',
          username: userLogado,
          reservaId,
          err: errGoogleDelete,
          reservaLocalSalva: false
        });
      }
    }

    // Cascade apaga participantes automaticamente (ON DELETE CASCADE)
    await client.query(`DELETE FROM rh.reservas_ambientes WHERE id = $1`, [reservaId]);
    return res.json({ ok: true, escopoAplicado: 'registro' });
  } catch (err) {
    console.error('[API] /api/rh/reservas DELETE erro:', err);
    return res.status(500).json({ error: 'Falha ao excluir reserva' });
  } finally {
    client.release();
  }
});

// ── Atas de Reunião ───────────────────────────────────────────────────────
// GET  /api/rh/atas?reserva_id=X  → lista todas as atas da reserva (ordem de criação, estável)
app.get('/api/rh/atas', async (req, res) => {
  const reservaId = Number(req.query?.reserva_id);
  if (!Number.isInteger(reservaId) || reservaId <= 0) {
    return res.status(400).json({ error: 'reserva_id inválido' });
  }
  try {
    const refRs = await pool.query(
      `SELECT COALESCE(ata_referencia_reserva_id, id) AS ata_reserva_id
         FROM rh.reservas_ambientes
        WHERE id = $1
        LIMIT 1`,
      [reservaId]
    );
    if (!refRs.rows.length) {
      return res.status(404).json({ error: 'Reserva não encontrada' });
    }
    const ataReservaId = Number(refRs.rows[0].ata_reserva_id) || reservaId;

    const { rows } = await pool.query(
      `SELECT id, reserva_id, tema, conteudo, criado_por,
              excluido, excluido_por,
              TO_CHAR(criado_em AT TIME ZONE 'America/Sao_Paulo', 'DD/MM/YYYY') AS criado_em_fmt,
              TO_CHAR(excluido_em AT TIME ZONE 'America/Sao_Paulo', 'DD/MM/YYYY HH24:MI') AS excluido_em_fmt
         FROM rh.atas_reuniao
        WHERE reserva_id = $1
        ORDER BY id ASC`,
      [ataReservaId]
    );

    const ids = rows.map(r => Number(r.id)).filter(Number.isInteger);
    const tarefasPorAta = new Map();
    if (ids.length) {
      const tarefasRs = await pool.query(
        `SELECT id, ata_id, linha_numero, texto, concluida,
                TO_CHAR(prazo, 'YYYY-MM-DD') AS prazo
           FROM rh.ata_tarefas
          WHERE ata_id = ANY($1::bigint[])
          ORDER BY ata_id ASC, linha_numero ASC, id ASC`,
        [ids]
      );
      tarefasRs.rows.forEach((t) => {
        const key = Number(t.ata_id);
        if (!tarefasPorAta.has(key)) tarefasPorAta.set(key, []);
        tarefasPorAta.get(key).push({
          id: Number(t.id),
          linha_numero: Number(t.linha_numero),
          texto: String(t.texto || ''),
          concluida: !!t.concluida,
          prazo: t.prazo || null
        });
      });
    }

    const atas = rows.map((r) => ({ ...r, tarefas: tarefasPorAta.get(Number(r.id)) || [] }));
    return res.json({ ok: true, atas });
  } catch (err) {
    console.error('[API] /api/rh/atas GET erro:', err);
    return res.status(500).json({ error: 'Falha ao buscar atas' });
  }
});

// POST /api/rh/atas  { reserva_id, tema, conteudo }
app.post('/api/rh/atas', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) return res.status(401).json({ error: 'Não autenticado' });

  const body = req.body || {};
  const reservaId = Number(body.reserva_id);
  const tema = String(body.tema || '').trim();
  const conteudo = String(body.conteudo || '').trim();

  if (!Number.isInteger(reservaId) || reservaId <= 0) return res.status(400).json({ error: 'reserva_id inválido' });
  if (!tema) return res.status(400).json({ error: 'Tema obrigatório' });
  if (!conteudo) return res.status(400).json({ error: 'Conteúdo obrigatório' });

  const client = await pool.connect();
  try {
    const refRs = await client.query(
      `SELECT COALESCE(ata_referencia_reserva_id, id) AS ata_reserva_id,
              data_reserva, hora_inicio
         FROM rh.reservas_ambientes
        WHERE id = $1
        LIMIT 1`,
      [reservaId]
    );
    if (!refRs.rows.length) {
      return res.status(404).json({ error: 'Reserva não encontrada' });
    }
    const ataReservaId = Number(refRs.rows[0].ata_reserva_id) || reservaId;
    const dataReserva = refRs.rows[0].data_reserva;
    const horaInicio = refRs.rows[0].hora_inicio;

    await client.query('BEGIN');
    const { rows } = await client.query(
      `INSERT INTO rh.atas_reuniao (reserva_id, tema, conteudo, criado_por)
       VALUES ($1, $2, $3, $4) RETURNING id`,
      [ataReservaId, tema, conteudo, userLogado]
    );
    const ataId = Number(rows[0]?.id);
    await sincronizarAtaTarefasRh(client, {
      ataId,
      reservaId: ataReservaId,
      criadoPor: userLogado,
      conteudo
    });
    await client.query('COMMIT');

    // Disparo automático de mensagem para usuários mencionados via @
    try {
      const mencoesMatch = conteudo.match(/(^|[^\w])@([\w.\-]+)/g) || [];
      const usernamesMencionados = [...new Set(
        mencoesMatch
          .map(m => m.replace(/^[^\w]*@/, '').trim().toLowerCase())
          .filter(u => u && !/^prazo$/i.test(u))
      )];

      if (usernamesMencionados.length > 0) {
        // Busca ID do remetente (quem mencionou)
        const senderRs = await pool.query(
          `SELECT id FROM public.auth_user WHERE LOWER(username) = LOWER($1) AND is_active = true LIMIT 1`,
          [userLogado]
        );
        const senderId = senderRs.rows[0]?.id;
        if (!senderId) throw new Error(`Remetente ${userLogado} não encontrado`);

        // Formata data e hora da reunião
        let dataHoraFormatada = '';
        if (dataReserva) {
          const d = new Date(dataReserva);
          const dia = String(d.getUTCDate()).padStart(2, '0');
          const mes = String(d.getUTCMonth() + 1).padStart(2, '0');
          const ano = d.getUTCFullYear();
          dataHoraFormatada = `${dia}/${mes}/${ano}`;
        }
        if (horaInicio) {
          dataHoraFormatada += ` ${String(horaInicio).slice(0, 5)}`;
        }

        for (const username of usernamesMencionados) {
          try {
            const destRs = await pool.query(
              `SELECT id FROM public.auth_user WHERE LOWER(username) = LOWER($1) AND is_active = true LIMIT 1`,
              [username]
            );
            const destId = destRs.rows[0]?.id;
            if (!destId) continue;

            const textoMensagem =
              `🤖 Mensagem automática\n` +
              `Você foi mencionado em uma ata\n` +
              `Data e hora da reunião: ${dataHoraFormatada}\n` +
              `---\n` +
              `${conteudo}`;

            await pool.query(
              'SELECT send_chat_message($1, $2, $3)',
              [senderId, destId, textoMensagem]
            );
          } catch (msgErr) {
            console.warn(`[atas] falha ao notificar @${username}:`, msgErr?.message || msgErr);
          }
        }
      }
    } catch (notifErr) {
      console.warn('[atas] falha no bloco de notificações de @menção:', notifErr?.message || notifErr);
    }

    return res.json({ ok: true, id: rows[0].id });
  } catch (err) {
    try { await client.query('ROLLBACK'); } catch (_) {}
    console.error('[API] /api/rh/atas POST erro:', err);
    return res.status(500).json({ error: 'Falha ao salvar ata' });
  } finally {
    client.release();
  }
});

// PUT /api/rh/atas/:id — alterna riscar/restaurar (toggle ~~...~~) — somente autor
app.put('/api/rh/atas/:id', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) return res.status(401).json({ error: 'Não autenticado' });

  const ataId = Number(req.params?.id);
  if (!Number.isInteger(ataId) || ataId <= 0) return res.status(400).json({ error: 'ID inválido' });

  const client = await pool.connect();
  try {
    const { rows } = await client.query(
      `SELECT criado_por, conteudo, reserva_id FROM rh.atas_reuniao WHERE id = $1 LIMIT 1`,
      [ataId]
    );
    if (!rows.length) return res.status(404).json({ error: 'Ata não encontrada' });
    if (String(rows[0].criado_por || '').toLowerCase() !== userLogado.toLowerCase()) {
      return res.status(403).json({ error: 'Somente o autor pode riscar esta anotação' });
    }
    const atual = String(rows[0].conteudo || '');
    let novoConteudo;
    // Se passou body.conteudo → edição direta do texto
    if (req.body && typeof req.body.conteudo === 'string') {
      const textoEditado = req.body.conteudo.trim();
      if (!textoEditado) return res.status(400).json({ error: 'Conteúdo não pode ficar vazio' });
      novoConteudo = textoEditado;
    } else {
      // Toggle: se já está riscado (~~...~~) restaura; senão risca
      novoConteudo = atual.startsWith('~~') && atual.endsWith('~~')
        ? atual.slice(2, -2)
        : `~~${atual}~~`;
    }
    await client.query('BEGIN');
    await client.query(`UPDATE rh.atas_reuniao SET conteudo = $1 WHERE id = $2`, [novoConteudo, ataId]);
    await sincronizarAtaTarefasRh(client, {
      ataId,
      reservaId: Number(rows[0].reserva_id),
      criadoPor: userLogado,
      conteudo: novoConteudo
    });
    await client.query('COMMIT');
    return res.json({ ok: true, conteudo: novoConteudo });
  } catch (err) {
    try { await client.query('ROLLBACK'); } catch (_) {}
    console.error('[API] PUT /api/rh/atas erro:', err);
    return res.status(500).json({ error: 'Falha ao atualizar ata' });
  } finally {
    client.release();
  }
});

// PATCH /api/rh/ata-tarefas/:id/toggle — alterna status do checkbox e espelha no texto da ata
app.patch('/api/rh/ata-tarefas/:id/toggle', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) return res.status(401).json({ error: 'Não autenticado' });

  const tarefaId = Number(req.params?.id);
  if (!Number.isInteger(tarefaId) || tarefaId <= 0) return res.status(400).json({ error: 'ID inválido' });

  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    const taskRs = await client.query(
      `SELECT t.id, t.ata_id, t.linha_numero, t.concluida, a.conteudo, a.criado_por
         FROM rh.ata_tarefas t
         JOIN rh.atas_reuniao a ON a.id = t.ata_id
        WHERE t.id = $1
        LIMIT 1`,
      [tarefaId]
    );
    if (!taskRs.rows.length) {
      await client.query('ROLLBACK');
      return res.status(404).json({ error: 'Tarefa não encontrada' });
    }

    const task = taskRs.rows[0];
    if (String(task.criado_por || '').toLowerCase() !== userLogado.toLowerCase()) {
      await client.query('ROLLBACK');
      return res.status(403).json({ error: 'Somente o autor pode marcar esta tarefa' });
    }

    const novoStatus = !task.concluida;
    await client.query(
      `UPDATE rh.ata_tarefas
          SET concluida = $1,
              atualizado_em = NOW()
        WHERE id = $2`,
      [novoStatus, tarefaId]
    );

    const linhas = String(task.conteudo || '').split(/\r?\n/);
    const idxLinha = Math.max(0, Number(task.linha_numero) - 1);
    if (idxLinha < linhas.length) {
      const linhaAtual = String(linhas[idxLinha] || '');
      if (/^\s*\[( |x|X)\]\s*/.test(linhaAtual)) {
        linhas[idxLinha] = linhaAtual.replace(/^\s*\[( |x|X)\]/, novoStatus ? '[x]' : '[ ]');
        await client.query(`UPDATE rh.atas_reuniao SET conteudo = $1 WHERE id = $2`, [linhas.join('\n'), task.ata_id]);
      }
    }

    await client.query('COMMIT');
    return res.json({ ok: true, concluida: novoStatus });
  } catch (err) {
    try { await client.query('ROLLBACK'); } catch (_) {}
    console.error('[API] PATCH /api/rh/ata-tarefas/:id/toggle erro:', err);
    return res.status(500).json({ error: 'Falha ao alternar tarefa' });
  } finally {
    client.release();
  }
});

// DELETE /api/rh/atas/:id  — exclusão lógica (soft-delete), somente o autor
app.delete('/api/rh/atas/:id', async (req, res) => {
  const userLogado = (resolverUsuarioAuditoria(req) || '').trim();
  if (!userLogado) return res.status(401).json({ error: 'Não autenticado' });

  const ataId = Number(req.params?.id);
  if (!Number.isInteger(ataId) || ataId <= 0) return res.status(400).json({ error: 'ID inválido' });

  try {
    const { rows } = await pool.query(`SELECT criado_por, excluido FROM rh.atas_reuniao WHERE id = $1 LIMIT 1`, [ataId]);
    if (!rows.length) return res.status(404).json({ error: 'Ata não encontrada' });
    if (String(rows[0].criado_por || '').toLowerCase() !== userLogado.toLowerCase()) {
      return res.status(403).json({ error: 'Somente o autor pode excluir esta anotação' });
    }
    if (rows[0].excluido) return res.status(409).json({ error: 'Anotação já excluída' });
    await pool.query(
      `UPDATE rh.atas_reuniao SET excluido = TRUE, excluido_por = $1, excluido_em = NOW() WHERE id = $2`,
      [userLogado, ataId]
    );
    return res.json({ ok: true });
  } catch (err) {
    console.error('[API] /api/rh/atas DELETE erro:', err);
    return res.status(500).json({ error: 'Falha ao excluir ata' });
  }
});

