// ========== ENDPOINTS DE HISTÓRICO DE SOLICITAÇÕES ==========

// GET /api/compras/historico/resumo - Estatísticas do histórico (DEVE VIR ANTES DO :id)
// ========================================
//  Endpoint: Gráfico histórico de compras (created_at x valor_pedido)
// ========================================
/**
 * GET /api/compras/grafico-historico
 * Retorna valor total de pedidos por dia a partir de compras.historico_compras
 * Parâmetros opcionais: dataInicio, dataFim (formato YYYY-MM-DD)
 */
// ========================================
//  Endpoint: Gráfico pizza por Departamento / Centro de Custo
// ========================================
/**
 * GET /api/compras/grafico-pizza-dept-cc
 * Retorna valor somado por status:
 *   - "Compra realizada" : compras.pedidos_omie — inativo=false, agrupado por Etapa_NF (join logistica.etapas_recebimento_nfe)
 *   - "Recebimento"      : logistica.recebimentos_nfe_omie — c_recebido=S, c_cancelada=N, c_bloqueado=N, c_devolvido=N, c_etapa=80, filtro d_rec
 * Parâmetros: dataInicio, dataFim (YYYY-MM-DD)
 */
app.get('/api/compras/grafico-pizza-dept-cc', async (req, res) => {
  try {
    const { dataInicio, dataFim } = req.query;

    // --- Barra 1: Compra realizada por Etapa_NF (pedidos_omie) ---
    // Agrupa todas as etapas (sem filtrar por NULL), fazendo JOIN com a tabela de etapas para trazer descrição.
    // Etapa_NF NULL = 'Aguardando recebimento'
    const paramsCompra = [];
    const whereCompra = [`p.inativo = false`];
    if (dataInicio) { paramsCompra.push(dataInicio); whereCompra.push(`p.d_inc_data >= $${paramsCompra.length}::date`); }
    if (dataFim)    { paramsCompra.push(dataFim);    whereCompra.push(`p.d_inc_data <= $${paramsCompra.length}::date`); }

    const r1 = await pool.query(`
      SELECT
        p."Etapa_NF"                                                AS etapa_codigo,
        COALESCE(e.descricao, 'Aguardando recebimento')             AS etapa_descricao,
        COALESCE(e.ordem, 0)                                        AS etapa_ordem,
        COALESCE(SUM(p.n_valor), 0)                                 AS total
      FROM compras.pedidos_omie p
      LEFT JOIN logistica.etapas_recebimento_nfe e ON e.codigo = p."Etapa_NF"
      WHERE ${whereCompra.join(' AND ')}
      GROUP BY p."Etapa_NF", e.descricao, e.ordem
      ORDER BY e.ordem NULLS FIRST
    `, paramsCompra);

    // --- Barra 2: Recebimento por ano da compra original (pedidos_omie.d_inc_data) ---
    // Junta recebimentos_nfe_omie → recebimentos_nfe_itens (n_id_receb) → pedidos_omie (n_cod_ped = n_id_pedido)
    // Agrupa por ano de d_inc_data para mostrar "de quando foi a compra" de cada recebimento.
    // NFs sem pedido vinculado ficam na camada "Sem pedido vinculado".
    const paramsReceb = [];
    const whereRecebBase = [
      `r.c_recebido = 'S'`,
      `r.c_cancelada = 'N'`,
      `r.c_bloqueado = 'N'`,
      `r.c_devolvido = 'N'`,
      `r.c_etapa = '80'`,
    ];
    if (dataInicio) { paramsReceb.push(dataInicio); whereRecebBase.push(`r.d_rec >= $${paramsReceb.length}::date`); }
    if (dataFim)    { paramsReceb.push(dataFim);    whereRecebBase.push(`r.d_rec <= $${paramsReceb.length}::date`); }

    // Recebimentos COM pedido vinculado, agrupados por mês/ano de d_inc_data
    const r2 = await pool.query(`
      SELECT
        TO_CHAR(ped.d_inc_data, 'MM/YYYY') AS ano_compra,
        MIN(ped.d_inc_data)                AS data_ord,
        COALESCE(SUM(i.v_total_item), 0)   AS total
      FROM logistica.recebimentos_nfe_omie r
      JOIN logistica.recebimentos_nfe_itens i ON i.n_id_receb = r.n_id_receb
      JOIN compras.pedidos_omie ped           ON ped.n_cod_ped = i.n_id_pedido
      WHERE ${whereRecebBase.join(' AND ')}
        AND i.n_id_pedido IS NOT NULL AND i.n_id_pedido > 0
      GROUP BY TO_CHAR(ped.d_inc_data, 'MM/YYYY')
      ORDER BY MIN(ped.d_inc_data)
    `, paramsReceb);

    // Recebimentos SEM pedido vinculado (n_id_pedido nulo ou 0)
    const r2sem = await pool.query(`
      SELECT COALESCE(SUM(i.v_total_item), 0) AS total
      FROM logistica.recebimentos_nfe_omie r
      LEFT JOIN logistica.recebimentos_nfe_itens i ON i.n_id_receb = r.n_id_receb
      WHERE ${whereRecebBase.join(' AND ')}
        AND (i.n_id_pedido IS NULL OR i.n_id_pedido = 0)
    `, paramsReceb);

    // Monta dados: uma entrada por etapa de "Compra realizada" + uma por ano de compra do "Recebimento"
    const etapasCompra = r1.rows.map(row => ({
      status:          'Compra realizada',
      etapa_codigo:    row.etapa_codigo,
      etapa_descricao: row.etapa_descricao,
      total:           Number(row.total),
    }));

    const etapasReceb = r2.rows
      .filter(row => Number(row.total) > 0)
      .map(row => ({
        status:          'Recebimento',
        etapa_codigo:    row.ano_compra,
        etapa_descricao: `Compra em ${row.ano_compra}`,
        total:           Number(row.total),
      }));

    const totalSemPedido = Number(r2sem.rows[0].total);
    if (totalSemPedido > 0) {
      etapasReceb.push({
        status:          'Recebimento',
        etapa_codigo:    'sem_pedido',
        etapa_descricao: 'Sem pedido vinculado',
        total:           totalSemPedido,
      });
    }

    const dados = [
      ...etapasCompra,
      ...etapasReceb,
    ];

    res.json({ ok: true, dados });
  } catch (err) {
    console.error('[Compras/GraficoPizzaDeptCC] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar dados do gráfico' });
  }
});

// ========================================
//  Endpoint: Gráfico Realizado x Recebido por Mês
// ========================================
/**
 * GET /api/compras/grafico-meses
 * Eixo X = mês de compra (d_inc_data de compras.pedidos_omie).
 * Barra 1 (azul)  : total realizado naquele mês (n_valor).
 * Barras 2-N (verdes empilhadas): quanto foi recebido daquelas compras,
 *   dividido pelo mês de recebimento (d_rec) de logistica.recebimentos_nfe_omie
 *   onde c_recebido = 'S'. Ligação: pedidos_omie → recebimentos_nfe_itens → recebimentos_nfe_omie.
 * Parâmetros: dataInicio, dataFim (YYYY-MM-DD) — filtram d_inc_data do pedido.
 */
app.get('/api/compras/grafico-meses', async (req, res) => {
  try {
    const { dataInicio, dataFim } = req.query;
    const params = [];
    const whereCompra = [`p.inativo = false`];
    if (dataInicio) { params.push(dataInicio); whereCompra.push(`p.d_inc_data >= $${params.length}::date`); }
    if (dataFim)    { params.push(dataFim);    whereCompra.push(`p.d_inc_data <= $${params.length}::date`); }

    // Total realizado por mês de compra (d_inc_data)
    const rCompra = await pool.query(`
      SELECT
        TO_CHAR(p.d_inc_data, 'MM/YYYY') AS mes,
        MIN(p.d_inc_data)                AS data_ord,
        COALESCE(SUM(p.n_valor), 0)      AS total_realizado
      FROM compras.pedidos_omie p
      WHERE ${whereCompra.join(' AND ')}
      GROUP BY TO_CHAR(p.d_inc_data, 'MM/YYYY')
      ORDER BY MIN(p.d_inc_data)
    `, params);

    // Total recebido por combinação (mês de compra × mês de recebimento d_rec).
    // Usa i.v_total_item (valor do ITEM do pedido naquela NF), NÃO n_valor_nfe.
    // n_valor_nfe é o total da NF inteira — se a NF tiver N pedidos vinculados,
    // seria contado N vezes. v_total_item já é o valor específico daquele item/pedido.
    // Ligação: pedidos_omie (n_cod_ped) → recebimentos_nfe_itens (n_id_pedido) → recebimentos_nfe_omie (n_id_receb).
    const rReceb = await pool.query(`
      SELECT
        TO_CHAR(ped.d_inc_data, 'MM/YYYY') AS mes_compra,
        TO_CHAR(r.d_rec, 'MM/YY')          AS mes_rec,
        MIN(ped.d_inc_data)                AS data_ord_compra,
        MIN(r.d_rec)                       AS data_ord_rec,
        COALESCE(SUM(i.v_total_item), 0)   AS total
      FROM compras.pedidos_omie ped
      JOIN logistica.recebimentos_nfe_itens i ON i.n_id_pedido = ped.n_cod_ped
      JOIN logistica.recebimentos_nfe_omie r  ON r.n_id_receb  = i.n_id_receb
      WHERE ${whereCompra.join(' AND ').replace(/p\./g, 'ped.')} AND r.c_recebido = 'S'
      GROUP BY TO_CHAR(ped.d_inc_data, 'MM/YYYY'), TO_CHAR(r.d_rec, 'MM/YY')
      ORDER BY MIN(ped.d_inc_data), MIN(r.d_rec)
    `, params);

    // Monta pivô: labels = meses de compra, camadas = meses de d_rec distintos
    const labels      = rCompra.rows.map(r => r.mes);
    const realizado   = rCompra.rows.map(r => Number(r.total_realizado));
    const labelIdx    = {};
    labels.forEach((l, i) => { labelIdx[l] = i; });

    // Coleta todos os d_rec meses distintos, em ordem cronológica.
    // Formato MM/AA (2 dígitos): adiciona 2000 para comparação correta.
    const mesRecSet = [...new Set(rReceb.rows.map(r => r.mes_rec))];
    mesRecSet.sort((a, b) => {
      const toDate = s => { const [m, y] = s.split('/'); return new Date(2000 + +y, +m - 1, 1); };
      return toDate(a) - toDate(b);
    });

    // Para cada d_rec mes, cria array de valores indexado pelos labels de compra
    const camadas_recebido = mesRecSet.map(mesRec => {
      const valores = labels.map(mesCompra => {
        const row = rReceb.rows.find(r => r.mes_compra === mesCompra && r.mes_rec === mesRec);
        return row ? Number(row.total) : 0;
      });
      return { mes_rec: mesRec, valores };
    });

    res.json({ ok: true, labels, realizado, camadas_recebido });
  } catch (err) {
    console.error('[Compras/GraficoMeses] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar gráfico de meses' });
  }
});

// ========================================
//  Endpoint: Detalhe de pedidos de um mês (clique na barra do gráfico de meses)
// ========================================
/**
 * GET /api/compras/grafico-meses-detalhe
 * Parâmetros:
 *   mesCompra  – "MM/YYYY" (mês/ano de d_inc_data do pedido)
 *   dataInicio – filtro de início do período geral (para consistência com o gráfico)
 *   dataFim    – filtro de fim do período geral
 * Retorna lista de pedidos do mês com:
 *   - n_cod_ped, fornecedor (razao_social), n_valor (valor do pedido)
 *   - d_inc_data (data da compra)
 *   - d_rec (data de recebimento — NULL se ainda não recebido)
 *   - v_recebido (soma de v_total_item recebidos)
 */
app.get('/api/compras/grafico-meses-detalhe', async (req, res) => {
  try {
    const { mesCompra, dataInicio, dataFim } = req.query;
    if (!mesCompra) return res.status(400).json({ ok: false, error: 'mesCompra obrigatório' });

    const params = [];
    const wherePed = [`p.inativo = false`];
    params.push(mesCompra);
    wherePed.push(`TO_CHAR(p.d_inc_data, 'MM/YYYY') = $${params.length}`);
    if (dataInicio) { params.push(dataInicio); wherePed.push(`p.d_inc_data >= $${params.length}::date`); }
    if (dataFim)    { params.push(dataFim);    wherePed.push(`p.d_inc_data <= $${params.length}::date`); }

    // ── Recebidos: uma linha por item de NF recebida ──────────────────────
    const rReceb = await pool.query(`
      SELECT
        p.c_numero,
        p.c_cod_categ,
        r.n_id_receb,
        COALESCE(r.n_valor_nfe, 0)          AS n_valor_nfe,
        TO_CHAR(r.d_rec, 'YYYY-MM-DD')      AS d_rec,
        i.c_codigo_produto,
        COALESCE(i.c_descricao_produto, '') AS c_descricao_produto,
        COALESCE(i.n_preco_unit, 0)         AS n_preco_unit,
        COALESCE(i.n_qtde_nfe, 0)           AS n_qtde_nfe
      FROM compras.pedidos_omie p
      JOIN logistica.recebimentos_nfe_itens i ON i.n_id_pedido = p.n_cod_ped
      JOIN logistica.recebimentos_nfe_omie r  ON r.n_id_receb  = i.n_id_receb
      WHERE ${wherePed.join(' AND ')} AND r.c_recebido = 'S'
      ORDER BY r.d_rec, p.c_numero, r.n_id_receb
    `, params);

    // Agrupa por NF (n_id_receb)
    const recebidosMap = new Map();
    for (const row of rReceb.rows) {
      const key = row.n_id_receb;
      if (!recebidosMap.has(key)) {
        recebidosMap.set(key, {
          c_numero:    row.c_numero,
          c_cod_categ: row.c_cod_categ || null,
          n_valor_nfe: Number(row.n_valor_nfe),
          d_rec:       row.d_rec,
          itens:       []
        });
      }
      if (row.c_codigo_produto) {
        recebidosMap.get(key).itens.push({
          c_codigo_produto:    row.c_codigo_produto,
          c_descricao_produto: row.c_descricao_produto,
          n_preco_unit:        Number(row.n_preco_unit),
          n_qtde_nfe:          Number(row.n_qtde_nfe)
        });
      }
    }
    const recebidos = [...recebidosMap.values()];

    // ── A receber: pedidos sem nenhum recebimento S + itens da requisição ───
    const rPendente = await pool.query(`
      SELECT
        p.c_numero,
        p.c_cod_categ,
        p.n_cod_ped,
        COALESCE(p.n_valor, 0) AS n_valor,
        COALESCE(
          roi.cod_int_prod::text,
          roi.cod_prod::text,
          roi.cod_int_item::text,
          roi.cod_item::text
        ) AS c_codigo_produto,
        COALESCE(roi.preco_unit, 0) AS n_preco_unit,
        COALESCE(roi.qtde, 0) AS n_qtde
      FROM compras.pedidos_omie p
      LEFT JOIN compras.requisicoes_omie_itens roi ON roi.cod_req_compra::text = p.n_cod_ped::text
      WHERE ${wherePed.join(' AND ')}
        AND p.n_cod_ped NOT IN (
          SELECT DISTINCT i2.n_id_pedido
          FROM logistica.recebimentos_nfe_itens i2
          JOIN logistica.recebimentos_nfe_omie r2 ON r2.n_id_receb = i2.n_id_receb
          WHERE r2.c_recebido = 'S' AND i2.n_id_pedido IS NOT NULL
        )
      ORDER BY p.c_numero, roi.cod_req_compra
    `, params);

    // Agrupa por pedido (n_cod_ped)
    const aReceberMap = new Map();
    for (const row of rPendente.rows) {
      const key = row.n_cod_ped;
      if (!aReceberMap.has(key)) {
        aReceberMap.set(key, {
          c_numero: row.c_numero,
          c_cod_categ: row.c_cod_categ || null,
          n_valor:  Number(row.n_valor),
          itens:    []
        });
      }
      if (row.c_codigo_produto) {
        aReceberMap.get(key).itens.push({
          c_codigo_produto: row.c_codigo_produto,
          n_preco_unit:     Number(row.n_preco_unit),
          n_qtde:           Number(row.n_qtde)
        });
      }
    }
    const a_receber = [...aReceberMap.values()];

    res.json({ ok: true, recebidos, a_receber });
  } catch (err) {
    console.error('[Compras/GraficoMesesDetalhe] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar detalhe' });
  }
});

// ========================================
//  Endpoint: Itens do pedido Omie (A receber)
// ========================================
/**
 * GET /api/compras/pedido-omie-itens
 * Parâmetros:
 *   cNumero - número do pedido Omie (cNumero)
 * Retorna lista simplificada de itens do pedido.
 */
app.get('/api/compras/pedido-omie-itens', async (req, res) => {
  try {
    const { cNumero } = req.query;
    if (!cNumero) return res.status(400).json({ ok: false, error: 'cNumero obrigatório' });
    if (!OMIE_APP_KEY || !OMIE_APP_SECRET) {
      return res.status(500).json({ ok: false, error: 'OMIE_APP_KEY/OMIE_APP_SECRET ausentes' });
    }

    const resp = await fetch('https://app.omie.com.br/api/v1/produtos/pedidocompra/', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        call: 'ConsultarPedCompra',
        app_key: OMIE_APP_KEY,
        app_secret: OMIE_APP_SECRET,
        param: [{ cNumero: String(cNumero) }]
      })
    });

    const data = await resp.json();
    if (!resp.ok || data?.faultstring) {
      return res.status(400).json({ ok: false, error: data?.faultstring || 'Falha ao consultar Omie' });
    }

    const itens = (data.produtos_consulta || []).map((it) => ({
      c_produto: it.cProduto || '',
      c_descricao: it.cDescricao || '',
      n_qtde: Number(it.nQtde || 0),
      c_unidade: it.cUnidade || '',
      n_val_unit: Number(it.nValUnit || 0)
    }));

    return res.json({ ok: true, itens });
  } catch (err) {
    console.error('[Compras/PedidoOmieItens] Erro:', err);
    return res.status(500).json({ ok: false, error: 'Erro ao consultar itens Omie' });
  }
});

// ========================================
//  Endpoint: Itens individuais por status (detalhes ao clicar no gráfico)
// ========================================
/**
 * GET /api/compras/grafico-pizza-itens
 * Retorna os itens individuais de historico_compras para um status dado,
 * enriquecidos com produto_codigo, produto_descricao, quantidade,
 * objetivo_compra e solicitante vindos das tabelas de origem.
 */
app.get('/api/compras/grafico-pizza-itens', async (req, res) => {
  try {
    const { status, dataInicio, dataFim, categoria } = req.query;
    if (!status) return res.status(400).json({ ok: false, error: 'Parâmetro status obrigatório' });

    if (status === 'Compra realizada') {
      // --- Itens de Compra realizada: pedidos_omie (todas as etapas) ---
      const params = [];
      const where = [`p.inativo = false`];
      if (dataInicio) { params.push(dataInicio); where.push(`p.d_inc_data >= $${params.length}::date`); }
      if (dataFim)    { params.push(dataFim);    where.push(`p.d_inc_data <= $${params.length}::date`); }

      // Filtro por categoria: grupo (categoria_superior=X) ou subcategoria exata (c_cod_categ=X)
      let joinCat = '';
      if (categoria) {
        params.push(categoria);
        const pIdx = params.length;
        joinCat = `JOIN configuracoes."ListarCategorias" cat ON cat.codigo = p.c_cod_categ`;
        where.push(`(cat.categoria_superior = $${pIdx} OR p.c_cod_categ = $${pIdx})`);
      }

      const { rows } = await pool.query(`
        SELECT
          p.n_cod_ped                                          AS h_id,
          p.c_numero,
          TO_CHAR(p.d_inc_data, 'YYYY-MM-DD')                 AS d_data,
          COALESCE(p.n_valor, 0)                               AS n_valor,
          COALESCE(
            NULLIF(BTRIM(f.nome_fantasia), ''),
            NULLIF(BTRIM(f.razao_social), ''),
            'Fornecedor não identificado'
          )                                                    AS fornecedor
        FROM compras.pedidos_omie p
        LEFT JOIN omie.fornecedores f ON f.codigo_cliente_omie = p.n_cod_for
        ${joinCat}
        WHERE ${where.join(' AND ')}
        ORDER BY p.d_inc_data DESC, p.n_cod_ped DESC
      `, params);

      return res.json({
        ok: true,
        itens: rows.map(r => ({
          h_id:       r.h_id,
          referencia: r.c_numero || '',
          d_data:     r.d_data   || '',
          valor_item: Number(r.n_valor),
          fornecedor: r.fornecedor,
          descricao:  '',
        }))
      });
    }

    if (status === 'Recebimento') {
      // --- Itens de Recebimento: recebimentos_nfe_omie + recebimentos_nfe_itens ---
      const params = [];
      const where = [
        `r.c_recebido = 'S'`,
        `r.c_cancelada = 'N'`,
        `r.c_bloqueado = 'N'`,
        `r.c_devolvido = 'N'`,
        `r.c_etapa = '80'`,
      ];
      if (dataInicio) { params.push(dataInicio); where.push(`r.d_rec >= $${params.length}::date`); }
      if (dataFim)    { params.push(dataFim);    where.push(`r.d_rec <= $${params.length}::date`); }

      // Filtro por categoria: grupo (categoria_superior=X) ou subcategoria exata (c_categoria_item=X)
      let joinCat = '';
      if (categoria) {
        params.push(categoria);
        const pIdx = params.length;
        joinCat = `JOIN configuracoes."ListarCategorias" cat ON cat.codigo = i.c_categoria_item`;
        where.push(`(cat.categoria_superior = $${pIdx} OR i.c_categoria_item = $${pIdx})`);
      }

      const { rows } = await pool.query(`
        SELECT
          r.n_id_receb,
          r.c_chave_nfe,
          TO_CHAR(r.d_rec, 'YYYY-MM-DD')     AS d_data,
          COALESCE(r.c_numero_nfe, '')        AS referencia,
          COALESCE(r.n_valor_nfe, 0)          AS n_valor_nfe,
          COALESCE(r.c_nome_fornecedor, 'Fornecedor não identificado') AS fornecedor,
          i.c_codigo_produto,
          COALESCE(i.c_descricao_produto, '') AS c_descricao_produto,
          COALESCE(i.n_preco_unit, 0)         AS n_preco_unit,
          COALESCE(i.n_qtde_nfe, 0)           AS n_qtde_nfe,
          COALESCE(i.v_total_item, 0)         AS v_total_item
        FROM logistica.recebimentos_nfe_omie r
        ${categoria ? 'INNER' : 'LEFT'} JOIN logistica.recebimentos_nfe_itens i ON i.n_id_receb = r.n_id_receb
        ${joinCat}
        WHERE ${where.join(' AND ')}
        ORDER BY r.d_rec DESC, r.n_id_receb DESC
      `, params);

      return res.json({
        ok: true,
        itens: rows.map(r => ({
          h_id:             r.n_id_receb,
          chave_nfe:        r.c_chave_nfe || '',
          referencia:       r.referencia,
          d_data:           r.d_data   || '',
          valor_item:       Number(r.n_valor_nfe),
          fornecedor:       r.fornecedor,
          descricao:        r.c_descricao_produto
            ? `${r.c_codigo_produto || ''} ${r.c_descricao_produto}`.trim()
            : '',
          preco_unit:       Number(r.n_preco_unit),
          qtde:             Number(r.n_qtde_nfe),
          v_total_item:     Number(r.v_total_item),
        }))
      });
    }

    return res.status(400).json({ ok: false, error: 'Status inválido' });

  } catch (err) {
    console.error('[Compras/GraficoPizzaItens] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar itens do gráfico' });
  }
});

// ========================================
/**
 * GET /api/compras/grafico-categorias
 * Retorna totais por categoria com suporte a drill-down (nivel pai/filho).
 * Parâmetros:
 *   status      - 'Recebimento' ou 'Compra realizada' (obrigatório)
 *   pai         - código da categoria pai para drill-down (opcional)
 *   dataInicio  - filtro de data início (opcional)
 *   dataFim     - filtro de data fim (opcional)
 * Sem pai: agrupa pelo pai direto da categoria do item (nível 1).
 * Com pai: agrupa pelos filhos diretos desse pai (nível 2).
 */
app.get('/api/compras/grafico-categorias', async (req, res) => {
  try {
    const { status, pai, dataInicio, dataFim, mesCompra } = req.query;
    if (!status) return res.status(400).json({ ok: false, error: 'Parâmetro status obrigatório' });

    const params = [];
    let q;

    if (status === 'Recebimento') {
      const where = [
        `r.c_recebido = 'S'`, `r.c_cancelada = 'N'`, `r.c_bloqueado = 'N'`,
        `r.c_devolvido = 'N'`, `r.c_etapa = '80'`,
        `i.c_categoria_item IS NOT NULL`, `i.c_categoria_item <> ''`,
      ];
      if (dataInicio) { params.push(dataInicio); where.push(`r.d_rec >= $${params.length}::date`); }
      if (dataFim)    { params.push(dataFim);    where.push(`r.d_rec <= $${params.length}::date`); }

      if (pai) {
        // Drill-down: subcategorias do pai selecionado
        params.push(pai);
        where.push(`cat.categoria_superior = $${params.length}`);
        q = `
          SELECT
            i.c_categoria_item AS codigo,
            COALESCE(NULLIF(BTRIM(cat.descricao),''), i.c_categoria_item, 'Sem Categoria') AS label,
            SUM(COALESCE(i.v_total_item, 0)) AS total
          FROM logistica.recebimentos_nfe_omie r
          JOIN logistica.recebimentos_nfe_itens i ON i.n_id_receb = r.n_id_receb
          JOIN configuracoes."ListarCategorias" cat ON cat.codigo = i.c_categoria_item
          WHERE ${where.join(' AND ')}
          GROUP BY i.c_categoria_item, cat.descricao
          ORDER BY total DESC
        `;
      } else {
        // Nível 1: agrupar pelo pai da categoria do item
        where.push(`cat.categoria_superior IS NOT NULL`, `cat.categoria_superior <> ''`);
        q = `
          SELECT
            cat.categoria_superior AS codigo,
            COALESCE(NULLIF(BTRIM(parent.descricao),''), cat.categoria_superior, 'Sem Categoria') AS label,
            SUM(COALESCE(i.v_total_item, 0)) AS total
          FROM logistica.recebimentos_nfe_omie r
          JOIN logistica.recebimentos_nfe_itens i ON i.n_id_receb = r.n_id_receb
          JOIN configuracoes."ListarCategorias" cat ON cat.codigo = i.c_categoria_item
          LEFT JOIN configuracoes."ListarCategorias" parent ON parent.codigo = cat.categoria_superior
          WHERE ${where.join(' AND ')}
          GROUP BY cat.categoria_superior, parent.descricao
          ORDER BY total DESC
        `;
      }
    } else if (status === 'Compra realizada') {
      const where = [
        `p.inativo = false`,
        `p.c_cod_categ IS NOT NULL`, `p.c_cod_categ <> ''`,
      ];
      if (dataInicio) { params.push(dataInicio); where.push(`p.d_inc_data >= $${params.length}::date`); }
      if (dataFim)    { params.push(dataFim);    where.push(`p.d_inc_data <= $${params.length}::date`); }
      if (mesCompra)  { params.push(mesCompra);  where.push(`TO_CHAR(p.d_inc_data, 'MM/YYYY') = $${params.length}`); }

      if (pai) {
        // Drill-down: subcategorias do pai selecionado
        params.push(pai);
        where.push(`cat.categoria_superior = $${params.length}`);
        q = `
          SELECT
            p.c_cod_categ AS codigo,
            COALESCE(NULLIF(BTRIM(cat.descricao),''), p.c_cod_categ, 'Sem Categoria') AS label,
            SUM(COALESCE(p.n_valor, 0)) AS total
          FROM compras.pedidos_omie p
          JOIN configuracoes."ListarCategorias" cat ON cat.codigo = p.c_cod_categ
          WHERE ${where.join(' AND ')}
          GROUP BY p.c_cod_categ, cat.descricao
          ORDER BY total DESC
        `;
      } else {
        // Nível 1: agrupar pelo pai da categoria do pedido
        where.push(`cat.categoria_superior IS NOT NULL`, `cat.categoria_superior <> ''`);
        q = `
          SELECT
            cat.categoria_superior AS codigo,
            COALESCE(NULLIF(BTRIM(parent.descricao),''), cat.categoria_superior, 'Sem Categoria') AS label,
            SUM(COALESCE(p.n_valor, 0)) AS total
          FROM compras.pedidos_omie p
          JOIN configuracoes."ListarCategorias" cat ON cat.codigo = p.c_cod_categ
          LEFT JOIN configuracoes."ListarCategorias" parent ON parent.codigo = cat.categoria_superior
          WHERE ${where.join(' AND ')}
          GROUP BY cat.categoria_superior, parent.descricao
          ORDER BY total DESC
        `;
      }
    } else {
      return res.status(400).json({ ok: false, error: 'Status inválido' });
    }

    const { rows } = await pool.query(q, params);
    return res.json({
      ok: true,
      nivelAtual: pai || null,
      categorias: rows.map(r => ({ codigo: r.codigo, label: r.label, total: Number(r.total) }))
    });

  } catch (err) {
    console.error('[Compras/GraficoCategorias] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar categorias' });
  }
});

app.get('/api/compras/grafico-historico', async (req, res) => {
  try {
    const { dataInicio, dataFim } = req.query;
    const params = [];
    let whereClauses = `WHERE valor_pedido IS NOT NULL AND valor_pedido > 0`;

    if (dataInicio) { params.push(dataInicio); whereClauses += ` AND created_at::date >= $${params.length}::date`; }
    if (dataFim)    { params.push(dataFim);    whereClauses += ` AND created_at::date <= $${params.length}::date`; }

    const { rows } = await pool.query(`
      SELECT
        DATE(created_at)          AS data,
        SUM(valor_pedido)         AS total
      FROM compras.historico_compras
      ${whereClauses}
      GROUP BY DATE(created_at)
      ORDER BY data ASC
    `, params);

    res.json({ ok: true, dados: rows.map(r => ({
      data: r.data,           // date string YYYY-MM-DD
      total: Number(r.total)  // valor somado no dia
    })) });
  } catch (err) {
    console.error('[Compras/GraficoHistorico] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao carregar dados do gráfico' });
  }
});

app.get('/api/compras/historico/resumo', async (req, res) => {
  try {
    const { dias = 30, table_source } = req.query;
    const diasInt = Number.parseInt(dias, 10) || 30;
    const tableSource = String(table_source || '').trim();

    let query = `
      SELECT 
        operacao,
        campo_alterado,
        COUNT(*) as total,
        COUNT(DISTINCT (COALESCE(table_source, 'solicitacao_compras') || ':' || solicitacao_id::TEXT)) as itens_afetados,
        COUNT(DISTINCT COALESCE(NULLIF(TRIM(usuario), ''), 'sistema')) as usuarios_distintos
      FROM compras.historico_solicitacao_compras
      WHERE created_at >= NOW() - ($1::INT * INTERVAL '1 day')
    `;
    const params = [diasInt];
    let paramIndex = 2;

    if (tableSource) {
      query += ` AND table_source = $${paramIndex}`;
      params.push(tableSource);
      paramIndex++;
    }

    query += `
      GROUP BY operacao, campo_alterado
      ORDER BY total DESC
    `;

    const { rows } = await pool.query(query, params);
    
    console.log(`[Compras] Resumo do histórico: ${rows.length} tipos de operações`);
    res.json({ ok: true, resumo: rows });
  } catch (err) {
    console.error(`[Compras] Erro ao gerar resumo do histórico:`, err);
    res.status(500).json({ ok: false, error: err.message });
  }
});

// GET /api/compras/historico - Lista histórico com filtros opcionais (DEVE VIR ANTES DO :id)
app.get('/api/compras/historico', async (req, res) => {
  try {
    const { usuario, operacao, table_source, dias = 30, limit = 100 } = req.query;
    const diasInt = Number.parseInt(dias, 10) || 30;
    const limitInt = Number.parseInt(limit, 10) || 100;
    const tableSource = String(table_source || '').trim();
    
    let query = `
      SELECT 
        id,
        solicitacao_id,
        table_source,
        operacao,
        campo_alterado,
        valor_anterior,
        valor_novo,
        usuario,
        descricao_item,
        status_item,
        departamento,
        created_at
      FROM compras.historico_solicitacao_compras
      WHERE created_at >= NOW() - ($1::INT * INTERVAL '1 day')
    `;
    
    const params = [diasInt];
    let paramIndex = 2;
    
    if (tableSource) {
      query += ` AND table_source = $${paramIndex}`;
      params.push(tableSource);
      paramIndex++;
    }
    
    if (usuario) {
      query += ` AND usuario = $${paramIndex}`;
      params.push(usuario);
      paramIndex++;
    }
    
    if (operacao) {
      query += ` AND operacao = $${paramIndex}`;
      params.push(operacao.toUpperCase());
      paramIndex++;
    }
    
    query += ` ORDER BY created_at DESC LIMIT $${paramIndex}`;
    params.push(limitInt);
    
    const { rows } = await pool.query(query, params);
    
    console.log(`[Compras] Histórico geral: ${rows.length} registros (últimos ${dias} dias)`);
    res.json({ ok: true, historico: rows });
  } catch (err) {
    console.error(`[Compras] Erro ao buscar histórico geral:`, err);
    res.status(500).json({ ok: false, error: err.message });
  }
});

