// Upload de arquivos para Supabase Storage (compras e outros anexos)
app.post('/api/upload/supabase', upload.single('file'), async (req, res) => {
  try {
    if (!req.file) return res.status(400).json({ error: 'Nenhum arquivo enviado' });
    
    const { createClient } = require('@supabase/supabase-js');
    // Usa as credenciais corretas do .env (service_role para upload no backend)
    const supabaseUrl = process.env.SUPABASE_URL;
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE;
    
    if (!supabaseUrl || !supabaseKey) {
      console.error('[Supabase Upload] Credenciais não configuradas no .env');
      return res.status(500).json({ error: 'Supabase não configurado' });
    }
    
    const supabase = createClient(supabaseUrl, supabaseKey);
    
    // Permite especificar o bucket via body; padrão: 'compras-anexos'
    const ALLOWED_BUCKETS = ['compras-anexos', 'Funcionarios'];
    const requestedBucket = String(req.body.bucket || '').trim();
    const bucketName = ALLOWED_BUCKETS.includes(requestedBucket) ? requestedBucket : 'compras-anexos';
    const filePath = req.body.path || `uploads/${Date.now()}_${req.file.originalname}`;
    
    // Verifica se o bucket existe, se não existir, cria
    try {
      const { data: buckets } = await supabase.storage.listBuckets();
      const bucketExists = buckets?.some(b => b.name === bucketName);
      
      const allowedMimes = [
        'image/*', 'application/pdf',
        'application/msword',
        'application/vnd.ms-excel', 'application/vnd.ms-powerpoint',
        'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'application/vnd.openxmlformats-officedocument.presentationml.presentation',
        'text/plain', 'application/zip', 'application/x-zip-compressed'
      ];
      if (!bucketExists) {
        console.log(`[Supabase] Criando bucket '${bucketName}'...`);
        const { error: createError } = await supabase.storage.createBucket(bucketName, {
          public: true,
          fileSizeLimit: 10485760, // 10MB
          allowedMimeTypes: allowedMimes
        });
        if (createError) {
          console.error('[Supabase] Erro ao criar bucket:', createError);
        } else {
          console.log(`[Supabase] Bucket '${bucketName}' criado com sucesso`);
        }
      } else {
        // Atualiza tipos permitidos para incluir formatos Office adicionados posteriormente
        await supabase.storage.updateBucket(bucketName, { allowedMimeTypes: allowedMimes }).catch(() => {});
      }
    } catch (bucketError) {
      console.warn('[Supabase] Erro ao verificar/criar bucket:', bucketError.message);
      // Continua com o upload de qualquer forma
    }
    
    const { data, error } = await supabase.storage
      .from(bucketName)
      .upload(filePath, req.file.buffer, {
        contentType: req.file.mimetype,
        upsert: false
      });
    
    if (error) {
      console.error('[Supabase Upload Error]', error);
      return res.status(500).json({ error: error.message });
    }
    
    // Gera URL pública
    const { data: publicData } = supabase.storage
      .from(bucketName)
      .getPublicUrl(filePath);
    
    res.json({ 
      ok: true, 
      path: filePath,
      url: publicData.publicUrl
    });
  } catch (err) {
    console.error('[upload/supabase]', err);
    res.status(500).json({ error: String(err) });
  }
});

// ── Manuais de produto (CRUD via Supabase Storage + coluna JSONB manuais) ──
const uploadManual = multer({ storage: multer.memoryStorage(), limits: { fileSize: 20 * 1024 * 1024 } });

async function detalharProdutosManuais(listaProdutos = []) {
  const codigosProduto = (Array.isArray(listaProdutos) ? listaProdutos : [])
    .map(item => String(item?.codigo_produto || item || '').trim())
    .filter(Boolean);

  if (!codigosProduto.length) return [];

  const { rows } = await pool.query(
    `SELECT codigo_produto::text AS codigo_produto, codigo, descricao
       FROM public.produtos_omie
      WHERE codigo_produto::text = ANY($1::text[])`,
    [codigosProduto]
  );

  const mapa = new Map(
    rows.map(r => [String(r.codigo_produto), {
      codigo_produto: String(r.codigo_produto || ''),
      codigo: String(r.codigo || r.codigo_produto || ''),
      descricao: String(r.descricao || '')
    }])
  );

  return codigosProduto.map(cp => mapa.get(cp) || ({
    codigo_produto: cp,
    codigo: cp,
    descricao: ''
  }));
}

