function isRecebimentoProdutoTopic(topic = '') {
  return /^RecebimentoProduto\./i.test(String(topic || ''));
}

function isNotaEntradaTopic(topic = '') {
  return /^NotaEntrada\./i.test(String(topic || ''));
}

function isRecebimentoNfeLifecycleTopic(topic = '') {
  return isRecebimentoProdutoTopic(topic) || isNotaEntradaTopic(topic);
}

function inferNotaEntradaStatusFromTopic(topic = '') {
  const normalizado = String(topic || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  if (!normalizado) return 'Desconhecida';
  if (normalizado.includes('incluid')) return 'Incluida';
  if (normalizado.includes('alterad')) return 'Alterada';
  if (normalizado.includes('concluid')) return 'Concluida';
  if (normalizado.includes('cancelad')) return 'Cancelada';
  if (normalizado.includes('excluid')) return 'Excluida';
  if (normalizado.includes('devolvid')) return 'Cancelada';
  if (normalizado.includes('revertid')) return 'Alterada';
  return 'Desconhecida';
}

function inferNotaEntradaStatusFromSnapshot(cabec = {}, infoCadastro = {}) {
  const cancelada = String(
    infoCadastro.cCancelada
    || infoCadastro.c_cancelada
    || cabec.cCancelada
    || cabec.c_cancelada
    || ''
  ).trim().toUpperCase() === 'S';

  if (cancelada) return 'Cancelada';

  const recebida = String(
    infoCadastro.cRecebido
    || infoCadastro.c_recebido
    || cabec.cRecebido
    || cabec.c_recebido
    || ''
  ).trim().toUpperCase() === 'S';

  const etapa = String(cabec.cEtapa || cabec.c_etapa || '').trim();
  if (recebida || ['60', '80', '100'].includes(etapa)) return 'Concluida';

  return 'Incluida';
}

function sanitizeNotaEntradaStatus(status = '') {
  const permitido = new Set(['Incluida', 'Alterada', 'Concluida', 'Cancelada', 'Excluida', 'Desconhecida', 'Sincronizada']);
  return permitido.has(status) ? status : 'Desconhecida';
}

function isNotaEntradaAtiva(status = '') {
  return !['Cancelada', 'Excluida'].includes(sanitizeNotaEntradaStatus(status));
}

function extrairCnpjEmitenteDaChaveNfe(chaveNfe = '') {
  const digitos = String(chaveNfe || '').replace(/\D/g, '');
  if (digitos.length !== 44) return null;
  return digitos.slice(6, 20);
}

async function buscarFornecedorLocalPorChaveNfe(chaveNfe, db = pool) {
  const cnpjEmitente = extrairCnpjEmitenteDaChaveNfe(chaveNfe);
  if (!cnpjEmitente) return null;

  const { rows } = await db.query(
    `
      SELECT
        codigo_cliente_omie AS n_id_fornecedor,
        COALESCE(NULLIF(BTRIM(razao_social), ''), NULLIF(BTRIM(nome_fantasia), '')) AS c_nome_fornecedor,
        NULLIF(BTRIM(cnpj_cpf), '') AS c_cnpj_cpf_fornecedor
      FROM omie.fornecedores
      WHERE regexp_replace(COALESCE(cnpj_cpf, ''), '[^0-9]', '', 'g') = $1
      ORDER BY updated_at DESC NULLS LAST, created_at DESC NULLS LAST
      LIMIT 1
    `,
    [cnpjEmitente]
  );

  return rows[0] || null;
}

async function resolverFornecedorRecebimentoFallback(dados = {}, db = pool) {
  const nIdFornecedor = Number.isFinite(Number(dados.nIdFornecedor)) && Number(dados.nIdFornecedor) > 0
    ? Number(dados.nIdFornecedor)
    : null;

  if (nIdFornecedor) {
    return {
      nIdFornecedor,
      cNomeFornecedor: dados.cNomeFornecedor ? String(dados.cNomeFornecedor).trim() || null : null,
      cCnpjCpfFornecedor: dados.cCnpjCpfFornecedor ? String(dados.cCnpjCpfFornecedor).trim() || null : null,
      origem: 'payload',
    };
  }

  const fornecedorLocal = await buscarFornecedorLocalPorChaveNfe(dados.cChaveNfe, db);
  if (fornecedorLocal?.n_id_fornecedor) {
    return {
      nIdFornecedor: Number(fornecedorLocal.n_id_fornecedor),
      cNomeFornecedor: fornecedorLocal.c_nome_fornecedor || null,
      cCnpjCpfFornecedor: fornecedorLocal.c_cnpj_cpf_fornecedor || null,
      origem: 'chave_nfe->omie.fornecedores',
    };
  }

  return {
    nIdFornecedor: null,
    cNomeFornecedor: dados.cNomeFornecedor ? String(dados.cNomeFornecedor).trim() || null : null,
    cCnpjCpfFornecedor: dados.cCnpjCpfFornecedor ? String(dados.cCnpjCpfFornecedor).trim() || null : null,
    origem: 'sem_match',
  };
}

