// Obter o link do anexo (cLinkDownload) via OMIE “ObterAnexo”
app.post('/api/omie/anexo-obter', express.json(), async (req, res) => {
  try {
    const { cTabela, nId, cCodIntAnexo, cNomeArquivo } = req.body;
    // monta o objeto de param aceitando _ou_ cCodIntAnexo _ou_ cNomeArquivo
    const paramObj = { cTabela, nId };
    if (cNomeArquivo) paramObj.cNomeArquivo = cNomeArquivo;
    else              paramObj.cCodIntAnexo = cCodIntAnexo;

    const result = await omieCall(
      'https://app.omie.com.br/api/v1/geral/anexo/',
      {
        call:      'ObterAnexo',
        app_key:   OMIE_APP_KEY,
        app_secret:OMIE_APP_SECRET,
        param:     [ paramObj ]
      }
    );

    // OMIE devolve array com 1 objeto
    const obj = Array.isArray(result) ? result[0] : result;
    return res.json({
      cLinkDownload: obj.cLinkDownload,
      cTipoArquivo:  obj.cTipoArquivo,
      cNomeArquivo:  obj.cNomeArquivo
    });
  } catch (err) {
    console.error('Erro em /api/omie/anexo-obter:', err);
    res.status(err.status || 500).json({ error: err.faultstring || err.message });
  }
});


// Proxy ViaCEP para evitar problemas de CORS
app.get('/api/viacep/:cep', async (req, res) => {
  try {
    const cep = req.params.cep.replace(/\D/g, '');
    const viacepRes = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
    if (!viacepRes.ok) {
      return res.status(viacepRes.status).json({ error: 'ViaCEP retornou erro' });
    }
    const data = await viacepRes.json();
    return res.json(data);
  } catch (err) {
    console.error('Erro no proxy ViaCEP:', err);
    return res.status(500).json({ error: err.message });
  }
});


// ——— Helpers de carimbo de usuário/data ————————————————
function userFromReq(req) {
  // Extrai usuário da sessão ou do header enviado pelo front (#userNameDisplay)
  const fromSession = (req.session?.user?.fullName)
                  || (req.session?.user?.username)
                  || (req.session?.user?.login);
  const fromHeader = String(req.headers?.['x-user'] || '').trim();
  return (fromSession && String(fromSession).trim()) || (fromHeader || 'sistema');
}
function stampNowBR() {
  const d = new Date();
  const p = n => String(n).padStart(2,'0');
  return `${p(d.getDate())}/${p(d.getMonth()+1)}/${d.getFullYear()} - ${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}`;
}
function buildStamp(prefix, req) {
  return `${prefix} - ${userFromReq(req)} - ${stampNowBR()}`;
}

// ────────────────────────────────────────────
// Link fixo por técnico AT: /at/:id → redireciona para portal com token
// ────────────────────────────────────────────
app.get('/at/:id(\\d+)', async (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (!id || id < 1) return res.redirect('/at-link.html');
  try {
    const { rows } = await dbQuery(
      `SELECT ctid, token FROM sac.controle_tecnicos WHERE id = $1 LIMIT 1`,
      [id]
    );
    if (!rows.length) return res.redirect('/at-link.html');
    let { ctid, token } = rows[0];
    if (!token) {
      const crypto = require('crypto');
      token = crypto.randomBytes(32).toString('hex');
      await dbQuery(
        `UPDATE sac.controle_tecnicos SET token = $1 WHERE ctid = $2`,
        [token, ctid]
      );
    }
    res.redirect(`/at-link.html?token=${encodeURIComponent(token)}`);
  } catch (err) {
    console.error('[AT link fixo] erro:', err.message);
    res.redirect('/at-link.html');
  }
});

// ────────────────────────────────────────────
// 4) Sirva todos os arquivos estáticos (CSS, JS, img) normalmente
// ────────────────────────────────────────────
// 🔒 Bloqueia download de arquivos sensíveis ANTES do express.static.
//    (impede que /server.js, /config.server.js, dumps SQL, .bak, .env, etc.
//    sejam servidos como estático a partir da raiz)
const STATIC_BLOCKLIST_FILES = new Set([
  '/server.js', '/config.server.js', '/config.server.example.js',
  '/Middleware.js', '/cookies.txt', '/package.json', '/package-lock.json',
  '/ecosystem.config.js', '/render.yaml', '/nodemon.json',
  '/intranet_db_yd0w_dump.sql', '/atualizar.sql',
  '/add_anexos_column.js', '/disable_trigger.js', '/fix_trigger.js',
  '/sync_omie_imagens_estoque.js', '/sync_omie_produtos.js',
  '/watch_print.js', '/teste_simples.js',
]);
const STATIC_BLOCKLIST_PREFIXES = [
  '/.git', '/.env', '/node_modules', '/scripts/', '/sql/', '/data/',
  '/csv/', '/backend/', '/cron/', '/logs/', '/uploads_internal/',
  '/readme/', '/.github/', '/.vscode/', '/api%20omie/', '/api omie/',
  '/Site_AT/', '/site_at/',
];
const STATIC_BLOCKLIST_EXT = /\.(bak|bak\d*|backup|sql|sqlite|db|dump|env|pem|key|pfx|p12|log|sh|ps1|psql|tsv)$/i;
app.use((req, res, next) => {
  if (req.method !== 'GET' && req.method !== 'HEAD') return next();
  let p;
  try { p = decodeURIComponent(req.path); } catch { p = req.path; }
  // qualquer dotfile (.env, .git, ...) – também bloqueia /algo/.env
  if (/\/\.[^/]+/.test(p)) return res.status(404).end();
  if (STATIC_BLOCKLIST_FILES.has(p)) return res.status(404).end();
  const lower = p.toLowerCase();
  if (STATIC_BLOCKLIST_PREFIXES.some(pref => lower.startsWith(pref.toLowerCase()))) {
    return res.status(404).end();
  }
  if (STATIC_BLOCKLIST_EXT.test(lower)) return res.status(404).end();
  next();
});

// estáticos unificados (CSS/JS/img) — antes das rotas HTML
app.use(express.static(path.join(__dirname), {
  etag: false,                 // evita servir HTML por engano via cache
  maxAge: 0,
  dotfiles: 'deny',            // 🔒 bloqueia .env, .git, etc.
  setHeaders: (res, p) => {
    if (p.endsWith('.webmanifest')) {
      res.setHeader('Content-Type', 'application/manifest+json');
    }
    if (p.endsWith('.html') || p.endsWith('.js') || p.endsWith('.css')) {
      res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
      res.setHeader('Pragma', 'no-cache');
      res.setHeader('Expires', '0');
    }
  }
}));

