/**
 * GET /api/compras/buscar-pedido-compra?numero=2589
 * Busca pedido de compra pelo c_numero e retorna com itens.
 */
app.get('/api/compras/buscar-pedido-compra', async (req, res) => {
  try {
    const numero = String(req.query.numero || '').trim();
    if (!numero) return res.status(400).json({ ok: false, error: 'Número do pedido não informado.' });

    const { rows } = await pool.query(`
      SELECT
        p.n_cod_ped,
        p.c_numero AS cnumero,
        COALESCE(f.nome_fantasia, f.razao_social, '') AS fornecedor,
        TO_CHAR(p.d_inc_data, 'DD/MM/YYYY') AS d_inc_data,
        COALESCE(p.c_obs, '') AS observacao
      FROM compras.pedidos_omie p
      LEFT JOIN omie.fornecedores f ON f.codigo_cliente_omie = p.n_cod_for
      WHERE COALESCE(p.inativo, false) = false
        AND p.c_numero = $1
      LIMIT 1
    `, [numero]);

    if (!rows.length) {
      return res.json({ ok: false, error: `Pedido nº ${numero} não encontrado.` });
    }

    const pedido = rows[0];
    const { rows: prodRows } = await pool.query(`
      SELECT c_produto AS produto_codigo, c_descricao AS produto_descricao,
             n_qtde AS quantidade, c_unidade AS unidade,
             COALESCE(n_val_tot, 0) AS valor_item
      FROM compras.pedidos_omie_produtos
      WHERE n_cod_ped = $1
      ORDER BY id ASC
    `, [pedido.n_cod_ped]);

    res.json({
      ok: true,
      pedido: {
        n_cod_ped: pedido.n_cod_ped,
        cnumero: pedido.cnumero,
        fornecedor: pedido.fornecedor,
        d_inc_data: pedido.d_inc_data,
        observacao: pedido.observacao,
        itens: prodRows
      }
    });
  } catch (err) {
    console.error('[Compras/BuscarPedidoCompra] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao buscar pedido.' });
  }
});

// ========================================
/**
 * POST /api/compras/ranking-pedidos-nfe
 * Usa OpenAI para ranquear pedidos de compra por relevância à NF-e informada.
 * Body: { nfe, itens_nfe, pedidos }
 */
app.post('/api/compras/ranking-pedidos-nfe', async (req, res) => {
  try {
    const apiKey = process.env.OPENAI_API_KEY;
    if (!apiKey) return res.status(503).json({ ok: false, error: 'IA não configurada neste ambiente.' });

    const { nfe = {}, itens_nfe = [], pedidos = [] } = req.body || {};
    if (!pedidos.length) return res.json({ ok: true, ranking: [] });

    // Formata valor BR para o prompt
    const fmtR = (v) => `R$${Number(v||0).toFixed(2)}`;

    const prompt = `Você é um especialista em compras industriais. Analise rigorosamente os dados da NF-e e dos pedidos candidatos.

REGRAS DE CLASSIFICAÇÃO (em ordem de importância):
1. DESCRIÇÃO DO PRODUTO (peso 60%): Pedidos com descrição igual ou muito semelhante aos itens da NF-e devem ter score altíssimo. Correspondência parcial de palavras (ex: "BORBOLETA ZAMAC") ainda conta bastante.
2. QUANTIDADE (peso 20%): Se a quantidade dos itens do pedido for igual ou muito próxima à da NF-e, aumente o score. Divergência grande reduz o score.
3. VALOR UNITÁRIO (peso 15%): Se o valor unitário do item do pedido for próximo ao valor unitário da NF-e (vlr_item ÷ qtd), aumente o score.
4. FORNECEDOR / DATA (peso 5%): Pedidos do mesmo fornecedor ou data próxima são leve tiebreaker.
IGNORE: categoria genérica, ordem de listagem, número do pedido.

NF-e:
- Fornecedor: ${(nfe.c_nome_fornecedor || '-').slice(0, 80)}
- CNPJ/CPF: ${nfe.c_cnpj_cpf_fornecedor || '-'}
- Emissão: ${nfe.d_emissao_nfe || '-'}
- Valor total NF: ${fmtR(nfe.n_valor_nfe)}
- Itens da NF-e:
${itens_nfe.slice(0, 15).map((i, n) => {
  const vlrUnit = (Number(i.qtd||0) > 0) ? (Number(i.vlr_item||0) / Number(i.qtd)).toFixed(2) : '?';
  return `  ${n + 1}. [${(i.codigo || '-').slice(0, 20)}] ${(i.descricao || '-').slice(0, 70)} | Qtd:${i.qtd} ${i.unidade||''} | VlrItem:${fmtR(i.vlr_item)} | VlrUnit:R$${vlrUnit}`;
}).join('\n')}

Pedidos candidatos:
${pedidos.map(p => `Pedido ${p.cnumero} (id:${p.n_cod_ped}):
  Fornecedor: ${(p.fornecedor || '-').slice(0, 60)}
  Data: ${p.d_inc_data || '-'}
  Itens: ${(p.itens || []).slice(0, 10).map(i => `[${(i.produto_codigo||'-').slice(0,15)}] ${(i.produto_descricao||'-').slice(0,45)} Qtd:${i.quantidade||'-'} ${i.unidade||''} Vl:${fmtR(i.valor_item)}`).join(' || ')}`).join('\n\n')}

Retorne SOMENTE um array JSON válido (sem texto adicional), ordenado do MAIS ao MENOS provável:
[{"n_cod_ped": <número inteiro>, "score": <0-100>, "justificativa": "<máx 80 chars em pt-BR indicando por que é ou não candidato"}]`;

    const controller = new AbortController();
    const tId = setTimeout(() => controller.abort(), 22000);
    let response;
    try {
      response = await safeFetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'gpt-4o-mini',
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.1,
          max_tokens: 512
        }),
        signal: controller.signal
      });
    } finally {
      clearTimeout(tId);
    }

    if (!response.ok) {
      const errText = await response.text().catch(() => '');
      console.error('[RankingNfe] OpenAI HTTP', response.status, errText.slice(0, 200));
      return res.status(502).json({ ok: false, error: 'Serviço de IA indisponível no momento.' });
    }

    const data = await response.json();
    const content = String(data.choices?.[0]?.message?.content || '').trim();
    let ranking = [];
    try {
      const ini = content.indexOf('[');
      const fim = content.lastIndexOf(']');
      if (ini >= 0 && fim > ini) ranking = JSON.parse(content.slice(ini, fim + 1));
    } catch (e) {
      console.error('[RankingNfe] Parse falhou:', content.slice(0, 300));
      return res.status(502).json({ ok: false, error: 'Resposta da IA em formato inesperado.' });
    }

    res.json({ ok: true, ranking });
  } catch (err) {
    if (err.name === 'AbortError') {
      return res.status(504).json({ ok: false, error: 'IA demorou muito para responder. Tente novamente.' });
    }
    console.error('[RankingNfe] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao processar classificação com IA.' });
  }
});

// ========================================
//  Endpoint: Listar Recebimentos NF-e por status (Faturada/Recebido/Concluído)
// ========================================
/**
 * GET /api/compras/pedidos-etapa-nf
 * Retorna recebimentos da tabela logistica.recebimentos_nfe_omie:
 * - Faturada pelo fornecedor: c_recebido <> S, c_cancelada <> S, c_bloqueado <> S
 * - Recebido: c_recebido = S, c_etapa IN (50,60), c_cancelada <> S, c_bloqueado <> S
 * - Concluído: c_recebido = S, c_etapa = 80, c_cancelada <> S, c_bloqueado <> S
 * Filtro de calendário: Faturada usa d_emissao_nfe; Recebido/Concluído usam d_rec
 */
app.get('/api/compras/pedidos-etapa-nf', async (req, res) => {
  try {
    console.log('[Compras/PedidosEtapaNF] Listando recebimentos NF-e (Faturada/Recebido/Concluído)...');

    const { dataInicio: diNF, dataFim: dfNF } = req.query;

    // Monta filtros de data para cada grupo
    // Faturada: filtra por d_emissao_nfe | Recebido/Concluído: filtra por d_rec
    const paramsFaturada = [];
    let whereDataFaturada = '';
    if (diNF) {
      paramsFaturada.push(diNF);
      whereDataFaturada += ` AND r.d_emissao_nfe::date >= $${paramsFaturada.length}::date`;
    }
    if (dfNF) {
      paramsFaturada.push(dfNF);
      whereDataFaturada += ` AND r.d_emissao_nfe::date <= $${paramsFaturada.length}::date`;
    }

    const paramsRecebConc = [];
    let whereDataRecebConc = '';
    if (diNF) {
      paramsRecebConc.push(diNF);
      whereDataRecebConc += ` AND r.d_rec::date >= $${paramsRecebConc.length}::date`;
    }
    if (dfNF) {
      paramsRecebConc.push(dfNF);
      whereDataRecebConc += ` AND r.d_rec::date <= $${paramsRecebConc.length}::date`;
    }

    const selectBase = `
        r.n_id_receb,
        r.c_chave_nfe,
        COALESCE(
          NULLIF(LTRIM(REGEXP_REPLACE(COALESCE(r.c_numero_nfe, ''), '\\D', '', 'g'), '0'), ''),
          NULLIF(LTRIM(SUBSTRING(r.c_chave_nfe FROM 26 FOR 9), '0'), ''),
          '0'
        ) AS numero_nfe_exibicao,
        r.c_nome_fornecedor,
        r.c_dados_adicionais,
        r.c_numero_nfe,
        r.n_valor_nfe,
        LOWER(BTRIM(COALESCE(r.compras, ''))) AS compras,
        r.c_etapa,
        r.c_recebido,
        r.d_emissao_nfe,
        r.d_rec,
        r.updated_at
    `;

    const orderBase = `
      ORDER BY
        CASE
          WHEN COALESCE(NULLIF(LTRIM(REGEXP_REPLACE(COALESCE(r.c_numero_nfe, ''), '\\D', '', 'g'), '0'), ''), NULLIF(LTRIM(SUBSTRING(r.c_chave_nfe FROM 26 FOR 9), '0'), '')) ~ '^\\d+$'
            THEN COALESCE(NULLIF(LTRIM(REGEXP_REPLACE(COALESCE(r.c_numero_nfe, ''), '\\D', '', 'g'), '0'), ''), NULLIF(LTRIM(SUBSTRING(r.c_chave_nfe FROM 26 FOR 9), '0'), ''))::BIGINT
          ELSE NULL
        END DESC,
        r.updated_at DESC NULLS LAST
    `;

    // 1) Faturada pelo fornecedor: não cancelada, não bloqueada, NÃO recebida
    const queryFaturada = `
      SELECT ${selectBase}
      FROM logistica.recebimentos_nfe_omie r
      WHERE UPPER(BTRIM(COALESCE(r.c_cancelada, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_bloqueado, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_recebido, 'N'))) NOT IN ('S', 'SIM')
        AND r.d_emissao_nfe >= '2026-01-01'${whereDataFaturada}
      ${orderBase}
    `;

    // 2) Recebido: não cancelada, não bloqueada, recebida, etapa 50 ou 60
    const queryRecebido = `
      SELECT ${selectBase}
      FROM logistica.recebimentos_nfe_omie r
      WHERE UPPER(BTRIM(COALESCE(r.c_cancelada, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_bloqueado, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_recebido, 'N'))) IN ('S', 'SIM')
        AND COALESCE(BTRIM(r.c_etapa), '') IN ('50', '60')
        AND r.d_emissao_nfe >= '2026-01-01'${whereDataRecebConc}
      ${orderBase}
    `;

    // 3) Concluído: não cancelada, não bloqueada, recebida, etapa 80
    const queryConcluido = `
      SELECT ${selectBase}
      FROM logistica.recebimentos_nfe_omie r
      WHERE UPPER(BTRIM(COALESCE(r.c_cancelada, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_bloqueado, 'N'))) NOT IN ('S', 'SIM')
        AND UPPER(BTRIM(COALESCE(r.c_recebido, 'N'))) IN ('S', 'SIM')
        AND COALESCE(BTRIM(r.c_etapa), '') = '80'
        AND r.d_emissao_nfe >= '2026-01-01'${whereDataRecebConc}
      ${orderBase}
    `;

    const [resFaturada, resRecebido, resConcluido] = await Promise.all([
      pool.query(queryFaturada, paramsFaturada),
      pool.query(queryRecebido, paramsRecebConc),
      pool.query(queryConcluido, paramsRecebConc)
    ]);

    const mapearStatus = {
      faturada: 'faturada pelo fornecedor',
      recebido: 'recebido',
      concluido: 'concluído'
    };

    const montarRegistro = (row, statusNf) => {
      const numeroNfe = String(row.numero_nfe_exibicao || '').trim() || '0';
      return {
        numero: numeroNfe,
        c_numero: numeroNfe,
        n_cod_ped: null,
        n_id_receb: row.n_id_receb,
        c_cod_int_ped: null,
        c_etapa: row.c_etapa || '',
        etapa_nf: row.c_etapa || '',
        status_nf: statusNf,
        n_cod_for: null,
        d_inc_data: row.d_emissao_nfe || null,
        d_dt_previsao: null,
        d_rec: row.d_rec || null,
        solicitante: null,
        grupo_requisicao: null,
        fornecedor_nome: row.c_nome_fornecedor || 'Sem fornecedor',
        c_chave_nfe: row.c_chave_nfe || null,
        c_dados_adicionais: row.c_dados_adicionais || null,
        n_valor_nfe: row.n_valor_nfe ?? null,
        compras: row.compras || null,
        origem_recebimento_nfe: true,
        created_at: null,
        updated_at: row.updated_at || null,
        itens: [
          {
            produto_codigo: 'Dados adicionais',
            produto_descricao: row.c_dados_adicionais || 'Sem dados adicionais',
            c_unidade: '-',
            n_qtde: 1,
            n_val_tot: 0,
            c_link_nfe_pdf: null,
            c_dados_adicionais_nfe: row.c_dados_adicionais || null
          }
        ]
      };
    };

    const pedidos = [];
    for (const row of resFaturada.rows) {
      pedidos.push(montarRegistro(row, mapearStatus.faturada));
    }
    for (const row of resRecebido.rows) {
      pedidos.push(montarRegistro(row, mapearStatus.recebido));
    }
    for (const row of resConcluido.rows) {
      pedidos.push(montarRegistro(row, mapearStatus.concluido));
    }

    const parseNumero = valor => {
      const texto = (valor || '').toString().trim();
      return /^\d+$/.test(texto) ? parseInt(texto, 10) : null;
    };

    pedidos.sort((a, b) => {
      const numA = parseNumero(a.numero);
      const numB = parseNumero(b.numero);
      if (numA !== null && numB !== null) return numB - numA;
      if (numA !== null) return -1;
      if (numB !== null) return 1;
      return String(b.numero).localeCompare(String(a.numero));
    });

    console.log(`[Compras/PedidosEtapaNF] Retornando ${pedidos.length} recebimentos agrupados (Faturada: ${resFaturada.rows.length}, Recebido: ${resRecebido.rows.length}, Concluído: ${resConcluido.rows.length})`);
    res.json({ ok: true, pedidos });
  } catch (err) {
    console.error('[Compras/PedidosEtapaNF] Erro ao listar recebimentos NF-e:', err);
    res.status(500).json({ ok: false, error: 'Erro ao listar recebimentos NF-e' });
  }
});

app.get('/api/compras/recebimentos-nfe/detalhes/:nIdReceb', async (req, res) => {
  try {
    const nIdReceb = Number(req.params.nIdReceb);
    if (!Number.isFinite(nIdReceb) || nIdReceb <= 0) {
      return res.status(400).json({ ok: false, error: 'nIdReceb inválido' });
    }

    await pool.query(`
      ALTER TABLE logistica.recebimentos_nfe_omie
      ADD COLUMN IF NOT EXISTS compras VARCHAR(3) NULL
    `);

    const { rows: recebimentoLocalRows } = await pool.query(
      `SELECT LOWER(BTRIM(COALESCE(compras, ''))) AS compras
         FROM logistica.recebimentos_nfe_omie
        WHERE n_id_receb = $1
        LIMIT 1`,
      [nIdReceb]
    );

    const comprasLocal = recebimentoLocalRows[0]?.compras || null;

    const recebimento = await chamarApiRecebimentoNfeOmie('ConsultarRecebimento', { nIdReceb });
    const cabec = recebimento?.cabec || {};
    const infoCadastro = recebimento?.infoCadastro || {};
    const infoAdicionais = recebimento?.infoAdicionais || {};
    const itensRaw = Array.isArray(recebimento?.itensRecebimento) ? recebimento.itensRecebimento : [];

    const cCategCompraRaw = String(
      infoAdicionais?.cCategCompra
      || cabec?.cCategCompra
      || cabec?.c_categoria_compra
      || ''
    ).trim();
    const cObsRaw = String(
      cabec?.cObs
      || cabec?.c_obs
      || cabec?.cObsNFe
      || cabec?.c_obs_nfe
      || infoCadastro?.cObsRec
      || ''
    ).trim();

    let categoriaCompra = null;
    if (cCategCompraRaw) {
      const codigoSemPontuacao = cCategCompraRaw.replace(/\./g, '');
      const { rows: categoriaRows } = await pool.query(
        `SELECT codigo, descricao, natureza
           FROM configuracoes."ListarCategorias"
          WHERE codigo = $1
             OR REPLACE(COALESCE(codigo, ''), '.', '') = $2
          ORDER BY CASE WHEN codigo = $1 THEN 0 ELSE 1 END
          LIMIT 1`,
        [cCategCompraRaw, codigoSemPontuacao]
      );

      if (categoriaRows.length) {
        categoriaCompra = {
          codigo: categoriaRows[0].codigo || cCategCompraRaw,
          descricao: categoriaRows[0].descricao || null,
          natureza: categoriaRows[0].natureza || null
        };
      } else {
        categoriaCompra = {
          codigo: cCategCompraRaw,
          descricao: null,
          natureza: null
        };
      }
    }

    const itens = itensRaw.map((item) => {
      const itensCabec = item?.itensCabec || {};
      const itensAjustes = item?.itensAjustes || {};
      const itensInfoAdic = item?.itensInfoAdic || {};
      const cCFOPItem = String(
        itensCabec?.cCFOP
        || itensCabec?.cCfop
        || item?.cCFOP
        || item?.cCfop
        || itensAjustes?.cCFOP
        || itensAjustes?.cCfop
        || itensInfoAdic?.cCFOP
        || itensInfoAdic?.cCfop
        || ''
      ).trim();

      return {
        cCodigoProduto: itensCabec?.cCodigoProduto || null,
        cDescricaoProduto: itensCabec?.cDescricaoProduto || null,
        cNCM: itensCabec?.cNCM || null,
        cUnidadeNfe: itensCabec?.cUnidadeNfe || null,
        nPrecoUnit: itensCabec?.nPrecoUnit ?? null,
        nQtdeNFe: itensCabec?.nQtdeNFe ?? null,
        cCFOPEntrada: itensAjustes?.cCFOPEntrada || itensInfoAdic?.cCfopEntrada || null,
        cCFOP: cCFOPItem || null
      };
    });

    const cfopDigitosItens = [...new Set(
      itens
        .map((item) => String(item?.cCFOP || '').replace(/\D/g, ''))
        .filter(Boolean)
    )];

    let mapaDescricaoCfop = new Map();
    if (cfopDigitosItens.length > 0) {
      const { rows: cfopRowsItens } = await pool.query(
        `SELECT codigo, descricao
           FROM configuracoes.cfop
          WHERE ativo = TRUE
            AND REGEXP_REPLACE(COALESCE(codigo, ''), '\\D', '', 'g') = ANY($1::text[])`,
        [cfopDigitosItens]
      );

      mapaDescricaoCfop = new Map(
        (cfopRowsItens || []).map((row) => [
          String(row?.codigo || '').replace(/\D/g, ''),
          row?.descricao || null
        ])
      );
    }

    const itensComDescricaoCfop = itens.map((item) => {
      const digitosCfop = String(item?.cCFOP || '').replace(/\D/g, '');
      return {
        ...item,
        cCFOPDescricao: digitosCfop ? (mapaDescricaoCfop.get(digitosCfop) || null) : null
      };
    });

    let possiveisComprasMesmoValor = [];
    const valorNfeNumero = Number(cabec?.nValorNFe ?? null);
    if (Number.isFinite(valorNfeNumero)) {
      const { rows: pedidosMesmoValorRows } = await pool.query(
        `SELECT DISTINCT TRIM(COALESCE(c_numero, '')) AS c_numero
           FROM compras.pedidos_omie
          WHERE COALESCE(inativo, false) = false
            AND COALESCE(BTRIM("Etapa_NF"), '') <> '80'
            AND TRIM(COALESCE(c_numero, '')) <> ''
            AND ABS(COALESCE(n_valor, 0)::NUMERIC - $1::NUMERIC) <= 0.01
          ORDER BY TRIM(COALESCE(c_numero, '')) DESC
          LIMIT 25`,
        [valorNfeNumero]
      );

      possiveisComprasMesmoValor = (pedidosMesmoValorRows || [])
        .map((row) => String(row?.c_numero || '').trim())
        .filter(Boolean);
    }

    return res.json({
      ok: true,
      dados: {
        cNome: cabec?.cNome || null,
        cNumeroNFe: cabec?.cNumeroNFe || null,
        cChaveNFe: cabec?.cChaveNFe || null,
        dEmissaoNFe: cabec?.dEmissaoNFe || null,
        nValorNFe: cabec?.nValorNFe ?? null,
        cCategCompra: cCategCompraRaw || null,
        categoriaCompra,
        cObs: cObsRaw || null,
        cCFOPEntrada: cabec?.cCfopEntrada || cabec?.cCFOPEntrada || null,
        possiveisComprasMesmoValor,
        compras: comprasLocal,
        itens: itensComDescricaoCfop
      }
    });
  } catch (err) {
    console.error('[Compras/RecebimentosNFe/Detalhes] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao consultar recebimento na Omie' });
  }
});

app.put('/api/compras/recebimentos-nfe/compras/:nIdReceb', async (req, res) => {
  try {
    const nIdReceb = Number(req.params.nIdReceb);
    if (!Number.isFinite(nIdReceb) || nIdReceb <= 0) {
      return res.status(400).json({ ok: false, error: 'nIdReceb inválido' });
    }

    await pool.query(`
      ALTER TABLE logistica.recebimentos_nfe_omie
      ADD COLUMN IF NOT EXISTS compras VARCHAR(3) NULL
    `);

    const comprasRaw = req.body?.compras;
    const comprasNormalizada = (comprasRaw === null || comprasRaw === undefined)
      ? null
      : String(comprasRaw).trim().toLowerCase();

    if (comprasNormalizada !== null && comprasNormalizada !== '' && comprasNormalizada !== 'sim' && comprasNormalizada !== 'nao') {
      return res.status(400).json({ ok: false, error: 'Valor inválido para compras. Use sim, nao ou null.' });
    }

    const valorFinal = (!comprasNormalizada || comprasNormalizada === '') ? null : comprasNormalizada;

    const { rows } = await pool.query(
      `UPDATE logistica.recebimentos_nfe_omie
          SET compras = $2,
              updated_at = NOW()
        WHERE n_id_receb = $1
      RETURNING n_id_receb, compras`,
      [nIdReceb, valorFinal]
    );

    if (!rows.length) {
      return res.status(404).json({ ok: false, error: 'Recebimento não encontrado' });
    }

    return res.json({
      ok: true,
      recebimento: {
        n_id_receb: rows[0].n_id_receb,
        compras: rows[0].compras || null
      }
    });
  } catch (err) {
    console.error('[Compras/RecebimentosNFe/Compras] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao atualizar campo compras' });
  }
});

// GET /api/configuracoes/cfop/:codigo
// Objetivo: consultar descrição e aplicação do CFOP em base local (configuracoes.cfop)
app.get('/api/configuracoes/cfop/:codigo', async (req, res) => {
  try {
    const codigoRaw = String(req.params.codigo || '').trim();
    const codigoDigitos = codigoRaw.replace(/\D/g, '');

    if (!codigoDigitos) {
      return res.status(400).json({ ok: false, error: 'Código CFOP inválido' });
    }

    await pool.query('CREATE SCHEMA IF NOT EXISTS configuracoes');
    await pool.query(`
      CREATE TABLE IF NOT EXISTS configuracoes.cfop (
        id BIGSERIAL PRIMARY KEY,
        codigo VARCHAR(10) NOT NULL,
        descricao TEXT NOT NULL,
        aplicacao TEXT NOT NULL,
        fonte_url TEXT NULL,
        ativo BOOLEAN NOT NULL DEFAULT TRUE,
        atualizado_em TIMESTAMPTZ NOT NULL DEFAULT NOW(),
        created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
        updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
        CONSTRAINT cfop_codigo_unico UNIQUE (codigo)
      )
    `);

    const { rows } = await pool.query(
      `SELECT codigo, descricao, aplicacao, fonte_url, atualizado_em
         FROM configuracoes.cfop
        WHERE ativo = TRUE
          AND REGEXP_REPLACE(COALESCE(codigo, ''), '\\D', '', 'g') = $1
        ORDER BY atualizado_em DESC NULLS LAST, updated_at DESC NULLS LAST
        LIMIT 1`,
      [codigoDigitos]
    );

    if (!rows.length) {
      return res.status(404).json({ ok: false, error: 'CFOP não encontrado na base local' });
    }

    const item = rows[0];
    return res.json({
      ok: true,
      cfop: {
        codigo: item.codigo,
        descricao: item.descricao,
        aplicacao: item.aplicacao,
        fonte_url: item.fonte_url,
        atualizado_em: item.atualizado_em
      }
    });
  } catch (err) {
    console.error('[Configuracoes/CFOP] Erro ao consultar CFOP:', err);
    return res.status(500).json({ ok: false, error: 'Erro ao consultar CFOP' });
  }
});

