// ========================================
//  Endpoint: GET /api/compras/pedido-detalhes/:nCodPed
// ========================================
/**
 * Objetivo: Retornar detalhes de um pedido de compra com informações de solicitante, departamento, centro de custo e objetivo
 * baseado na lógica do c_cod_int_ped
 */
app.get('/api/compras/pedido-detalhes/:nCodPed', async (req, res) => {
  try {
    const { nCodPed } = req.params;
    const nCodPedInt = parseInt(nCodPed, 10);
    
    console.log('[PedidoDetalhes] Buscando n_cod_ped:', nCodPedInt);
    
    // Busca o pedido
    const { rows: pedidoRows } = await pool.query(
      'SELECT n_cod_ped, c_cod_int_ped, d_inc_data, d_dt_previsao, created_at, n_cod_for FROM compras.pedidos_omie WHERE n_cod_ped = $1',
      [nCodPedInt]
    );
    
    if (pedidoRows.length === 0) {
      console.log('[PedidoDetalhes] Pedido não encontrado:', nCodPedInt);
      return res.status(404).json({ ok: false, error: 'Pedido não encontrado' });
    }
    
    const pedido = pedidoRows[0];
    const cCodIntPed = (pedido.c_cod_int_ped || '').toString().trim();
    
    console.log('[PedidoDetalhes] Pedido encontrado:', { n_cod_ped: pedido.n_cod_ped, c_cod_int_ped: cCodIntPed });
    
    // Busca o nome do fornecedor usando n_cod_for
    let fornecedorNome = 'Sem fornecedor';
    if (pedido.n_cod_for) {
      console.log('[PedidoDetalhes] Buscando fornecedor com codigo_cliente_omie:', pedido.n_cod_for);
      const { rows: fornecedorRows } = await pool.query(
        `SELECT nome_fantasia FROM omie.fornecedores WHERE codigo_cliente_omie = $1 LIMIT 1`,
        [pedido.n_cod_for]
      );
      if (fornecedorRows.length > 0) {
        fornecedorNome = fornecedorRows[0].nome_fantasia || 'Sem fornecedor';
        console.log('[PedidoDetalhes] Fornecedor encontrado:', fornecedorNome);
      } else {
        // Fallback: usa o código como referência
        console.log('[PedidoDetalhes] Fornecedor não encontrado para codigo:', pedido.n_cod_for);
        fornecedorNome = `Fornecedor ID: ${pedido.n_cod_for}`;
      }
    }
    
    // Busca os produtos/itens do pedido
    console.log('[PedidoDetalhes] Buscando itens para n_cod_ped:', nCodPedInt);
    const { rows: produtosRows } = await pool.query(
      `SELECT c_produto, c_descricao, n_qtde FROM compras.pedidos_omie_produtos 
       WHERE n_cod_ped = $1
       ORDER BY id ASC`,
      [nCodPedInt]
    );
    
    console.log('[PedidoDetalhes] Encontrados', produtosRows.length, 'produtos');
    
    const itens = produtosRows.map(row => ({
      produto_codigo: row.c_produto,
      produto_descricao: row.c_descricao,
      quantidade: row.n_qtde || '-'
    }));
    
    let solicitante = '-';
    let departamento = '-';
    let centroCusto = '-';
    let objetivoCompra = '-';
    
    if (cCodIntPed === '' || cCodIntPed === 'null') {
      // Vazio = Realizado na omie
      console.log('[PedidoDetalhes] c_cod_int_ped vazio - Realizado na omie');
      solicitante = 'Realizado na omie';
    } else if (cCodIntPed.startsWith('REQ')) {
      // Começa com REQ = Realizado em app externo
      console.log('[PedidoDetalhes] c_cod_int_ped começa com REQ - Realizado em app externo');
      solicitante = 'Realizado em app externo';
    } else {
      // Objetivo: Buscar em solicitacao_compras usando numero_pedido = c_cod_int_ped
      // O c_cod_int_ped contém o identificador único que foi armazenado como numero_pedido
      console.log('[PedidoDetalhes] Procurando em solicitacao_compras com numero_pedido:', cCodIntPed);
      const { rows: solicitRows } = await pool.query(
        `SELECT solicitante, departamento, centro_custo, objetivo_compra 
         FROM compras.solicitacao_compras 
         WHERE numero_pedido = $1 
         LIMIT 1`,
        [cCodIntPed]
      );
      
      if (solicitRows.length > 0) {
        console.log('[PedidoDetalhes] Encontrado em solicitacao_compras por numero_pedido');
        solicitante = solicitRows[0].solicitante || '-';
        departamento = solicitRows[0].departamento || '-';
        centroCusto = solicitRows[0].centro_custo || '-';
        objetivoCompra = solicitRows[0].objetivo_compra || '-';
      } else {
        // Fallback: Procurar por grupo_requisicao
        console.log('[PedidoDetalhes] Não encontrado por numero_pedido, tentando grupo_requisicao');
        const { rows: solicitRows2 } = await pool.query(
          `SELECT solicitante, departamento, centro_custo, objetivo_compra 
           FROM compras.solicitacao_compras 
           WHERE grupo_requisicao = $1 
           LIMIT 1`,
          [cCodIntPed]
        );
        
        if (solicitRows2.length > 0) {
          console.log('[PedidoDetalhes] Encontrado em solicitacao_compras por grupo_requisicao');
          solicitante = solicitRows2[0].solicitante || '-';
          departamento = solicitRows2[0].departamento || '-';
          centroCusto = solicitRows2[0].centro_custo || '-';
          objetivoCompra = solicitRows2[0].objetivo_compra || '-';
        } else {
          // Fallback: Procurar em compras_sem_cadastro
          console.log('[PedidoDetalhes] Não encontrado em solicitacao_compras, procurando em compras_sem_cadastro');
          const { rows: semCadastroRows } = await pool.query(
            `SELECT solicitante, departamento, centro_custo, objetivo_compra 
             FROM compras.compras_sem_cadastro 
             WHERE CAST(grupo_requisicao AS TEXT) = $1 OR CAST(id AS TEXT) = $1
             LIMIT 1`,
            [cCodIntPed]
          );
          
          if (semCadastroRows.length > 0) {
            console.log('[PedidoDetalhes] Encontrado em compras_sem_cadastro');
            solicitante = semCadastroRows[0].solicitante || '-';
            departamento = semCadastroRows[0].departamento || '-';
            centroCusto = semCadastroRows[0].centro_custo || '-';
            objetivoCompra = semCadastroRows[0].objetivo_compra || '-';
          } else {
            // Se nenhum match, marcar como "Realizado na Omie" (sem requisição)
            console.log('[PedidoDetalhes] Nenhuma correspondência encontrada - marcando como criado na Omie');
            solicitante = 'Criado direto na Omie (sem requisição)';
          }
        }
      }
    }
    
    res.json({
      ok: true,
      solicitante,
      departamento,
      centroCusto,
      objetivoCompra,
      fornecedorNome,
      d_inc_data: pedido.d_inc_data,
      d_dt_previsao: pedido.d_dt_previsao,
      createdAt: pedido.created_at,
      itens: itens
    });
  } catch (err) {
    console.error('[Compras/PedidoDetalhes] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao buscar detalhes do pedido' });
  }
});

function parseValorDecimalNfe(valor) {
  const texto = String(valor || '').trim().replace(/\u00A0/g, ' ');
  if (!texto) return NaN;
  const semMoeda = texto.replace(/[R$\s]/g, '');
  if (!semMoeda) return NaN;

  if (semMoeda.includes(',') && semMoeda.includes('.')) {
    if (semMoeda.lastIndexOf(',') > semMoeda.lastIndexOf('.')) {
      return Number(semMoeda.replace(/\./g, '').replace(',', '.'));
    }
    return Number(semMoeda.replace(/,/g, ''));
  }

  if (semMoeda.includes(',')) {
    return Number(semMoeda.replace(/\./g, '').replace(',', '.'));
  }

  return Number(semMoeda);
}

function extrairPedidoDosDadosAdicionaisNfe(texto) {
  const conteudo = String(texto || '').replace(/\s+/g, ' ').trim();
  if (!conteudo) return null;
  const match = conteudo.match(/(^|[^a-z0-9])(n\s*)?pedido[a-z]*[^0-9]*([0-9]{2,})/i);
  return match ? String(match[3]).trim() : null;
}

async function localizarRecebimentoNfePorPedidoValor(numeroPedidoRaw, valorTotalRaw) {
  const numeroPedido = String(numeroPedidoRaw || '').trim();
  if (!numeroPedido) {
    return { ok: false, error: 'Parâmetro numero_pedido é obrigatório' };
  }

  const valorTotal = parseValorDecimalNfe(valorTotalRaw);
  if (!Number.isFinite(valorTotal) || valorTotal <= 0) {
    return { ok: false, error: 'Parâmetro valor_total inválido' };
  }

  const pedidoResult = await pool.query(
    `SELECT n_cod_ped, n_cod_for, c_numero
       FROM compras.pedidos_omie
      WHERE TRIM(COALESCE(c_numero, '')) = TRIM($1)
        AND (inativo IS NULL OR inativo = false)
      ORDER BY updated_at DESC NULLS LAST, created_at DESC NULLS LAST, n_cod_ped DESC
      LIMIT 1`,
    [numeroPedido]
  );

  if (pedidoResult.rows.length === 0) {
    return { ok: false, error: 'Pedido não encontrado em compras.pedidos_omie' };
  }

  const pedido = pedidoResult.rows[0];
  const codFornecedor = pedido.n_cod_for;
  if (!codFornecedor) {
    return { ok: false, error: 'Pedido encontrado sem n_cod_for' };
  }

  const recebimentosResult = await pool.query(
    `SELECT n_id_receb, c_numero_nfe, n_valor_nfe, c_dados_adicionais, d_emissao_nfe, created_at
       FROM logistica.recebimentos_nfe_omie
      WHERE n_id_fornecedor = $1
        AND c_numero_nfe IS NOT NULL
        AND TRIM(c_numero_nfe) <> ''
        AND n_valor_nfe IS NOT NULL
        AND ABS(n_valor_nfe::numeric - $2::numeric) < 0.01
      ORDER BY d_emissao_nfe DESC NULLS LAST, created_at DESC NULLS LAST, n_id_receb DESC`,
    [codFornecedor, valorTotal]
  );

  let recebimentos = recebimentosResult.rows.map((row) => ({
    ...row,
    pedido_extraido: extrairPedidoDosDadosAdicionaisNfe(row.c_dados_adicionais)
  }));

  if (recebimentos.length === 0) {
    const fallbackResult = await pool.query(
      `SELECT n_id_receb, c_numero_nfe, n_valor_nfe, c_dados_adicionais, d_emissao_nfe, created_at
         FROM logistica.recebimentos_nfe_omie
        WHERE n_id_fornecedor = $1
          AND c_numero_nfe IS NOT NULL
          AND TRIM(c_numero_nfe) <> ''
        ORDER BY d_emissao_nfe DESC NULLS LAST, created_at DESC NULLS LAST, n_id_receb DESC
        LIMIT 300`,
      [codFornecedor]
    );

    recebimentos = fallbackResult.rows
      .map((row) => ({
        ...row,
        pedido_extraido: extrairPedidoDosDadosAdicionaisNfe(row.c_dados_adicionais)
      }))
      .filter((row) => row.pedido_extraido === numeroPedido);
  }

  if (recebimentos.length === 0) {
    return {
      ok: false,
      error: 'Nenhum recebimento encontrado para este fornecedor (valor/pedido)'
    };
  }

  let recebimentoSelecionado = recebimentos[0];

  if (recebimentos.length > 1) {
    const pedidosExtraidos = [...new Set(recebimentos.map(r => r.pedido_extraido).filter(Boolean))];
    const pedidosValidos = new Set();

    if (pedidosExtraidos.length > 0) {
      const pedidosValidosResult = await pool.query(
        `SELECT DISTINCT TRIM(COALESCE(c_numero, '')) AS c_numero
           FROM compras.pedidos_omie
          WHERE TRIM(COALESCE(c_numero, '')) = ANY($1::text[])
            AND n_cod_for = $2
            AND (inativo IS NULL OR inativo = false)`,
        [pedidosExtraidos, codFornecedor]
      );

      pedidosValidosResult.rows.forEach((row) => {
        const numero = String(row.c_numero || '').trim();
        if (numero) pedidosValidos.add(numero);
      });
    }

    const candidatosMesmoPedido = recebimentos.filter((row) => (
      row.pedido_extraido
      && row.pedido_extraido === numeroPedido
      && pedidosValidos.has(row.pedido_extraido)
    ));

    if (candidatosMesmoPedido.length > 0) {
      recebimentoSelecionado = candidatosMesmoPedido[0];
    }
  }

  const numeroNfeRaw = String(recebimentoSelecionado.c_numero_nfe || '').trim();
  const numeroNfeDigitos = numeroNfeRaw.replace(/\D/g, '');
  if (!numeroNfeDigitos) {
    return { ok: false, error: 'Recebimento encontrado sem c_numero_nfe válido' };
  }

  return {
    ok: true,
    numero_pedido: numeroPedido,
    valor_total: Number(valorTotal.toFixed(2)),
    n_cod_for: codFornecedor,
    n_id_receb: recebimentoSelecionado.n_id_receb,
    c_numero_nfe: numeroNfeRaw,
    numero_nfe_digitos: numeroNfeDigitos
  };
}

async function obterPdfNfeViaOmie(numeroNfeDigitos) {
  if (!(global.__omieNfePdfCache instanceof Map)) {
    global.__omieNfePdfCache = new Map();
  }
  if (!global.__omieNfePdfRateLimit) {
    global.__omieNfePdfRateLimit = {
      blockedUntilMs: 0,
      reason: ''
    };
  }

  const normalizarNumeroNfeCache = (valor) => {
    const digitos = String(valor || '').replace(/\D/g, '');
    if (!digitos) return '';
    return digitos.replace(/^0+/, '') || '0';
  };

  const extrairCooldownSegundos = (mensagem) => {
    const match = String(mensagem || '').match(/tente novamente em\s*(\d+)\s*segundos/i);
    if (!match) return 0;
    const segundos = Number(match[1]);
    return Number.isFinite(segundos) && segundos > 0 ? segundos : 0;
  };

  const chaveCache = normalizarNumeroNfeCache(numeroNfeDigitos);
  const agora = Date.now();
  const cachePdf = global.__omieNfePdfCache;
  const estadoRateLimit = global.__omieNfePdfRateLimit;

  if (chaveCache) {
    const cacheItem = cachePdf.get(chaveCache);
    if (cacheItem && cacheItem.expiresAtMs > agora && /^https?:\/\//i.test(String(cacheItem.cPdf || ''))) {
      return {
        ok: true,
        cPdf: cacheItem.cPdf,
        n_id_nfe: cacheItem.n_id_nfe || null,
        from_cache: true
      };
    }
  }

  if (estadoRateLimit.blockedUntilMs > agora) {
    const restanteSegundos = Math.ceil((estadoRateLimit.blockedUntilMs - agora) / 1000);
    return {
      ok: false,
      error: `API bloqueada por consumo indevido. Tente novamente em ${restanteSegundos} segundos.`
    };
  }

  if (!OMIE_APP_KEY || !OMIE_APP_SECRET) {
    return { ok: false, error: 'Credenciais Omie não configuradas no servidor' };
  }

  const possiveisNNf = [
    numeroNfeDigitos.padStart(9, '0'),
    numeroNfeDigitos,
    String(parseInt(numeroNfeDigitos, 10))
  ].filter((v) => v && v !== 'NaN');
  const nNfUnicos = [...new Set(possiveisNNf)];

  let nIdNf = null;
  let ultimaFalhaConsulta = '';

  for (const nNf of nNfUnicos) {
    const consultaResp = await fetch('https://app.omie.com.br/api/v1/produtos/nfconsultar/', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        call: 'ConsultarNF',
        app_key: OMIE_APP_KEY,
        app_secret: OMIE_APP_SECRET,
        param: [{ nNF: nNf }]
      })
    });

    const consultaData = await consultaResp.json().catch(() => ({}));
    const faultConsulta = consultaData?.faultstring || consultaData?.faultcode || '';

    if (!consultaResp.ok || faultConsulta) {
      if (/api bloqueada por consumo indevido/i.test(String(faultConsulta || ''))) {
        const cooldownSegundos = extrairCooldownSegundos(faultConsulta);
        if (cooldownSegundos > 0) {
          estadoRateLimit.blockedUntilMs = Date.now() + (cooldownSegundos * 1000);
          estadoRateLimit.reason = faultConsulta;
        }
      }
      ultimaFalhaConsulta = faultConsulta || `HTTP ${consultaResp.status}`;
      continue;
    }

    const nIdNFConsulta = consultaData?.compl?.nIdNF
      || consultaData?.compl?.nIdNf
      || consultaData?.nIdNF
      || consultaData?.nIdNfe;

    if (!nIdNFConsulta) {
      ultimaFalhaConsulta = 'Resposta da Omie sem compl.nIdNF';
      continue;
    }

    nIdNf = Number(nIdNFConsulta);
    break;
  }

  if (!Number.isFinite(nIdNf) || nIdNf <= 0) {
    return { ok: false, error: `Não foi possível localizar nIdNF. ${ultimaFalhaConsulta || ''}`.trim() };
  }

  const obterNfeResp = await fetch('https://app.omie.com.br/api/v1/produtos/dfedocs/', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      call: 'ObterNfe',
      app_key: OMIE_APP_KEY,
      app_secret: OMIE_APP_SECRET,
      param: [{ nIdNfe: nIdNf }]
    })
  });

  const obterNfeData = await obterNfeResp.json().catch(() => ({}));
  const faultObter = obterNfeData?.faultstring || obterNfeData?.faultcode || '';
  if (!obterNfeResp.ok || faultObter) {
    if (/api bloqueada por consumo indevido/i.test(String(faultObter || ''))) {
      const cooldownSegundos = extrairCooldownSegundos(faultObter);
      if (cooldownSegundos > 0) {
        estadoRateLimit.blockedUntilMs = Date.now() + (cooldownSegundos * 1000);
        estadoRateLimit.reason = faultObter;
      }
    }
    return {
      ok: false,
      error: faultObter || `Erro HTTP ${obterNfeResp.status} ao obter XML/PDF da NF`
    };
  }

  const cPdf = String(obterNfeData?.cPdf || '').trim();
  if (!/^https?:\/\//i.test(cPdf)) {
    return { ok: false, error: 'Link cPdf não encontrado na resposta da Omie' };
  }

  if (chaveCache) {
    cachePdf.set(chaveCache, {
      cPdf,
      n_id_nfe: nIdNf,
      expiresAtMs: Date.now() + (20 * 60 * 1000)
    });
  }

  estadoRateLimit.blockedUntilMs = 0;
  estadoRateLimit.reason = '';

  return { ok: true, cPdf, n_id_nfe: nIdNf };
}

function decodificarXmlHtmlEscapado(valor) {
  const texto = String(valor || '');
  if (!texto) return '';
  return texto
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&amp;/g, '&');
}

async function obterXmlNfeViaOmie({ nIdNF, nNF, chaveNfe, cModelo = '55' } = {}) {
  if (!OMIE_APP_KEY || !OMIE_APP_SECRET) {
    return { ok: false, error: 'Credenciais Omie não configuradas no servidor' };
  }

  const nIdNumero = Number(nIdNF);
  const nIdValido = Number.isFinite(nIdNumero) && nIdNumero > 0;
  const nNfLimpo = String(nNF || '').replace(/\D/g, '');
  const chaveLimpa = String(chaveNfe || '').replace(/\D/g, '');

  const callOmie = async (url, payload) => {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await response.json().catch(() => ({}));
    return {
      ok: response.ok,
      status: response.status,
      data,
      fault: String(data?.faultstring || data?.faultcode || '')
    };
  };

  let nIdParaConsulta = nIdValido ? nIdNumero : null;

  if (!nIdParaConsulta && (nNfLimpo || chaveLimpa)) {
    const paramConsulta = {};
    if (nNfLimpo) paramConsulta.nNF = nNfLimpo;
    if (chaveLimpa) paramConsulta.cChaveNFe = chaveLimpa;

    const consultaResp = await callOmie('https://app.omie.com.br/api/v1/produtos/nfconsultar/', {
      call: 'ConsultarNF',
      app_key: OMIE_APP_KEY,
      app_secret: OMIE_APP_SECRET,
      param: [paramConsulta]
    });

    if (consultaResp.ok && !consultaResp.fault) {
      const nIdDetectado = Number(
        consultaResp.data?.compl?.nIdNF
        || consultaResp.data?.compl?.nIdNf
        || consultaResp.data?.nIdNF
        || consultaResp.data?.nIdNfe
      );
      if (Number.isFinite(nIdDetectado) && nIdDetectado > 0) {
        nIdParaConsulta = nIdDetectado;
      }
    }

    // Fallback: ListarNFe via /produtos/nfe/ (aceita cChaveNFe)
    if (!nIdParaConsulta && chaveLimpa) {
      try {
        const listarNfeResp = await callOmie('https://app.omie.com.br/api/v1/produtos/nfe/', {
          call: 'ListarNFe',
          app_key: OMIE_APP_KEY,
          app_secret: OMIE_APP_SECRET,
          param: [{ nPagina: 1, nRegPorPagina: 1, cChaveNFe: chaveLimpa }]
        });
        if (listarNfeResp.ok && !listarNfeResp.fault) {
          const listagem = Array.isArray(listarNfeResp.data?.listagemNfe)
            ? listarNfeResp.data.listagemNfe
            : [];
          const encontrado = listagem.find((item) => {
            const chaveItem = String(item?.cChaveNFe || '').replace(/\D/g, '');
            return chaveItem === chaveLimpa;
          }) || listagem[0];
          const nIdListado = Number(encontrado?.nIdNFe || 0);
          if (Number.isFinite(nIdListado) && nIdListado > 0) {
            nIdParaConsulta = nIdListado;
            console.log(`[obterXmlNfeViaOmie] nIdNFe=${nIdListado} encontrado via ListarNFe (fallback)`);
          }
        }
      } catch (_errListar) {
        console.warn('[obterXmlNfeViaOmie] ListarNFe fallback falhou:', _errListar?.message);
      }
    }

    if (!nIdParaConsulta) {
      return {
        ok: false,
        error: 'Não foi possível localizar nIdNF via ConsultarNF nem ListarNFe',
        fonte: 'ConsultarNF+ListarNFe'
      };
    }
  }

  if (!nIdParaConsulta) {
    return {
      ok: false,
      error: 'Informe nIdNF válido (ou nNF/chaveNfe para localizar)',
      fonte: 'entrada'
    };
  }

  const listarResp = await callOmie('https://app.omie.com.br/api/v1/contador/xml/', {
    call: 'ListarDocumentos',
    app_key: OMIE_APP_KEY,
    app_secret: OMIE_APP_SECRET,
    param: [{
      nPagina: 1,
      nRegPorPagina: 20,
      cModelo,
      nIdNF: nIdParaConsulta
    }]
  });

  if (listarResp.ok && !listarResp.fault) {
    const docs = Array.isArray(listarResp.data?.documentosEncontrados)
      ? listarResp.data.documentosEncontrados
      : [];
    const doc = docs.find((item) => Number(item?.nIdNF) === Number(nIdParaConsulta)) || docs[0];
    const cXml = decodificarXmlHtmlEscapado(doc?.cXml || '');
    if (cXml) {
      return {
        ok: true,
        fonte: 'ListarDocumentos',
        nIdNF: Number(doc?.nIdNF || nIdParaConsulta),
        nChave: String(doc?.nChave || ''),
        cXml
      };
    }
  }

  const obterResp = await callOmie('https://app.omie.com.br/api/v1/produtos/dfedocs/', {
    call: 'ObterNfe',
    app_key: OMIE_APP_KEY,
    app_secret: OMIE_APP_SECRET,
    param: [{ nIdNfe: nIdParaConsulta }]
  });

  if (!obterResp.ok || obterResp.fault) {
    const motivoListar = listarResp.fault || (listarResp.ok ? '' : `HTTP ${listarResp.status}`);
    const motivoObter = obterResp.fault || `HTTP ${obterResp.status}`;
    return {
      ok: false,
      error: `Não foi possível obter XML da NFe. ListarDocumentos: ${motivoListar || 'sem XML'} | ObterNfe: ${motivoObter}`,
      fonte: 'ObterNfe'
    };
  }

  const cXml = decodificarXmlHtmlEscapado(
    obterResp.data?.cXml
    || obterResp.data?.cXmlNfe
    || obterResp.data?.xml
    || obterResp.data?.xmlNfe
    || obterResp.data?.cConteudo
    || ''
  );

  if (!cXml) {
    return {
      ok: false,
      error: 'A Omie retornou resposta sem campo de XML',
      fonte: 'ObterNfe'
    };
  }

  return {
    ok: true,
    fonte: 'ObterNfe',
    nIdNF: nIdParaConsulta,
    nChave: String(chaveLimpa || ''),
    cXml,
    cPdf: String(obterResp.data?.cPdf || '').trim() || null,
    cLinkPortal: String(obterResp.data?.cLinkPortal || '').trim() || null
  };
}

function normalizarNumeroNfeComparacao(valor) {
  const digitos = String(valor || '').replace(/\D/g, '');
  if (!digitos) return '';
  return digitos.replace(/^0+/, '') || '0';
}

function normalizarChaveNfeComparacao(valor) {
  const digitos = String(valor || '').replace(/\D/g, '');
  return digitos.length === 44 ? digitos : '';
}

function extrairCooldownSegundosOmie(mensagem) {
  const texto = String(mensagem || '');
  const match = texto.match(/aguarde\s+(\d+)\s+segundos/i);
  return match ? Number(match[1]) : 0;
}

function ehErroRedundanteOmie(erro) {
  const msg = String(erro?.message || erro || '');
  return /consumo redundante|REDUNDANT|SOAP-ENV:Client-6|SOAP-ENV:Client-8/i.test(msg);
}

async function chamarApiRecebimentoNfeOmieComRetryRedundant(call, param = {}, opcoes = {}) {
  const tentativasMaximas = Number.isFinite(Number(opcoes?.tentativasMaximas))
    ? Math.max(1, Number(opcoes.tentativasMaximas))
    : 2;
  const margemSegundos = Number.isFinite(Number(opcoes?.margemSegundos))
    ? Math.max(0, Number(opcoes.margemSegundos))
    : 5;
  const esperaMinimaSegundos = Number.isFinite(Number(opcoes?.esperaMinimaSegundos))
    ? Math.max(0, Number(opcoes.esperaMinimaSegundos))
    : 2;

  let ultimaFalha = null;
  for (let tentativa = 1; tentativa <= tentativasMaximas; tentativa += 1) {
    try {
      return await chamarApiRecebimentoNfeOmie(call, param);
    } catch (erro) {
      ultimaFalha = erro;
      const redundante = ehErroRedundanteOmie(erro);
      if (!redundante || tentativa >= tentativasMaximas) {
        throw erro;
      }

      const msg = String(erro?.message || erro || '');
      const cooldown = extrairCooldownSegundosOmie(msg);
      const esperaSegundos = Math.max(esperaMinimaSegundos, cooldown + margemSegundos);
      await new Promise((resolve) => setTimeout(resolve, esperaSegundos * 1000));
    }
  }

  throw ultimaFalha || new Error(`Falha ao chamar ${call} na Omie`);
}

function obterCacheRecebimentoNfeOmie() {
  if (!global.__omieRecebimentoNfeCache) {
    global.__omieRecebimentoNfeCache = new Map();
  }
  return global.__omieRecebimentoNfeCache;
}

function gravarCacheRecebimentoNfeOmie(recebimento, chaveNfe = '', numeroNfe = '') {
  const cache = obterCacheRecebimentoNfeOmie();
  const ttlMs = 2 * 60 * 1000;
  const expiraEm = Date.now() + ttlMs;
  const valor = { recebimento, expiraEm };

  const chaveNormalizada = normalizarChaveNfeComparacao(chaveNfe || recebimento?.cabec?.cChaveNFe || recebimento?.cabec?.cChaveNfe);
  if (chaveNormalizada) {
    cache.set(`chave:${chaveNormalizada}`, valor);
  }

  const numeroNormalizado = normalizarNumeroNfeComparacao(numeroNfe || recebimento?.cabec?.cNumeroNFe || recebimento?.cabec?.cNumeroNfe);
  if (numeroNormalizado) {
    cache.set(`numero:${numeroNormalizado}`, valor);
  }
}

function lerCacheRecebimentoNfeOmie(chaveNfe = '', numeroNfe = '') {
  const cache = obterCacheRecebimentoNfeOmie();
  const agora = Date.now();

  const buscar = (chave) => {
    if (!chave) return null;
    const item = cache.get(chave);
    if (!item) return null;
    if (!item.expiraEm || item.expiraEm <= agora) {
      cache.delete(chave);
      return null;
    }
    return item.recebimento || null;
  };

  const chaveNormalizada = normalizarChaveNfeComparacao(chaveNfe);
  const porChave = buscar(chaveNormalizada ? `chave:${chaveNormalizada}` : '');
  if (porChave) return porChave;

  const numeroNormalizado = normalizarNumeroNfeComparacao(numeroNfe);
  return buscar(numeroNormalizado ? `numero:${numeroNormalizado}` : '');
}

async function chamarApiRecebimentoNfeOmie(call, param = {}) {
  if (!OMIE_APP_KEY || !OMIE_APP_SECRET) {
    throw new Error('Credenciais Omie não configuradas no servidor');
  }

  const response = await fetch('https://app.omie.com.br/api/v1/produtos/recebimentonfe/', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      call,
      app_key: OMIE_APP_KEY,
      app_secret: OMIE_APP_SECRET,
      param: [param]
    })
  });

  const data = await response.json().catch(() => ({}));
  const fault = data?.faultstring || data?.faultcode || '';

  if (!response.ok || fault) {
    console.error(`[OmieAPI] ${call} resposta:`, JSON.stringify(data));
    throw new Error(fault || `Omie retornou HTTP ${response.status} em ${call}`);
  }

  return data;
}

function extrairPedidosVinculadosDoRecebimento(recebimento) {
  const itens = Array.isArray(recebimento?.itensRecebimento)
    ? recebimento.itensRecebimento
    : [];

  const pedidos = new Set();

  for (const item of itens) {
    const nIdPedido = item?.itensCabec?.nIdPedido;
    const nNumPedCompra = item?.itensInfoAdic?.nNumPedCompra;

    if (nIdPedido !== null && nIdPedido !== undefined && String(nIdPedido).trim() !== '') {
      pedidos.add(String(nIdPedido).trim());
    }
    if (nNumPedCompra !== null && nNumPedCompra !== undefined && String(nNumPedCompra).trim() !== '') {
      pedidos.add(String(nNumPedCompra).trim());
    }
  }

  return [...pedidos];
}

function obterCachePlanoAssociacaoNfePedido() {
  if (!global.__cachePlanoAssociacaoNfePedido) {
    global.__cachePlanoAssociacaoNfePedido = new Map();
  }
  return global.__cachePlanoAssociacaoNfePedido;
}

function criarChavePlanoAssociacaoNfePedido(numeroNfe = '', chaveNfe = '', nCodPed = 0, numeroPedido = '') {
  const chaveNormalizada = normalizarChaveNfeComparacao(chaveNfe);
  const numeroNormalizado = normalizarNumeroNfeComparacao(numeroNfe);
  const pedidoId = Number(nCodPed);
  const pedidoNumero = String(numeroPedido || '').trim();
  return [chaveNormalizada || '-', numeroNormalizado || '-', Number.isFinite(pedidoId) && pedidoId > 0 ? String(pedidoId) : '-', pedidoNumero || '-'].join('|');
}

function gravarCachePlanoAssociacaoNfePedido(chave, plano, ttlMs = 120000) {
  if (!chave || !plano) return;
  const cache = obterCachePlanoAssociacaoNfePedido();
  cache.set(chave, {
    expiraEm: Date.now() + Math.max(1000, Number(ttlMs) || 120000),
    plano
  });
}

function lerCachePlanoAssociacaoNfePedido(chave) {
  if (!chave) return null;
  const cache = obterCachePlanoAssociacaoNfePedido();
  const item = cache.get(chave);
  if (!item) return null;
  if (!item.expiraEm || item.expiraEm <= Date.now()) {
    cache.delete(chave);
    return null;
  }
  return item.plano || null;
}

async function localizarRecebimentoOmiePorNumeroNfe(numeroNfeInformada, chaveNfeInformada = null) {
  const recebimentoCacheInicial = lerCacheRecebimentoNfeOmie(chaveNfeInformada, numeroNfeInformada);
  if (recebimentoCacheInicial?.cabec?.nIdReceb) {
    return recebimentoCacheInicial;
  }

  const chaveNfeNormalizada = normalizarChaveNfeComparacao(chaveNfeInformada);
  if (chaveNfeNormalizada) {
    try {
      const recebimentoPorChave = await chamarApiRecebimentoNfeOmie('ConsultarRecebimento', {
        cChaveNfe: chaveNfeNormalizada
      });
      if (recebimentoPorChave?.cabec?.nIdReceb) {
        gravarCacheRecebimentoNfeOmie(recebimentoPorChave, chaveNfeNormalizada, recebimentoPorChave?.cabec?.cNumeroNFe || numeroNfeInformada);
        return recebimentoPorChave;
      }
    } catch (erroChave) {
      const msgErro = String(erroChave?.message || erroChave || '');
      if (/consumo redundante|REDUNDANT|SOAP-ENV:Client-6|SOAP-ENV:Client-8/i.test(msgErro)) {
        const espera = extrairCooldownSegundosOmie(msgErro);
        throw new Error(
          espera > 0
            ? `API Omie bloqueou temporariamente por consumo redundante. Aguarde ${espera} segundos e tente novamente.`
            : 'API Omie bloqueou temporariamente por consumo redundante. Tente novamente em instantes.'
        );
      }
      console.warn('[Compras/NFeAssociarPedido] Falha ao consultar recebimento por chave, tentando por número:', msgErro);
    }
  }

  const numeroNfeNormalizado = normalizarNumeroNfeComparacao(numeroNfeInformada);
  if (!numeroNfeNormalizado) {
    return null;
  }

  // ── Fallback rápido por n_id_receb local ────────────────────────────────────
  // Antes de paginar toda a API Omie (lento), tenta recuperar o n_id_receb do
  // banco local e chamar ConsultarRecebimento diretamente. Resolve NF-es que
  // existem localmente mas não aparecem na listagem Omie (ex: NF-e 2121).
  try {
    const { rows: localRows } = await pool.query(`
      SELECT n_id_receb, c_chave_nfe
      FROM logistica.recebimentos_nfe_omie
      WHERE LTRIM(REGEXP_REPLACE(COALESCE(c_numero_nfe,''), '[^0-9]', '', 'g'), '0') = $1
        AND n_id_receb IS NOT NULL
        AND n_id_receb > 0
      ORDER BY n_id_receb DESC
      LIMIT 1
    `, [numeroNfeNormalizado]);

    if (localRows.length > 0) {
      const nIdRecebLocal = Number(localRows[0].n_id_receb);
      if (Number.isFinite(nIdRecebLocal) && nIdRecebLocal > 0) {
        try {
          const recebPorId = await chamarApiRecebimentoNfeOmie('ConsultarRecebimento', { nIdReceb: nIdRecebLocal });
          if (recebPorId?.cabec?.nIdReceb) {
            gravarCacheRecebimentoNfeOmie(
              recebPorId,
              recebPorId?.cabec?.cChaveNFe || recebPorId?.cabec?.cChaveNfe || localRows[0].c_chave_nfe || chaveNfeInformada,
              numeroNfeInformada
            );
            console.log(`[Compras/NFeAssociarPedido] NF-e ${numeroNfeInformada} localizada via n_id_receb=${nIdRecebLocal} (fallback local)`);
            return recebPorId;
          }
        } catch (erroId) {
          console.warn(`[Compras/NFeAssociarPedido] Falha ao consultar por n_id_receb=${nIdRecebLocal}:`, erroId?.message);
        }
      }
    }
  } catch (erroLocal) {
    console.warn('[Compras/NFeAssociarPedido] Falha no fallback local por n_id_receb:', erroLocal?.message);
  }

  let pagina = 1;
  let totalPaginas = 1;
  let recebimentoResumo = null;

  while (pagina <= totalPaginas && pagina <= 40) {
    const lista = await chamarApiRecebimentoNfeOmie('ListarRecebimentos', {
      nPagina: pagina,
      nRegistrosPorPagina: 100,
      cExibirDetalhes: 'S'
    });

    totalPaginas = Number(lista?.nTotalPaginas || 1);
    const recebimentos = Array.isArray(lista?.recebimentos) ? lista.recebimentos : [];

    recebimentoResumo = recebimentos.find((rec) => {
      const numeroApi = rec?.cabec?.cNumeroNFe;
      return normalizarNumeroNfeComparacao(numeroApi) === numeroNfeNormalizado;
    }) || null;

    if (recebimentoResumo) break;
    pagina += 1;
  }

  if (!recebimentoResumo?.cabec?.nIdReceb) {
    return null;
  }

  const nIdReceb = Number(recebimentoResumo.cabec.nIdReceb);
  if (!Number.isFinite(nIdReceb) || nIdReceb <= 0) {
    return null;
  }

  const recebimentoCompleto = await chamarApiRecebimentoNfeOmie('ConsultarRecebimento', { nIdReceb });
  if (recebimentoCompleto?.cabec?.nIdReceb) {
    gravarCacheRecebimentoNfeOmie(recebimentoCompleto, recebimentoCompleto?.cabec?.cChaveNFe || recebimentoCompleto?.cabec?.cChaveNfe || chaveNfeInformada, numeroNfeInformada);
  }
  return recebimentoCompleto;
}

function normalizarTextoAssociacaoNfePedido(valor) {
  return String(valor ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function tokenizarTextoAssociacaoNfePedido(valor) {
  const ignorar = new Set([
    'de', 'da', 'do', 'das', 'dos', 'e', 'em', 'com', 'para', 'por', 'a', 'o', 'as', 'os',
    'un', 'und', 'kg', 'mts', 'mt', 'mm', 'cm', 'mg', 'ml', 'g', 'l', 'pc', 'peca', 'pecas',
    'cpr', 'cprs', 'caps', 'cap', 'gen', 'gas', 'fluido', 'refrigerante'
  ]);

  return [...new Set(
    normalizarTextoAssociacaoNfePedido(valor)
      .split(/\s+/)
      .filter((token) => token && !ignorar.has(token) && token.length > 1)
  )];
}

function calcularScoreAssociacaoNfePedido(itemReceb, itemPedido) {
  const itensCabec = itemReceb?.itensCabec || {};
  const codigoRecBruto = String(itensCabec?.cCodigoProduto || '').trim();
  const codigoPedidoBruto = String(itemPedido?.c_produto || '').trim();
  const descricaoRecBruta = String(itensCabec?.cDescricaoProduto || '').trim();
  const descricaoPedidoBruta = String(itemPedido?.c_descricao || '').trim();

  const codigoRec = normalizarTextoAssociacaoNfePedido(codigoRecBruto).replace(/\s+/g, '');
  const codigoPedido = normalizarTextoAssociacaoNfePedido(codigoPedidoBruto).replace(/\s+/g, '');
  const descricaoRec = normalizarTextoAssociacaoNfePedido(descricaoRecBruta);
  const descricaoPedido = normalizarTextoAssociacaoNfePedido(descricaoPedidoBruta);

  let score = 0;

  if (codigoRec && codigoPedido) {
    if (codigoRec === codigoPedido) score += 1000;
    else if (codigoRec.includes(codigoPedido) || codigoPedido.includes(codigoRec)) score += 180;
  }

  if (descricaoRec && descricaoPedido) {
    if (descricaoRec === descricaoPedido) score += 800;
    else if (descricaoRec.includes(descricaoPedido) || descricaoPedido.includes(descricaoRec)) score += 140;
  }

  const tokensRec = tokenizarTextoAssociacaoNfePedido(descricaoRecBruta);
  const tokensPedido = tokenizarTextoAssociacaoNfePedido(descricaoPedidoBruta);
  const tokensPedidoSet = new Set(tokensPedido);

  let coincidencias = 0;
  let pesoCoincidencias = 0;
  tokensRec.forEach((token) => {
    if (tokensPedidoSet.has(token)) {
      coincidencias += 1;
      pesoCoincidencias += token.length;
    }
  });

  score += coincidencias * 35;
  score += pesoCoincidencias * 2;

  const qtdRec = Number(itensCabec?.nQtdeNFe);
  const qtdPedido = Number(itemPedido?.n_qtde);
  if (Number.isFinite(qtdRec) && Number.isFinite(qtdPedido)) {
    const diferenca = Math.abs(qtdRec - qtdPedido);
    if (diferenca < 0.0001) {
      score += 60;
    } else if (Math.min(qtdRec, qtdPedido) > 0) {
      const proporcao = Math.max(qtdRec, qtdPedido) / Math.min(qtdRec, qtdPedido);
      if (proporcao <= 1.25) score += 18;
      else if (proporcao <= 2) score += 8;
    }
  }

  return score;
}

async function montarPlanoAssociacaoNfePedido(numeroNfe, numeroPedido, chaveNfe = null, nCodPedInformado = null) {
  const nCodPedNumerico = Number(nCodPedInformado);
  const usarIdDireto = Number.isFinite(nCodPedNumerico) && nCodPedNumerico > 0;

  const pedidoResult = usarIdDireto
    ? await pool.query(
      `SELECT n_cod_ped, c_numero
         FROM compras.pedidos_omie
        WHERE n_cod_ped = $1
        LIMIT 1`,
      [nCodPedNumerico]
    )
    : await pool.query(
      `SELECT n_cod_ped, c_numero
         FROM compras.pedidos_omie
        WHERE TRIM(COALESCE(c_numero, '')) = TRIM($1)
           OR n_cod_ped::text = TRIM($1)
        ORDER BY updated_at DESC NULLS LAST, n_cod_ped DESC
        LIMIT 1`,
      [numeroPedido]
    );

  if (!pedidoResult.rows.length) {
    throw new Error('Pedido não encontrado em compras.pedidos_omie');
  }

  const pedido = pedidoResult.rows[0];
  const nCodPed = Number(pedido.n_cod_ped);
  if (!Number.isFinite(nCodPed) || nCodPed <= 0) {
    throw new Error('Pedido encontrado com n_cod_ped inválido');
  }

  const recebimento = await localizarRecebimentoOmiePorNumeroNfe(numeroNfe, chaveNfe);
  if (!recebimento?.cabec?.nIdReceb) {
    throw new Error('NF-e não encontrada na API de recebimentos da Omie');
  }

  const itensReceb = Array.isArray(recebimento?.itensRecebimento)
    ? recebimento.itensRecebimento
    : [];

  if (!itensReceb.length) {
    throw new Error('Recebimento localizado sem itens para associação');
  }

  const itensPedidoResult = await pool.query(
    `SELECT n_cod_item, c_produto, c_descricao, n_qtde, n_val_unit, n_val_tot, n_cod_prod, c_unidade
       FROM compras.pedidos_omie_produtos
      WHERE n_cod_ped = $1`,
    [nCodPed]
  );

  const itensPedido = itensPedidoResult.rows;
  const itensPedidoOrdenados = [...itensPedido].sort((a, b) => {
    const aItem = Number(a?.n_cod_item || 0);
    const bItem = Number(b?.n_cod_item || 0);
    return aItem - bItem;
  });
  const mapaPorCodigoProduto = new Map();
  const mapaPorIdProduto = new Map();

  for (const item of itensPedido) {
    const codigo = String(item?.c_produto || '').trim();
    const idProduto = Number(item?.n_cod_prod);

    if (codigo) {
      if (!mapaPorCodigoProduto.has(codigo)) mapaPorCodigoProduto.set(codigo, []);
      mapaPorCodigoProduto.get(codigo).push(item);
    }

    if (Number.isFinite(idProduto) && idProduto > 0) {
      if (!mapaPorIdProduto.has(idProduto)) mapaPorIdProduto.set(idProduto, []);
      mapaPorIdProduto.get(idProduto).push(item);
    }
  }

  const itensPedidoUsados = new Set();
  const obterChaveUsoItemPedido = (itemPedido) => {
    const nCodItem = Number(itemPedido?.n_cod_item || 0);
    if (Number.isFinite(nCodItem) && nCodItem > 0) return `cod_item:${nCodItem}`;
    return `ref:${String(itemPedido?.c_produto || '').trim()}|${String(itemPedido?.c_descricao || '').trim()}`;
  };
  const itemPedidoDisponivel = (itemPedido) => !itensPedidoUsados.has(obterChaveUsoItemPedido(itemPedido));
  const reservarItemPedido = (itemPedido) => {
    if (itemPedido) itensPedidoUsados.add(obterChaveUsoItemPedido(itemPedido));
    return itemPedido;
  };
  const escolherMelhorCandidatoPedido = (itemReceb, candidatos = []) => {
    let melhorItem = null;
    let melhorScore = -1;

    candidatos
      .filter(itemPedidoDisponivel)
      .forEach((candidato) => {
        const scoreAtual = calcularScoreAssociacaoNfePedido(itemReceb, candidato);
        if (scoreAtual > melhorScore) {
          melhorScore = scoreAtual;
          melhorItem = candidato;
        }
      });

    return { item: melhorItem, score: melhorScore };
  };

  const previewItens = [];

  const itensRecebimentoEditar = itensReceb.map((item, idx) => {
    const itensCabec = item?.itensCabec || {};
    const itensInfoAdic = item?.itensInfoAdic || {};
    const nSequencia = Number(itensCabec?.nSequencia || idx + 1);
    const codigoProdutoRec = String(
      itensCabec?.cCodigoProduto
      || itensCabec?.cCodProduto
      || itensInfoAdic?.cCodIntProd
      || itensInfoAdic?.cCodigoProduto
      || ''
    ).trim();
    const descricaoProdutoRec = String(
      itensCabec?.cDescricaoProduto
      || itensCabec?.cDescricao
      || itensInfoAdic?.cDescricaoProduto
      || ''
    ).trim();
    const nIdProdutoRec = Number(itensCabec?.nIdProduto);

    let itemPedidoVinculo = null;
    let criterioMatch = null;
    let scoreMatch = 0;

    if (Number.isFinite(nIdProdutoRec) && nIdProdutoRec > 0 && mapaPorIdProduto.has(nIdProdutoRec)) {
      const candidatos = mapaPorIdProduto.get(nIdProdutoRec);
      const { item: melhorPorId, score } = escolherMelhorCandidatoPedido(item, candidatos);
      if (melhorPorId) {
        itemPedidoVinculo = reservarItemPedido(melhorPorId);
        criterioMatch = 'id_produto';
        scoreMatch = Math.max(score, 1200);
      }
    }

    if (!itemPedidoVinculo && codigoProdutoRec && mapaPorCodigoProduto.has(codigoProdutoRec)) {
      const candidatos = mapaPorCodigoProduto.get(codigoProdutoRec);
      const { item: melhorPorCodigo, score } = escolherMelhorCandidatoPedido(item, candidatos);
      if (melhorPorCodigo) {
        itemPedidoVinculo = reservarItemPedido(melhorPorCodigo);
        criterioMatch = 'codigo_produto';
        scoreMatch = Math.max(score, 1000);
      }
    }

    if (!itemPedidoVinculo) {
      const { item: melhorSimilaridade, score } = escolherMelhorCandidatoPedido(item, itensPedido);
      if (melhorSimilaridade && score >= 35) {
        itemPedidoVinculo = reservarItemPedido(melhorSimilaridade);
        criterioMatch = 'descricao_similar';
        scoreMatch = score;
      }
    }

    if (!itemPedidoVinculo && itensPedido.length === 1 && itemPedidoDisponivel(itensPedido[0])) {
      itemPedidoVinculo = reservarItemPedido(itensPedido[0]);
      criterioMatch = 'fallback_item_unico_pedido';
      scoreMatch = 5;
    }

    if (!itemPedidoVinculo && itensPedido.length === itensReceb.length) {
      const candidatoSequencia = itensPedidoOrdenados.find(itemPedidoDisponivel);
      if (candidatoSequencia) {
        itemPedidoVinculo = reservarItemPedido(candidatoSequencia);
        criterioMatch = 'fallback_sequencia';
        scoreMatch = 1;
      }
    }

    const itensIde = {
      nSequencia: Number.isFinite(nSequencia) && nSequencia > 0 ? nSequencia : (idx + 1),
      cAcao: 'ASSOCIAR-PEDIDO',
      nIdPedidoExistente: nCodPed
    };

    const nCodItem = Number(itemPedidoVinculo?.n_cod_item);
    if (Number.isFinite(nCodItem) && nCodItem > 0) {
      itensIde.nIdItPedidoExistente = nCodItem;
    }

    previewItens.push({
      n_sequencia: itensIde.nSequencia,
      nf_codigo_produto: codigoProdutoRec || null,
      nf_descricao_produto: descricaoProdutoRec || null,
      nf_qtde: itensCabec?.nQtdeNFe ?? null,
      nf_unidade: String(itensCabec?.cUnidadeNfe || '').trim() || null,
      nf_valor_total: itensCabec?.vTotalItem ?? null,
      pedido_item_encontrado: !!itemPedidoVinculo,
      pedido_n_cod_item: Number.isFinite(nCodItem) && nCodItem > 0 ? nCodItem : null,
      pedido_codigo_produto: String(itemPedidoVinculo?.c_produto || '').trim() || null,
      pedido_descricao_produto: String(itemPedidoVinculo?.c_descricao || '').trim() || null,
      pedido_qtde: itemPedidoVinculo?.n_qtde ?? null,
      pedido_unidade: String(itemPedidoVinculo?.c_unidade || '').trim() || null,
      pedido_valor_total: itemPedidoVinculo?.n_val_tot ?? null,
      criterio_match: criterioMatch,
      score_match: scoreMatch
    });

    return { itensIde };
  });

  const itensSemIdItemPedido = previewItens.filter(
    (item) => !Number.isFinite(Number(item?.pedido_n_cod_item || NaN))
  );

  if (itensSemIdItemPedido.length > 0) {
    throw new Error(
      `Não foi possível mapear nIdItPedidoExistente para ${itensSemIdItemPedido.length} item(ns) da NF-e. ` +
      'Verifique se os itens do pedido Omie correspondem aos itens do recebimento.'
    );
  }

  return {
    numero_nfe: String(recebimento?.cabec?.cNumeroNFe || '').trim() || String(numeroNfe || '').trim(),
    n_id_receb: Number(recebimento?.cabec?.nIdReceb || 0) || null,
    n_cod_ped: nCodPed,
    c_numero_pedido: String(pedido?.c_numero || '').trim() || null,
    itens_pedido_total: itensPedido.length,
    itens_nf_total: itensReceb.length,
    itens_match_total: previewItens.filter(item => item.pedido_item_encontrado).length,
    itens_sem_match_total: previewItens.filter(item => !item.pedido_item_encontrado).length,
    itens_preview: previewItens,
    itensRecebimentoEditar
  };
}

// GET /api/compras/categorias-ativas
// Retorna categorias ativas (conta_inativa = 'N') da tabela configuracoes."ListarCategorias"
app.get('/api/compras/categorias-ativas', async (req, res) => {
  try {
    const { rows } = await pool.query(`
      SELECT codigo, descricao, categoria_superior, conta_despesa, natureza
      FROM configuracoes."ListarCategorias"
      WHERE conta_inativa = 'N'
      ORDER BY codigo
    `);
    return res.json({ ok: true, categorias: rows });
  } catch (err) {
    console.error('[Compras/CategoriasAtivas] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao buscar categorias ativas' });
  }
});

// POST /api/compras/pedidos-omie/nfe-associar-pedido/consultar
// Objetivo: localizar NF-e na Omie e exibir contexto antes da associação.
app.post('/api/compras/pedidos-omie/nfe-associar-pedido/consultar', express.json(), async (req, res) => {
  try {
    const numeroNfe = String(req.body?.numero_nfe || '').trim();
    const chaveNfe = String(req.body?.chave_nfe || '').trim();
    if (!numeroNfe && !chaveNfe) {
      return res.status(400).json({ ok: false, error: 'Parâmetro numero_nfe ou chave_nfe é obrigatório' });
    }

    const recebimento = await localizarRecebimentoOmiePorNumeroNfe(numeroNfe, chaveNfe);
    if (!recebimento) {
      return res.status(404).json({ ok: false, error: 'NF-e não encontrada na API de recebimentos da Omie' });
    }

    const pedidosVinculados = extrairPedidosVinculadosDoRecebimento(recebimento);

    // Verifica se a categoria de compra do recebimento está inativa
    const cCategCompraConsultar = String(
      recebimento?.infoAdicionais?.cCategCompra
      || recebimento?.cabec?.cCategCompra
      || recebimento?.cabec?.c_categoria_compra
      || ''
    ).trim();
    let categoriaInfo = null;
    if (cCategCompraConsultar) {
      const codigoSemPontuacao = cCategCompraConsultar.replace(/\./g, '');
      const catResult = await pool.query(
        `SELECT codigo, descricao, conta_inativa
           FROM configuracoes."ListarCategorias"
          WHERE codigo = $1
             OR REPLACE(COALESCE(codigo, ''), '.', '') = $2
          ORDER BY CASE WHEN codigo = $1 THEN 0 ELSE 1 END
          LIMIT 1`,
        [cCategCompraConsultar, codigoSemPontuacao]
      ).catch(() => ({ rows: [] }));
      const catRow = catResult.rows[0] || null;
      categoriaInfo = {
        codigo: catRow?.codigo || cCategCompraConsultar,
        descricao: catRow?.descricao || cCategCompraConsultar,
        inativa: catRow?.conta_inativa === 'S'
      };
    }

    return res.json({
      ok: true,
      recebimento: {
        n_id_receb: recebimento?.cabec?.nIdReceb || null,
        c_numero_nfe: recebimento?.cabec?.cNumeroNFe || null,
        c_chave_nfe: recebimento?.cabec?.cChaveNfe || null,
        c_nome_fornecedor: recebimento?.cabec?.cRazaoSocial || recebimento?.cabec?.cNome || null,
        itens_total: Array.isArray(recebimento?.itensRecebimento) ? recebimento.itensRecebimento.length : 0,
        pedidos_vinculados: pedidosVinculados,
        categoria: categoriaInfo
      }
    });
  } catch (err) {
    console.error('[Compras/NFeAssociarPedido/Consultar] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao consultar NF-e na Omie' });
  }
});

app.post('/api/compras/pedidos-omie/nfe-associar-pedido/preview', express.json(), async (req, res) => {
  try {
    const numeroNfe = String(req.body?.numero_nfe || '').trim();
    const numeroPedido = String(req.body?.numero_pedido || '').trim();
    const chaveNfe = String(req.body?.chave_nfe || '').trim();
    const nCodPed = Number(req.body?.n_cod_ped || 0);

    if (!numeroNfe && !chaveNfe) {
      return res.status(400).json({ ok: false, error: 'Parâmetro numero_nfe ou chave_nfe é obrigatório' });
    }
    if (!numeroPedido && !(Number.isFinite(nCodPed) && nCodPed > 0)) {
      return res.status(400).json({ ok: false, error: 'Parâmetro numero_pedido ou n_cod_ped é obrigatório' });
    }

    const plano = await montarPlanoAssociacaoNfePedido(numeroNfe, numeroPedido, chaveNfe, nCodPed);
    const chaveCachePlano = criarChavePlanoAssociacaoNfePedido(
      plano?.numero_nfe || numeroNfe,
      chaveNfe,
      plano?.n_cod_ped || nCodPed,
      plano?.c_numero_pedido || numeroPedido
    );
    gravarCachePlanoAssociacaoNfePedido(chaveCachePlano, plano, 120000);

    return res.json({
      ok: true,
      preview: {
        numero_nfe: plano.numero_nfe,
        n_id_receb: plano.n_id_receb,
        n_cod_ped: plano.n_cod_ped,
        c_numero_pedido: plano.c_numero_pedido,
        itens_nf_total: plano.itens_nf_total,
        itens_pedido_total: plano.itens_pedido_total,
        itens_match_total: plano.itens_match_total,
        itens_sem_match_total: plano.itens_sem_match_total,
        itens: plano.itens_preview
      }
    });
  } catch (err) {
    console.error('[Compras/NFeAssociarPedido/Preview] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao gerar prévia de associação' });
  }
});

// POST /api/compras/pedidos-omie/nfe-associar-pedido
// Objetivo: associar manualmente uma NF-e a um pedido de compra na Omie.
app.post('/api/compras/pedidos-omie/nfe-associar-pedido', express.json(), async (req, res) => {
  try {
    const numeroNfe = String(req.body?.numero_nfe || '').trim();
    const numeroPedido = String(req.body?.numero_pedido || '').trim();
    const chaveNfe = String(req.body?.chave_nfe || '').trim();
    const nCodPed = Number(req.body?.n_cod_ped || 0);
    // Categoria substituta informada pelo usuário (quando a categoria original está inativa)
    const novaCategoriaCompra = String(req.body?.nova_categoria_compra || '').trim();

    if (!numeroNfe && !chaveNfe) {
      return res.status(400).json({ ok: false, error: 'Parâmetro numero_nfe ou chave_nfe é obrigatório' });
    }
    if (!numeroPedido && !(Number.isFinite(nCodPed) && nCodPed > 0)) {
      return res.status(400).json({ ok: false, error: 'Parâmetro numero_pedido ou n_cod_ped é obrigatório' });
    }

    let plano = null;
    const chaveCachePlano = criarChavePlanoAssociacaoNfePedido(numeroNfe, chaveNfe, nCodPed, numeroPedido);
    plano = lerCachePlanoAssociacaoNfePedido(chaveCachePlano);
    if (!plano) {
      plano = await montarPlanoAssociacaoNfePedido(numeroNfe, numeroPedido, chaveNfe, nCodPed);
      const chaveCachePlanoResolvida = criarChavePlanoAssociacaoNfePedido(
        plano?.numero_nfe || numeroNfe,
        chaveNfe,
        plano?.n_cod_ped || nCodPed,
        plano?.c_numero_pedido || numeroPedido
      );
      gravarCachePlanoAssociacaoNfePedido(chaveCachePlanoResolvida, plano, 120000);
    }

    // ── Consulta o pedido de compra na Omie para obter nCodCC ────────────────
    // Aplica para TODAS as associações:
    //   • nIdConta = nCodCC do pedido
    //   • cUnidade e nQtde do pedido (ou override do usuário) em cada item
    //   • dVencimento dinâmico conforme compras.contas_omie (tipo CR, melhor_data, fechamento_conta)
    //   • Se conta especial (GLP/Frigelar): codigo_local_estoque = ESTOQUE_LOCAL_ESPECIAL
    const CONTAS_ESPECIAIS = [10507452702, 10440916421];
    const ESTOQUE_LOCAL_ESPECIAL = 10408201806;
    let nCodCC = null;

    // Lê itens_override do frontend (Qtd/Unid editados pelo user na prévia)
    const itensOverride = Array.isArray(req.body?.itens_override) ? req.body.itens_override : [];
    const overrideMap = new Map();
    for (const ov of itensOverride) {
      const seq = Number(ov?.n_sequencia || 0);
      if (seq > 0) overrideMap.set(seq, ov);
    }

    try {
      const pedidoNumero = plano.c_numero_pedido || numeroPedido || String(nCodPed || '');
      const paramPed = pedidoNumero
        ? { cNumero: pedidoNumero }
        : { nCodPed: plano.n_cod_ped };
      const respPed = await fetch('https://app.omie.com.br/api/v1/produtos/pedidocompra/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          call: 'ConsultarPedCompra',
          app_key: OMIE_APP_KEY,
          app_secret: OMIE_APP_SECRET,
          param: [paramPed]
        })
      });
      const pedidoOmie = await respPed.json().catch(() => ({}));
      if (!pedidoOmie?.faultstring) {
        const cab = pedidoOmie?.cabecalho_consulta || pedidoOmie?.cabecalho || {};
        nCodCC = Number(cab?.nCodCC || cab?.n_cod_cc || 0) || null;
        console.log(`[Compras/NFeAssociarPedido] ConsultarPedCompra => nCodCC=${nCodCC}`);
      }
    } catch (errPed) {
      console.warn('[Compras/NFeAssociarPedido] Falha ao buscar nCodCC do pedido:', errPed?.message);
    }

    const aplicarEstoqueEspecial = nCodCC && CONTAS_ESPECIAIS.includes(nCodCC);

    // Itens conforme plano (ASSOCIAR-PEDIDO)
    const itensParaEnviar = plano.itensRecebimentoEditar;

    // Monta parcelas, infoAdicionais e estoque para TODAS as associações
    let financeiroParaEnviar = undefined;
    let infoAdicionaisParaEnviar = undefined;
    let itensEditarEstoque = null;
    let recebimentoCache = null;
    let cCategCompraRegraCfop = '';
    let ufNfeRegraCfop = '';
    let cfopCalculado = null;

    if (nCodCC) {
      try {
        // Busca dados atuais do recebimento + unidades do pedido
        const [recebAtual, pedidoConsulta] = await Promise.all([
          chamarApiRecebimentoNfeOmie('ConsultarRecebimento', { nIdReceb: Number(plano.n_id_receb) }),
          fetch('https://app.omie.com.br/api/v1/produtos/pedidocompra/', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              call: 'ConsultarPedCompra',
              app_key: OMIE_APP_KEY,
              app_secret: OMIE_APP_SECRET,
              param: [plano.c_numero_pedido ? { cNumero: plano.c_numero_pedido } : { nCodPed: Number(plano.n_cod_ped) }]
            })
          }).then(r => r.json()).catch(() => null)
        ]);

        const categoriaAtualReceb = String(
          recebAtual?.infoAdicionais?.cCategCompra
          || recebAtual?.cabec?.cCategCompra
          || recebAtual?.cabec?.c_categoria_compra
          || ''
        ).trim();

        if (categoriaAtualReceb) {
          const categoriaAtualSemPontuacao = categoriaAtualReceb.replace(/\./g, '');
          const categoriaSubstitutaSemPontuacao = novaCategoriaCompra.replace(/\./g, '');
          const categoriaAtualDb = await pool.query(
            `SELECT codigo, descricao, conta_inativa
               FROM configuracoes."ListarCategorias"
              WHERE codigo = $1
                 OR REPLACE(COALESCE(codigo, ''), '.', '') = $2
              ORDER BY CASE WHEN codigo = $1 THEN 0 ELSE 1 END
              LIMIT 1`,
            [categoriaAtualReceb, categoriaAtualSemPontuacao]
          ).catch(() => ({ rows: [] }));

          const categoriaAtualRow = categoriaAtualDb.rows[0] || null;
          const categoriaAtualInativa = categoriaAtualRow?.conta_inativa === 'S';

          if (categoriaAtualInativa && !novaCategoriaCompra) {
            return res.status(422).json({
              ok: false,
              error_type: 'categoria_inativa',
              categoria_atual: {
                codigo: categoriaAtualRow?.codigo || categoriaAtualReceb,
                descricao: categoriaAtualRow?.descricao || categoriaAtualReceb
              },
              error: `Categoria de compra inativa: ${categoriaAtualRow?.codigo || categoriaAtualReceb} - ${categoriaAtualRow?.descricao || categoriaAtualReceb}. Selecione uma categoria ativa antes de associar.`
            });
          }

          if (categoriaAtualInativa && novaCategoriaCompra) {
            const categoriaNovaDb = await pool.query(
              `SELECT codigo, descricao, conta_inativa
                 FROM configuracoes."ListarCategorias"
                WHERE codigo = $1
                   OR REPLACE(COALESCE(codigo, ''), '.', '') = $2
                ORDER BY CASE WHEN codigo = $1 THEN 0 ELSE 1 END
                LIMIT 1`,
              [novaCategoriaCompra, categoriaSubstitutaSemPontuacao]
            ).catch(() => ({ rows: [] }));

            const categoriaNovaRow = categoriaNovaDb.rows[0] || null;
            if (!categoriaNovaRow || categoriaNovaRow?.conta_inativa === 'S') {
              return res.status(422).json({
                ok: false,
                error_type: 'categoria_substituta_invalida',
                error: 'A categoria substituta selecionada é inválida ou está inativa. Escolha uma categoria ativa.'
              });
            }
          }
        }

        // Mapa de unidade por nCodItem do pedido
        const unidadePorCodItem = {};
        (pedidoConsulta?.produtos_consulta || []).forEach(p => {
          if (p.nCodItem) {
            unidadePorCodItem[String(p.nCodItem)] = p.cUnidade;
          }
        });

        const parcelasLista = Array.isArray(recebAtual?.parcelas?.parcelasLista)
          ? recebAtual.parcelas.parcelasLista : [];
        const cCodParcela = recebAtual?.parcelas?.cCodParcela || '000';
        const nQtdParcela = cCodParcela === '999' ? (recebAtual?.parcelas?.nQtdParcela || parcelasLista.length) : null;

        // ── dVencimento dinâmico via compras.contas_omie ──
        let dVencimento = null;
        try {
          const contaDb = await pool.query(
            `SELECT tipo, fechamento_conta, melhor_data FROM compras.contas_omie WHERE n_cod_cc = $1`,
            [nCodCC]
          );
          const contaRow = contaDb.rows[0] || null;
          console.log(`[Compras/NFeAssociarPedido] contas_omie p/ nCodCC=${nCodCC}: tipo=${contaRow?.tipo} fechamento=${contaRow?.fechamento_conta} melhor_data=${contaRow?.melhor_data}`);

          if (contaRow && String(contaRow.tipo).toUpperCase() === 'CR' && contaRow.fechamento_conta) {
            const diaFechamento = Number(contaRow.fechamento_conta);
            const diaMelhorData = Number(contaRow.melhor_data || 0);

            // Usa dEmissaoNFe do recebimento para decidir o mês
            const dEmissaoStr = recebAtual?.cabec?.dEmissaoNFe || '';
            let diaEmissao = 0;
            let mesEmissao = 0;
            let anoEmissao = 0;
            if (dEmissaoStr) {
              const partes = dEmissaoStr.split('/');
              if (partes.length === 3) {
                diaEmissao = Number(partes[0]);
                mesEmissao = Number(partes[1]);
                anoEmissao = Number(partes[2]);
              }
            }
            if (!diaEmissao || !mesEmissao || !anoEmissao) {
              // Fallback: usa data de hoje
              const hj = new Date();
              diaEmissao = hj.getDate();
              mesEmissao = hj.getMonth() + 1;
              anoEmissao = hj.getFullYear();
            }

            if (diaMelhorData > 0 && diaEmissao > diaMelhorData) {
              // Emissão DEPOIS do melhor_data → fechamento do MÊS SEGUINTE
              let mesFech = mesEmissao + 1;
              let anoFech = anoEmissao;
              if (mesFech > 12) { mesFech = 1; anoFech++; }
              dVencimento = `${String(diaFechamento).padStart(2, '0')}/${String(mesFech).padStart(2, '0')}/${anoFech}`;
            } else {
              // Emissão ANTES ou IGUAL ao melhor_data → fechamento do MÊS ATUAL
              dVencimento = `${String(diaFechamento).padStart(2, '0')}/${String(mesEmissao).padStart(2, '0')}/${anoEmissao}`;
            }
            console.log(`[Compras/NFeAssociarPedido] dVencimento dinâmico: ${dVencimento} (dEmissao=${dEmissaoStr} diaMelhorData=${diaMelhorData} diaFechamento=${diaFechamento})`);
          }
        } catch (errConta) {
          console.warn('[Compras/NFeAssociarPedido] Falha ao calcular dVencimento via contas_omie:', errConta?.message);
        }

        console.log('[Compras/NFeAssociarPedido] Parcelas originais:', JSON.stringify(parcelasLista, null, 2));

        // --- Parcelas ---
        if (parcelasLista.length > 0 && dVencimento) {
          const parcelasEditarObj = {
            cCodParcela,
            parcelasListaEditar: parcelasLista.map(p => {
              const parcAtualizada = { nSequencia: p.nSequencia, vParcela: p.vParcela, pParcela: p.pParcela };
              if (dVencimento) parcAtualizada.dVencimento = dVencimento;
              return parcAtualizada;
            })
          };
          if (nQtdParcela !== null) parcelasEditarObj.nQtdParcela = nQtdParcela;
          financeiroParaEnviar = { parcelasEditar: parcelasEditarObj };
        }

        // --- infoAdicionais: dRegistro = hoje, nIdConta = nCodCC ---
        const dHoje = (() => {
          const d = new Date();
          const dd = String(d.getDate()).padStart(2, '0');
          const mm = String(d.getMonth() + 1).padStart(2, '0');
          return `${dd}/${mm}/${d.getFullYear()}`;
        })();
        // novaCategoriaCompra: substitui a categoria inativa se o usuário selecionou uma nova
        const categoriaParaInforAdic = novaCategoriaCompra || recebAtual?.infoAdicionais?.cCategCompra || undefined;
        infoAdicionaisParaEnviar = {
          cCategCompra: categoriaParaInforAdic,
          dRegistro: dHoje,
          nIdConta: nCodCC
        };

        // --- CFOP calculado por regra: UF da NF-e (extraída da chave) + cCategCompra ---
        try {
          const chaveNfeReceb = String(
            recebAtual?.cabec?.cChaveNFe
            || recebAtual?.cabec?.cChaveNfe
            || plano?.chave_nfe
            || chaveNfe
            || ''
          ).replace(/\D/g, '');
          const codigoUfNfe = chaveNfeReceb.length >= 2 ? chaveNfeReceb.slice(0, 2) : '';
          const ufNfe = codigoUfNfe === '42' ? 'SC' : (codigoUfNfe ? 'OUTRA' : '');
          // Usa a nova categoria se o usuário substituiu (categoria inativa), senão usa a do recebimento
          const cCategCompraReceb = String(novaCategoriaCompra || recebAtual?.infoAdicionais?.cCategCompra || '').trim();
          cCategCompraRegraCfop = cCategCompraReceb;
          ufNfeRegraCfop = ufNfe;
          if (ufNfe && cCategCompraReceb) {
            const dentroEstado = ufNfe === 'SC';
            if (cCategCompraReceb === '2.01.04') {
              cfopCalculado = '1.102';
            } else if (cCategCompraReceb === '2.01.03') {
              cfopCalculado = dentroEstado ? '1.101' : '2.101';
            } else {
              cfopCalculado = dentroEstado ? '1.556' : '2.556';
            }
            console.log(`[Compras/NFeAssociarPedido] CFOP calculado: ${cfopCalculado} (UF_NFe=${ufNfe} codUf=${codigoUfNfe} categ=${cCategCompraReceb})`);
          }
        } catch (errCfop) {
          console.warn('[Compras/NFeAssociarPedido] Falha ao calcular CFOP:', errCfop?.message);
        }

        // --- EDITAR cada item: cUnidade + nQtde (do pedido ou override do user) ---
        // Se conta especial, também aplica codigo_local_estoque
        itensEditarEstoque = plano.itensRecebimentoEditar.map(itemEditar => {
          const nSeq = itemEditar.itensIde?.nSequencia;
          const nIdItPed = itemEditar.itensIde?.nIdItPedidoExistente;
          const cUnidadePedido = nIdItPed ? unidadePorCodItem[String(nIdItPed)] : null;

          // Override do user tem prioridade sobre o valor do pedido
          const override = overrideMap.get(nSeq);
          const cUnidadeFinal = override?.cUnidade || cUnidadePedido || null;

          const ajustes = {};
          if (aplicarEstoqueEspecial) ajustes.codigo_local_estoque = ESTOQUE_LOCAL_ESPECIAL;
          if (cUnidadeFinal) ajustes.cUnidade = cUnidadeFinal;
          if (cfopCalculado) ajustes.cCFOPEntrada = cfopCalculado;
          // Nota: nQtde não é campo válido em itensAjustes da Omie

          // Só incluir o item se tiver ajustes
          if (Object.keys(ajustes).length === 0) return null;

          return {
            itensIde: { nSequencia: nSeq, cAcao: 'EDITAR' },
            itensAjustes: ajustes
          };
        }).filter(Boolean);

        recebimentoCache = recebAtual;
        console.log(`[Compras/NFeAssociarPedido] nIdConta=${nCodCC} estoqueEspecial=${aplicarEstoqueEspecial} dVencimento=${dVencimento} parcelas=${parcelasLista.length} itensEditar=${itensEditarEstoque.length} overrides=${overrideMap.size}`);
      } catch (errPrep) {
        console.warn('[Compras/NFeAssociarPedido] Falha ao preparar dados de associação:', errPrep?.message);
      }
    }

    // ─── Passo 1: associação do pedido (PRIMEIRO, pois pode resetar dados financeiros) ───
    const payloadAlterar = {
      ide: { nIdReceb: Number(plano.n_id_receb) },
      itensRecebimentoEditar: itensParaEnviar
    };

    console.log('[Compras/NFeAssociarPedido] ===== PASSO 1: ASSOCIAR-PEDIDO =====');
    console.log(JSON.stringify(payloadAlterar, null, 2));
    console.log('[Compras/NFeAssociarPedido] ===================================');

    let alertaItemAssociacao = '';
    const etapaAlvoRecebimentoTotal = '60';
    try {
      await chamarApiRecebimentoNfeOmieComRetryRedundant('AlterarRecebimento', payloadAlterar, {
        tentativasMaximas: 2
      });
    } catch (erroAssociacao) {
      const msgErro = String(erroAssociacao?.message || erroAssociacao || '');
      const erroItemPedidoInvalido = /Código do Pedido .* e do Item .* devem ser válidos/i.test(msgErro);
      if (!erroItemPedidoInvalido) {
        throw erroAssociacao;
      }
      alertaItemAssociacao = msgErro;
    }

    // ─── Passo 2: parcelas + infoAdicionais DEPOIS da associação ───
    // A associação (ASSOCIAR-PEDIDO) pode resetar parcelas, por isso aplicamos DEPOIS
    if (financeiroParaEnviar || infoAdicionaisParaEnviar) {
      try {
        const payloadParcelas = {
          ide: { nIdReceb: Number(plano.n_id_receb) },
          ...(financeiroParaEnviar || {}),
          ...(infoAdicionaisParaEnviar ? { infoAdicionais: infoAdicionaisParaEnviar } : {})
        };
        console.log('[Compras/NFeAssociarPedido] ===== PASSO 2: parcelas+infoAdic =====');
        console.log(JSON.stringify(payloadParcelas, null, 2));
        console.log('[Compras/NFeAssociarPedido] ===================================');
        await chamarApiRecebimentoNfeOmieComRetryRedundant('AlterarRecebimento', payloadParcelas, {
          tentativasMaximas: 2
        });
        console.log('[Compras/NFeAssociarPedido] Parcelas/infoAdicionais atualizados com sucesso.');
      } catch (errParcelas) {
        console.warn('[Compras/NFeAssociarPedido] Falha ao atualizar parcelas/infoAdicionais:', errParcelas?.message);
      }
    }

    // ─── Passo 3: EDITAR itens com cUnidade + nQtde (+ codigo_local_estoque se especial) ───
    if (itensEditarEstoque && itensEditarEstoque.length > 0) {
      try {
        const payloadEstoque = {
          ide: { nIdReceb: Number(plano.n_id_receb) },
          itensRecebimentoEditar: itensEditarEstoque
        };
        console.log('[Compras/NFeAssociarPedido] ===== PASSO 3: estoque =====');
        console.log(JSON.stringify(payloadEstoque, null, 2));
        console.log('[Compras/NFeAssociarPedido] ===================================');
        await chamarApiRecebimentoNfeOmieComRetryRedundant('AlterarRecebimento', payloadEstoque, {
          tentativasMaximas: 2
        });
        console.log('[Compras/NFeAssociarPedido] Local estoque/unidade atualizados com sucesso.');
      } catch (errEstoque) {
        console.warn('[Compras/NFeAssociarPedido] Falha ao atualizar local estoque:', errEstoque?.message);
      }
    }

    // ─── Passo 4: Concluir recebimento (etapa 60) ───
    // ConcluirRecebimento é mais confiável que AlterarEtapaRecebimento
    // (AlterarEtapaRecebimento pode retornar "OK" sem efetivamente mudar a etapa)
    let etapaConcluida = false;
    let respostaEtapaFinal = null;
    try {
      respostaEtapaFinal = await chamarApiRecebimentoNfeOmieComRetryRedundant('ConcluirRecebimento', {
        nIdReceb: Number(plano.n_id_receb),
        cEtapa: etapaAlvoRecebimentoTotal
      }, { tentativasMaximas: 3 });
      const codStatusConcluir = String(respostaEtapaFinal?.cCodStatus || '').trim();
      if (codStatusConcluir && codStatusConcluir !== '0') {
        throw new Error(`ConcluirRecebimento retornou status ${codStatusConcluir}: ${respostaEtapaFinal?.cDescStatus || 'Sem descrição'}`);
      }
      console.log('[Compras/NFeAssociarPedido] ConcluirRecebimento OK:', JSON.stringify(respostaEtapaFinal));
      etapaConcluida = true;
    } catch (erroConcluir) {
      const msgConcluir = String(erroConcluir?.message || '');
      const erroCfopObrigatorio = /CFOP para o Recebimento/i.test(msgConcluir);
      const erroCategoriaInativa = /categoria .*inativad/i.test(msgConcluir);
      const erroNegocialOmie = /^ERROR:/i.test(msgConcluir)
        || /ConcluirRecebimento retornou status/i.test(msgConcluir)
        || /utilize o método ConcluirRecebimento/i.test(msgConcluir);
      if (erroCfopObrigatorio) {
        throw new Error(
          `Omie não permitiu concluir: item sem CFOP de entrada. Categoria atual=${cCategCompraRegraCfop || 'N/A'}, UF_NFe=${ufNfeRegraCfop || 'N/A'}, CFOP calculado=${cfopCalculado || 'N/A'}. Ajuste a regra de CFOP para essa categoria antes de associar.`
        );
      }
      if (erroCategoriaInativa) {
        throw new Error(
          `Omie não permitiu concluir: categoria de compra inativa (${cCategCompraRegraCfop || 'N/A'}). Mensagem Omie: ${msgConcluir}`
        );
      }
      if (erroNegocialOmie) {
        throw new Error(`Omie não permitiu concluir o recebimento: ${msgConcluir}`);
      }

      console.warn('[Compras/NFeAssociarPedido] ConcluirRecebimento falhou:', erroConcluir?.message, '- tentando AlterarEtapaRecebimento...');
      try {
        respostaEtapaFinal = await chamarApiRecebimentoNfeOmieComRetryRedundant('AlterarEtapaRecebimento', {
          nIdReceb: Number(plano.n_id_receb),
          cEtapa: etapaAlvoRecebimentoTotal
        }, { tentativasMaximas: 2 });
        const codStatusEtapa = String(respostaEtapaFinal?.cCodStatus || '').trim();
        if (codStatusEtapa && codStatusEtapa !== '0') {
          throw new Error(`AlterarEtapaRecebimento retornou status ${codStatusEtapa}: ${respostaEtapaFinal?.cDescStatus || 'Sem descrição'}`);
        }
        console.log('[Compras/NFeAssociarPedido] AlterarEtapaRecebimento OK (fallback):', JSON.stringify(respostaEtapaFinal));
        etapaConcluida = true;
      } catch (erroEtapa) {
        console.warn('[Compras/NFeAssociarPedido] AlterarEtapaRecebimento também falhou:', erroEtapa?.message);
      }
    }

    // ─── Confirmação final pelo retorno da própria Omie ───
    let recebimentoAposAlteracao;
    let etapaFinalRecebimento = '';

    if (etapaConcluida) {
      etapaFinalRecebimento = etapaAlvoRecebimentoTotal;
      recebimentoAposAlteracao = recebimentoCache
        ? { ...recebimentoCache, cabec: { ...(recebimentoCache.cabec || {}), cEtapa: etapaAlvoRecebimentoTotal } }
        : { cabec: { nIdReceb: plano.n_id_receb, cNumeroNFe: plano.numero_nfe || numeroNfe, cEtapa: etapaAlvoRecebimentoTotal } };
    } else {
      throw new Error('NF-e associada, porém não foi possível concluir o recebimento (etapa 60).');
    }

    const pedidosVinculados = extrairPedidosVinculadosDoRecebimento(recebimentoAposAlteracao);
    const vinculoConfirmado = pedidosVinculados.includes(String(plano.n_cod_ped))
      || pedidosVinculados.includes(String(plano.c_numero_pedido || '').trim())
      || pedidosVinculados.includes(String(numeroPedido).trim());

    const numeroNfeVinculada = String(
      recebimentoAposAlteracao?.cabec?.cNumeroNFe ||
      plano.numero_nfe ||
      numeroNfe ||
      ''
    ).trim();

    if (numeroNfeVinculada) {
      await pool.query(`
        ALTER TABLE compras.pedidos_omie
        ADD COLUMN IF NOT EXISTS "NFe vinculada" TEXT
      `);

      await pool.query(
        `UPDATE compras.pedidos_omie
            SET "NFe vinculada" = $1,
                "Etapa_NF" = $2
          WHERE n_cod_ped = $3`,
        [numeroNfeVinculada, etapaFinalRecebimento || etapaAlvoRecebimentoTotal, plano.n_cod_ped]
      );
    }

    if (alertaItemAssociacao && !vinculoConfirmado) {
      throw new Error(alertaItemAssociacao);
    }

    return res.json({
      ok: true,
      message: alertaItemAssociacao
        ? `Pedido ${plano.c_numero_pedido || plano.n_cod_ped} vinculado à NF-e ${recebimentoAposAlteracao?.cabec?.cNumeroNFe || numeroNfe} na Omie, com alerta de item: ${alertaItemAssociacao}`
        : (vinculoConfirmado
          ? `NF-e ${recebimentoAposAlteracao?.cabec?.cNumeroNFe || numeroNfe} associada ao pedido ${plano.c_numero_pedido || plano.n_cod_ped} na Omie.${respostaEtapaFinal?.cDescStatus ? ` ${respostaEtapaFinal.cDescStatus}` : ''}`
          : 'vinculado com sucesso.'),
      dados: {
        n_id_receb: recebimentoAposAlteracao?.cabec?.nIdReceb || plano.n_id_receb || null,
        c_numero_nfe: recebimentoAposAlteracao?.cabec?.cNumeroNFe || plano.numero_nfe || null,
        n_cod_ped: plano.n_cod_ped,
        c_numero_pedido: plano.c_numero_pedido || null,
        nfe_vinculada: numeroNfeVinculada || null,
        etapa_nf_omie: etapaFinalRecebimento || null,
        retorno_etapa_omie: respostaEtapaFinal || null,
        pedidos_vinculados: pedidosVinculados,
        alerta_item: alertaItemAssociacao || null
      }
    });
  } catch (err) {
    console.error('[Compras/NFeAssociarPedido] Erro:', err);
    return res.status(500).json({ ok: false, error: err?.message || 'Erro ao associar NF-e ao pedido na Omie' });
  }
});

// POST /api/compras/pedidos-omie/nfe-disponibilidade
// Objetivo: validar em lote apenas no banco se existe c_numero_nfe para cada pedido/valor (sem chamar Omie).
app.post('/api/compras/pedidos-omie/nfe-disponibilidade', express.json(), async (req, res) => {
  try {
    const itens = Array.isArray(req.body?.itens) ? req.body.itens.slice(0, 400) : [];
    if (itens.length === 0) {
      return res.json({ ok: true, resultados: [] });
    }

    const chavesVistas = new Set();
    const itensUnicos = [];
    for (const item of itens) {
      const numeroPedido = String(item?.numero_pedido || '').trim();
      const valorTotal = parseValorDecimalNfe(item?.valor_total);
      if (!numeroPedido || !Number.isFinite(valorTotal) || valorTotal <= 0) continue;

      const chave = `${numeroPedido}|${Number(valorTotal.toFixed(2))}`;
      if (chavesVistas.has(chave)) continue;
      chavesVistas.add(chave);
      itensUnicos.push({
        chave,
        numeroPedido,
        valorTotal: Number(valorTotal.toFixed(2))
      });
    }

    const resultados = [];
    const concorrencia = 8;
    for (let i = 0; i < itensUnicos.length; i += concorrencia) {
      const lote = itensUnicos.slice(i, i + concorrencia);
      const loteResultados = await Promise.all(lote.map(async (item) => {
        const localizacao = await localizarRecebimentoNfePorPedidoValor(item.numeroPedido, item.valorTotal);
        return {
          chave: item.chave,
          numero_pedido: item.numeroPedido,
          valor_total: item.valorTotal,
          disponivel: !!localizacao?.ok,
          c_numero_nfe: localizacao?.ok ? localizacao.c_numero_nfe : null,
          erro: localizacao?.ok ? null : (localizacao?.error || 'Não encontrado')
        };
      }));
      resultados.push(...loteResultados);
    }

    res.json({ ok: true, resultados });
  } catch (err) {
    console.error('[Compras/NFeDisponibilidade] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao verificar disponibilidade de NF-e' });
  }
});

// GET /api/compras/pedidos-omie/nfe-pdf-link
// Objetivo: gerar cPdf da NF-e apenas no clique (chamada à Omie).
app.get('/api/compras/pedidos-omie/nfe-pdf-link', async (req, res) => {
  try {
    const numeroPedido = String(req.query.numero_pedido || '').trim();
    const valorTotalRaw = String(req.query.valor_total || '').trim();

    const localizacao = await localizarRecebimentoNfePorPedidoValor(numeroPedido, valorTotalRaw);
    if (!localizacao?.ok) {
      return res.json({ ok: false, error: localizacao?.error || 'Não foi possível localizar NF-e' });
    }

    const omieResult = await obterPdfNfeViaOmie(localizacao.numero_nfe_digitos);
    if (!omieResult?.ok) {
      return res.json({ ok: false, error: omieResult?.error || 'Falha ao consultar Omie' });
    }

    res.json({
      ok: true,
      cPdf: omieResult.cPdf,
      numero_pedido: localizacao.numero_pedido,
      c_numero_nfe: localizacao.c_numero_nfe,
      n_id_nfe: omieResult.n_id_nfe,
      n_id_receb: localizacao.n_id_receb
    });
  } catch (err) {
    console.error('[Compras/NFePdfLink] Erro:', err);
    res.status(500).json({ ok: false, error: 'Erro ao gerar link do PDF da NF-e' });
  }
});

app.post('/api/omie/nfe/xml', express.json(), async (req, res) => {
  try {
    const nIdNF = Number(
      req.body?.nIdNF
      || req.body?.nIdNf
      || req.body?.nIdNfe
      || req.body?.compl?.nIdNF
    );
    const nNF = String(
      req.body?.nNF
      || req.body?.numeroNf
      || req.body?.compl?.nNumero
      || req.body?.ide?.nNF
      || ''
    );
    const chaveNfe = String(
      req.body?.chaveNfe
      || req.body?.cChaveNFe
      || req.body?.compl?.cChaveNFe
      || ''
    );
    const cModelo = String(req.body?.cModelo || req.body?.ide?.mod || '55');

    const resultado = await obterXmlNfeViaOmie({
      nIdNF,
      nNF,
      chaveNfe,
      cModelo
    });

    if (!resultado?.ok) {
      return res.status(404).json({ ok: false, error: resultado?.error || 'XML não encontrado' });
    }

    return res.json({
      ok: true,
      fonte: resultado.fonte,
      nIdNF: resultado.nIdNF || nIdNF || null,
      nChave: resultado.nChave || null,
      cXml: resultado.cXml,
      cPdf: resultado.cPdf || null,
      cLinkPortal: resultado.cLinkPortal || null
    });
  } catch (err) {
    console.error('[omie/nfe/xml] erro →', err);
    return res.status(err.status || 500).json({ ok: false, error: err.faultstring || err.message });
  }
});

app.get('/api/omie/nfe/xml-download', async (req, res) => {
  try {
    const nIdNF = Number(
      req.query?.nIdNF
      || req.query?.nIdNf
      || req.query?.nIdNfe
      || 0
    );
    const nNF = String(
      req.query?.nNF
      || req.query?.numero_nfe
      || req.query?.numeroNf
      || ''
    );
    const chaveNfe = String(
      req.query?.chave_nfe
      || req.query?.chaveNfe
      || req.query?.cChaveNFe
      || ''
    );
    const cModelo = String(req.query?.cModelo || '55');

    const resultado = await obterXmlNfeViaOmie({
      nIdNF,
      nNF,
      chaveNfe,
      cModelo
    });

    if (!resultado?.ok || !resultado?.cXml) {
      return res.status(404).send(resultado?.error || 'XML não encontrado');
    }

    const chaveArquivo = String(resultado?.nChave || chaveNfe || '').replace(/\D/g, '');
    const numeroArquivo = String(nNF || '').replace(/\D/g, '');
    const nomeArquivo = chaveArquivo
      ? `nfe-${chaveArquivo}.xml`
      : (numeroArquivo ? `nfe-${numeroArquivo}.xml` : 'nfe.xml');

    res.setHeader('Content-Type', 'application/xml; charset=utf-8');
    res.setHeader('Content-Disposition', `attachment; filename="${nomeArquivo}"`);
    return res.status(200).send(resultado.cXml);
  } catch (err) {
    console.error('[omie/nfe/xml-download] erro →', err);
    return res.status(err.status || 500).send(err.faultstring || err.message || 'Erro ao baixar XML');
  }
});

