const GOOGLE_SHEETS_AUTOSYNC_ENABLED = process.env.GOOGLE_SHEETS_AUTOSYNC_ENABLED !== '0';
const GOOGLE_SHEETS_SYNC_MODE = String(process.env.GOOGLE_SHEETS_SYNC_MODE || 'db-trigger').toLowerCase();
